            new() { Id=5036, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"關於NIST，下列敘述何者正確？", OptionsJson=@"[""A. 專門制定歐盟隱私法規"", ""B. 美國國家標準與技術研究所"", ""C. 僅負責硬體製造認證"", ""D. 只處理金融監理議題""]", CorrectAnswer="B", Explanation=@"NIST是美國國家標準與技術研究所，提供資訊安全與風險管理等標準與指引。" },
            new() { Id=5037, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"GDPR的主要重點為何？", OptionsJson=@"[""A. 提升AI計算效能"", ""B. 規範機器人勞動權"", ""C. 強調個人資料保護與處理透明度"", ""D. 僅管理政府公開資料""]", CorrectAnswer="C", Explanation=@"GDPR強調個人隱私保護、資料處理透明與取得明確同意等。" },
            new() { Id=5038, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"CCPA主要保護哪一類權益？", OptionsJson=@"[""A. 加州消費者的個人資料隱私權"", ""B. 歐盟公民投票權"", ""C. 企業智慧財產權"", ""D. 開發者著作權""]", CorrectAnswer="A", Explanation=@"CCPA聚焦加州消費者，賦予其對個人資料的查詢、刪除與拒絕出售等權利。" },
            new() { Id=5039, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"在AI高風險應用（如醫療診斷）中，以下何者最符合治理原則？", OptionsJson=@"[""A. 完全交由AI自動判斷"", ""B. 只讓工程師審核結果"", ""C. 由人類專業人員進行最終決策審核"", ""D. 只看模型準確率是否最高""]", CorrectAnswer="C", Explanation=@"高風險情境中需保留人類最終決策權與專業判斷，以避免不可逆錯誤。" },
            new() { Id=5040, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"「可解釋性」在AI治理中的角色為何？", OptionsJson=@"[""A. 讓程式碼更難讀"", ""B. 讓AI決策過程可被人類理解與追溯"", ""C. 保證模型不會出錯"", ""D. 提升演算法執行速度""]", CorrectAnswer="B", Explanation=@"可解釋性是指能說明模型如何從輸入推導出輸出，避免成為黑箱。" },
            new() { Id=5041, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"Microsoft Tay事件主要凸顯哪一項AI治理問題？", OptionsJson=@"[""A. 硬體設備老舊"", ""B. 缺乏對互動內容與學習資料的有效管控"", ""C. 演算法過於透明"", ""D. 資料量太少""]", CorrectAnswer="B", Explanation=@"Tay從社群媒體學習到仇恨與歧視言論，顯示缺乏內容審查與安全防護機制。" },
            new() { Id=5042, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"COMPAS風險評估工具的爭議主要與哪一項原則相關？", OptionsJson=@"[""A. 效率"", ""B. 公平性與偏見"", ""C. 節能減碳"", ""D. 使用者體驗""]", CorrectAnswer="B", Explanation=@"研究發現COMPAS對不同族群的誤判率差異大，被批評存在種族偏見。" },
            new() { Id=5043, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"在AI治理中，「問責制」最主要是在說明什麼？", OptionsJson=@"[""A. 讓AI自己負責"", ""B. 發生問題時能追溯與界定責任"", ""C. 只要公開原始碼即可"", ""D. 將責任完全外包給供應商""]", CorrectAnswer="B", Explanation=@"問責制要求能釐清誰設計、部署與管理系統，出問題時可以追責。" },
            new() { Id=5044, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"如果AI系統使用來源不明的訓練資料，最可能產生哪種風險？", OptionsJson=@"[""A. 效能一定變差"", ""B. 電力使用量下降"", ""C. 引發隱私侵害或偏見"", ""D. 完全不影響系統表現""]", CorrectAnswer="C", Explanation=@"未知來源資料可能違反隱私法規，且可能含有系統性偏見。" },
            new() { Id=5045, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"資料治理在AI治理中的主要目的為何？", OptionsJson=@"[""A. 提高演算法複雜度"", ""B. 保護資料隱私與完整性"", ""C. 鼓勵任意資料收集"", ""D. 關閉所有外部資料來源""]", CorrectAnswer="B", Explanation=@"良好資料治理確保資料準確、合法、無不當偏見，是負責任AI的基礎。" },
            new() { Id=5046, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"歐盟AI法案的主要政策方向為何？", OptionsJson=@"[""A. 優先鼓勵任何形式的AI創新"", ""B. 完全禁止機器學習"", ""C. 以風險為基礎分類並要求高風險AI符合特定義務"", ""D. 只規範娛樂用途AI""]", CorrectAnswer="C", Explanation=@"歐盟AI法案採風險分級，特別嚴管高風險應用並要求合規與監管。" },
            new() { Id=5047, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能說明「社會與公眾監督」在AI治理中的角色？", OptionsJson=@"[""A. 只由技術團隊自行評估"", ""B. 讓投資人決定是否上線"", ""C. 確保技術發展符合公共利益與人權"", ""D. 僅關注產品銷售量""]", CorrectAnswer="C", Explanation=@"引入政府、民間組織與公眾參與，以平衡商業利益與社會價值。" },
            new() { Id=5048, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"NIST AI風險管理框架（AI RMF）的主要目的為何？", OptionsJson=@"[""A. 規範程式語言標準"", ""B. 協助組織在AI生命週期中辨識與管理風險"", ""C. 替代所有隱私法規"", ""D. 只用來測試硬體效能""]", CorrectAnswer="B", Explanation=@"AI RMF提供結構化流程，協助在設計、開發與部署階段識別與降低AI風險。" },
            new() { Id=5049, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"下列何者最符合「包容性」的AI設計？", OptionsJson=@"[""A. 只針對單一族群最佳化"", ""B. 忽略弱勢使用者需求"", ""C. 在開發時就考量不同族群的需求與影響"", ""D. 只測試英文使用者""]", CorrectAnswer="C", Explanation=@"包容性要求AI不排除或不利於特定族群，並在設計階段納入多元觀點。" },
            new() { Id=5050, ChapterId=1301, Type="multiple", Difficulty=2, QuestionText=@"對使用者而言，為何AI系統的「隱私與安全」是信任關鍵？", OptionsJson=@"[""A. 可以加快網路速度"", ""B. 能避免個資濫用與資料外洩"", ""C. 能降低產品售價"", ""D. 使系統完全離線""]", CorrectAnswer="B", Explanation=@"若無適當隱私與安全措施，使用者將不願提供資料或依賴AI決策。" },
            new() { Id=5051, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"下列何者最能體現「風險導向」的AI治理思維？", OptionsJson=@"[""A. 所有AI一律禁止使用"", ""B. 僅以公司規模決定管制強度"", ""C. 依照AI應用風險高低決定監管嚴格程度"", ""D. 只針對開源模型監管""]", CorrectAnswer="C", Explanation=@"風險導向會將醫療、司法等高風險應用納入較嚴格管理。" },
            new() { Id=5052, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"若一個AI系統在整體準確率上表現良好，但對某一族群的誤判率特別高，最適合用哪個概念描述此問題？", OptionsJson=@"[""A. 效率不足"", ""B. 隱私洩漏"", ""C. 演算法歧視"", ""D. 資安弱點""]", CorrectAnswer="C", Explanation=@"即使整體準確率高，若對特定群體系統性不利，就是演算法歧視與不公平。" },
            new() { Id=5053, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"在AI治理中要求「人類可介入與覆寫AI決策」主要是為了確保哪一項？", OptionsJson=@"[""A. 電腦運算資源充足"", ""B. 人類監管與最終責任"", ""C. 資料集大小足夠"", ""D. 模型開源""]", CorrectAnswer="B", Explanation=@"人類介入機制能在AI出現異常時及時調整，確保決策可控並可問責。" },
            new() { Id=5054, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"若企業宣稱其AI模型「不可公開說明原理，因為是商業機密」，這最直接影響哪一項治理要求？", OptionsJson=@"[""A. 可解釋性與透明性"", ""B. 節能減碳"", ""C. 運算效能"", ""D. 資料量大小""]", CorrectAnswer="A", Explanation=@"過度以機密為由拒絕說明，將削弱外部稽核與使用者對模型的理解與信任。" },
            new() { Id=5055, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"在引入外部雲端服務訓練AI模型時，下列哪項是資料治理上最關鍵的考量？", OptionsJson=@"[""A. 雲端供應商使用的程式語言"", ""B. 是否有明確的資料處理與保護契約"", ""C. 雲端機房所在城市景觀"", ""D. 伺服器品牌""]", CorrectAnswer="B", Explanation=@"需確認雲端服務如何儲存、處理與刪除資料，以及是否符合法規與契約約定。" },
            new() { Id=5056, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"某AI系統開發時未納入多元族群資料，導致實際部署後對少數族群誤判率極高，這顯示開發階段缺少哪一項？", OptionsJson=@"[""A. 效能調校"", ""B. 多元與包容性考量"", ""C. 硬體升級"", ""D. 廣告預算""]", CorrectAnswer="B", Explanation=@"資料與設計階段若未納入多元樣本與觀點，容易在部署時造成系統性不公平。" },
            new() { Id=5057, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"下列何種作法最符合GDPR對AI相關自動化決策的要求？", OptionsJson=@"[""A. 完全不讓使用者知道有使用AI"", ""B. 提供使用者查詢與異議管道，並說明決策邏輯概要"", ""C. 要求使用者放棄所有權利"", ""D. 只保留模型輸出紀錄""]", CorrectAnswer="B", Explanation=@"GDPR強調自動化決策的透明度與使用者權利，包括知情權與異議權。" },
            new() { Id=5058, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"企業若想同時參考NIST標準並符合GDPR/CCPA，最適合的實務做法是？", OptionsJson=@"[""A. 只採用單一法規即可"", ""B. 將NIST的技術與風險管理做法對應到GDPR/CCPA要求"", ""C. 忽略隱私議題"", ""D. 只看演算法準確率""]", CorrectAnswer="B", Explanation=@"以NIST提供的安全與風險管理措施作為實作指南，對齊GDPR/CCPA法規義務。" },
            new() { Id=5059, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"在評估AI系統「可解釋性」時，下列哪種情況最令人擔憂？", OptionsJson=@"[""A. 模型文件完整"", ""B. 可提供關鍵特徵重要性與規則"", ""C. 系統無法說明任何決策依據且拒絕外部稽核"", ""D. 提供模型版本歷史""]", CorrectAnswer="C", Explanation=@"完全無法說明決策依據且不能稽核，代表高度黑箱，難以符合治理要求。" },
            new() { Id=5060, ChapterId=1301, Type="multiple", Difficulty=3, QuestionText=@"某AI聊天機器人在上線前未進行對抗性測試與內容過濾，上線後迅速學習到大量仇恨言論。此案例最主要缺少哪一類治理措施？", OptionsJson=@"[""A. 行銷策略"", ""B. 前測與防護性設計（如濾毒機制與緊急停用流程）"", ""C. 增加運算資源"", ""D. 更炫的介面設計""]", CorrectAnswer="B", Explanation=@"缺乏內容審查、對抗性測試與緊急下線機制，使系統易被惡意操弄。" },
            new() { Id=5061, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某製造公司想導入「機器故障預測系統」，打算蒐集生產線上每秒感測器數據並記錄設備是否在之後一週內發生故障。下列哪一項做法最適合用於建立預測模型？", OptionsJson=@"[""A. 只蒐集是否故障(是/否)不需蒐集感測器數據"", ""B. 將感測器時間序列資料與未來是否故障標記起來用監督式學習模型預測故障機率"", ""C. 不加任何標記直接用KNN將資料分群做故障預測"", ""D. 只用靜態的員工人數與班別資訊作為模型輸入""]", CorrectAnswer="B", Explanation=@"故障預測是有標籤的預測問題,需將時間序列感測器數據與故障標記結合並用監督式學習訓練模型。KNN不擅長處理時間依賴性,只用計數或不含特徵的做法無法得到有效模型。" },
            new() { Id=5062, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某資料科學家取得一份大型客戶交易資料表(行列欄位明確)準備訓練模型預測客戶是否流失並以70%:15%:15%分為訓練集、驗證集與測試集。關於這種做法何者最正確？", OptionsJson=@"[""A. 三個資料集都可在訓練過程中一起用來調整模型參數"", ""B. 驗證集主要用於訓練模型訓練集則用於調整超參數"", ""C. 測試集只在訓練完成後使用用於對模型做最終且公平的效能評估"", ""D. 由於資料很多因此不需要驗證集只要訓練集與測試集即可""]", CorrectAnswer="C", Explanation=@"訓練集用於模型學習,驗證集用於訓練過程中調整超參數,測試集保留到最後做最終且公平的效能評估,不能在訓練過程中使用。" },
            new() { Id=5063, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"有關「資料是AI的訓練燃料」與「資料是新石油」的說法下列哪一項最能正確說明其意涵？", OptionsJson=@"[""A. 資料可以完全取代演算法單靠資料就能產生準確預測"", ""B. 只要資料量足夠大就不需要在乎資料品質"", ""C. 資料是驅動AI演算法學習與做出預測的關鍵資源其品質與多樣性直接影響模型效能與商業價值"", ""D. 資料的價值主要在於佔用儲存空間可以用來測試硬體效能""]", CorrectAnswer="C", Explanation=@"這兩種比喻都在強調資料在AI時代的核心資源地位:資料驅動演算法學習並帶來商業價值,而不是單靠演算法或硬體。" },
            new() { Id=5064, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某家公司同時擁有以下三種資料:(1)資料庫中的客戶資料表(2)外部API回傳的JSON產品資訊(3)客戶社群貼文截圖圖片。下列哪一組「結構型態」分類最適當？", OptionsJson=@"[""A. (1)結構化(2)半結構化(3)非結構化"", ""B. (1)非結構化(2)結構化(3)半結構化"", ""C. (1)半結構化(2)非結構化(3)結構化"", ""D. (1)(2)(3)全部都是非結構化""]", CorrectAnswer="A", Explanation=@"資料庫表格屬結構化,JSON帶有標記與階層屬半結構化,圖片檔沒有固定欄位屬非結構化。" },
            new() { Id=5065, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"研究人員蒐集以下四種變數:(1)每位員工身高(公分)(2)每家門市每日來店顧客人數(3)產品售價(元可有小數)(4)每棟大樓樓層數。關於這四種變數的資料型態何者最正確？", OptionsJson=@"[""A. (1)(3)為離散資料(2)(4)為連續資料"", ""B. (1)(3)為連續資料(2)(4)為離散資料"", ""C. 四者皆為連續資料"", ""D. 四者皆為離散資料""]", CorrectAnswer="B", Explanation=@"身高與售價可取任意實數值屬連續資料;顧客人數與樓層數只能是整數計數屬離散資料。" },
            new() { Id=5066, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在監督式學習中為什麼標記資料特別重要？", OptionsJson=@"[""A. 因為標記資料可以減少儲存空間"", ""B. 因為標記資料讓模型能學習輸入與正確輸出之間的關係"", ""C. 因為標記資料只適合非監督式學習"", ""D. 因為標記資料可以避免時間序列的問題""]", CorrectAnswer="B", Explanation=@"監督式學習需要成對的輸入與目標輸出,模型透過這些標記案例學會如何預測正確結果。" },
            new() { Id=5067, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列何者最符合「未標記資料」的描述？", OptionsJson=@"[""A. 附有輸入與對應正確標籤的資料"", ""B. 只有輸入特徵沒有對應目標標記的資料"", ""C. 只包含時間戳記沒有任何特徵的資料"", ""D. 只包含文字型態的資料""]", CorrectAnswer="B", Explanation=@"未標記資料僅有輸入特徵沒有目標輸出,常用於非監督式學習如聚類分析。" },
            new() { Id=5068, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某問卷調查請受訪者選擇「非常不滿意、不滿意、普通、滿意、非常滿意」。此題的資料型態屬於何者？", OptionsJson=@"[""A. 名目資料"", ""B. 連續資料"", ""C. 有序資料"", ""D. 時間序列資料""]", CorrectAnswer="C", Explanation=@"滿意度選項之間具有明顯順序但間距不一定相同,因此屬有序資料。" },
            new() { Id=5069, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"關於時間序列資料的敘述下列何者正確？", OptionsJson=@"[""A. 每筆資料無須時間戳記只要有數值即可"", ""B. 重點在隨機性因此不強調順序"", ""C. 每個資料點通常附有時間戳記並依時間順序排列"", ""D. 只要是金融資料就一定是時間序列資料""]", CorrectAnswer="C", Explanation=@"時間序列資料的核心特徵是具有時間戳記且依時間順序排列,可呈現趨勢與季節性。" },
            new() { Id=5070, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列哪一種應用最典型地使用時間序列資料？", OptionsJson=@"[""A. 一次性問卷調查的統計分析"", ""B. 將員工按部門分群的聚類分析"", ""C. 分析股價每日收盤價的變化趨勢"", ""D. 比較不同城市的平均身高""]", CorrectAnswer="C", Explanation=@"股價每日收盤價是按時間連續產生的數據,非常典型的時間序列應用。" },
            new() { Id=5071, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某分析師要把產品售價分成「低價、中價、高價」三類以簡化模型。此做法最可能產生哪一種影響？", OptionsJson=@"[""A. 提升資料的精細度"", ""B. 完全避免任何資訊損失"", ""C. 降低計算複雜度但可能損失部分連續資訊"", ""D. 讓資料自動轉為時間序列資料""]", CorrectAnswer="C", Explanation=@"將連續變數離散化可簡化模型與解釋,但會犧牲部分精細資訊,需在效率與精度間權衡。" },
            new() { Id=5072, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最不可能被視為結構化資料？", OptionsJson=@"[""A. 關聯式資料庫中的顧客資料表"", ""B. Excel 銷售紀錄表"", ""C. JSON 格式API回應"", ""D. 資料倉儲中的訂單明細表""]", CorrectAnswer="C", Explanation=@"JSON雖有結構標記但非固定行列表格,屬半結構化而非結構化資料。" },
            new() { Id=5073, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"關於文本資料的應用下列敘述何者正確？", OptionsJson=@"[""A. 圖像分類是典型文本資料應用"", ""B. 客服聊天機器人是文本資料常見應用"", ""C. 語音辨識只使用音頻資料與文本無關"", ""D. 醫學影像診斷主要使用文本資料""]", CorrectAnswer="B", Explanation=@"客服聊天機器人需理解與產生文字內容,是文本資料與自然語言處理的典型應用。" },
            new() { Id=5074, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某公司希望將客戶依購買行為自動分群以設計不同行銷方案。如只使用未標記的交易紀錄下列哪種方法最適合？", OptionsJson=@"[""A. 監督式學習的分類模型"", ""B. 聚類分析等非監督式學習方法"", ""C. 時間序列分解方法"", ""D. KNN 用於標記資料的最近鄰分類""]", CorrectAnswer="B", Explanation=@"沒有標籤時適合使用非監督式聚類方法,從資料中自動發現群組結構。" },
            new() { Id=5075, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在故障預測情境中感測器數據以每分鐘一筆連續記錄。此種資料最適合被歸類為：", OptionsJson=@"[""A. 名目資料"", ""B. 時間序列資料"", ""C. 非結構化資料"", ""D. 有序分類資料""]", CorrectAnswer="B", Explanation=@"感測器數據附帶時間戳記並按時間順序收集,典型時間序列資料。" },
            new() { Id=5076, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能代表離散資料的例子？", OptionsJson=@"[""A. 一天中的平均氣溫"", ""B. 產品長度(公分)"", ""C. 每小時網站造訪人數"", ""D. 股票價格變化""]", CorrectAnswer="C", Explanation=@"造訪人數為整數計數不能取中間值,是離散資料;其餘多可取連續數值。" },
            new() { Id=5077, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"某公司儲存顧客來電錄音檔以訓練語音辨識系統。這些錄音檔最適合被歸類為哪一種資料型態？", OptionsJson=@"[""A. 文本資料"", ""B. 音頻資料"", ""C. 影像資料"", ""D. 結構化資料""]", CorrectAnswer="B", Explanation=@"錄音檔屬聲音訊號,是語音辨識與語音分析所使用的音頻資料。" },
            new() { Id=5078, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在機器學習專案中為何需要將資料分成訓練集與驗證集？", OptionsJson=@"[""A. 讓兩者一起用於最終公平評估模型"", ""B. 避免測試集過大"", ""C. 在訓練過程中利用驗證集調整超參數並監控過擬合情形"", ""D. 方便儲存不同格式的資料""]", CorrectAnswer="C", Explanation=@"訓練集用於學習,驗證集則在訓練過程中評估效能與調整超參數,避免模型過度貼合訓練資料。" },
            new() { Id=5079, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"若某資料欄位記錄「員工是否為主管」(是/否)，該欄位最適合歸類為：", OptionsJson=@"[""A. 連續資料"", ""B. 有序資料"", ""C. 名目資料"", ""D. 時間序列資料""]", CorrectAnswer="C", Explanation=@"是/否屬於無自然順序的分類標籤,因此是名目資料。" },
            new() { Id=5080, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"時間序列資料常具有趨勢與季節性。下列哪一項最能代表季節性？", OptionsJson=@"[""A. 股價長期由低走高"", ""B. 每年暑假冰品銷量顯著增加"", ""C. 隨機出現的單次促銷活動"", ""D. 某天突然發生的系統故障""]", CorrectAnswer="B", Explanation=@"季節性指隨季節或週期性時間規律而出現的變化,如暑假或冬季的固定模式。" },
            new() { Id=5081, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在一個圖像辨識專案中訓練資料包含大量圖片以及對應物體標籤(如貓、狗、車)。此種訓練資料應被視為：", OptionsJson=@"[""A. 未標記圖像資料"", ""B. 標記圖像資料"", ""C. 半結構化資料"", ""D. 時間序列資料""]", CorrectAnswer="B", Explanation=@"同時有圖片(輸入)與物體標籤(輸出),是典型的標記資料用於監督式學習。" },
            new() { Id=5082, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"某公司從API取得JSON格式的產品資訊再轉換並寫入資料庫表格。關於此流程下列敘述何者較為正確？", OptionsJson=@"[""A. 原始JSON屬結構化資料轉成資料庫後變為半結構化"", ""B. 原始JSON屬半結構化資料轉成資料庫表後變為結構化"", ""C. 兩者都是非結構化資料"", ""D. 兩者都屬時間序列資料""]", CorrectAnswer="B", Explanation=@"JSON有標籤與階層結構但不是固定表格屬半結構化;寫入資料庫表後以行列呈現屬結構化資料。" },
            new() { Id=5083, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"下列哪一種情境最需要特別注意時間依賴性而不宜直接使用一般KNN模型？", OptionsJson=@"[""A. 依客戶年齡與收入預測是否購買保險"", ""B. 依病患身高體重預測是否有高血壓"", ""C. 依機器感測器按時間連續紀錄預測未來一小時是否故障"", ""D. 依學生固定背景資料預測是否通過考試""]", CorrectAnswer="C", Explanation=@"機器感測器數據會隨時間變化且前後點高度相關,屬時間序列問題,較適合使用RNN、LSTM等考慮序列性的模型。" },
            new() { Id=5084, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"下列題目中哪一項最能測出學生是否理解「資料品質」對AI模型的影響？", OptionsJson=@"[""A. 詢問學生是否記得常見演算法的名稱"", ""B. 比較高品質與低品質標記資料對模型預測準確率的差異"", ""C. 讓學生背誦不同資料庫欄位型態"", ""D. 要求學生說出CSV的完整英文名稱""]", CorrectAnswer="B", Explanation=@"觀察不同品質標記資料對模型效能的差異,能直接反映學生是否理解資料品質的重要性。" },
            new() { Id=5085, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"某公司想利用歷史銷售記錄預測未來需求並優化庫存。下列哪一個步驟若做不好最容易導致模型在實務上表現不佳？", OptionsJson=@"[""A. 將訓練集與測試集中的資料時間區間完全重疊"", ""B. 在資料中加入時間標籤並依時間分割訓練與測試集"", ""C. 刪除所有缺失值並隨機打亂資料順序"", ""D. 只使用最近一天的資料作為全部訓練資料""]", CorrectAnswer="A", Explanation=@"若訓練與測試時間區間重疊,模型在測試集上看似很好但無法真實反映未來資料,會嚴重高估效能。" },
            new() { Id=5086, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"下列哪一種資料最不可能直接用簡單的表格行列結構完整表示？", OptionsJson=@"[""A. 每筆訂單的金額與日期"", ""B. 機器每毫秒收集的多維感測器時間序列"", ""C. 每位顧客的聯絡電話與地址"", ""D. 每件商品的庫存數量""]", CorrectAnswer="B", Explanation=@"多維高頻時間序列包含大量連續時間點與多種變數,若完全攤平成表格會非常巨大且難以操作。" },
            new() { Id=5087, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"如果在訓練模型時不小心使用了部分測試資料來調整超參數最可能的結果是什麼？", OptionsJson=@"[""A. 模型在實務上的表現會比評估結果更好"", ""B. 模型的訓練時間大幅縮短"", ""C. 模型在測試集上的表現被高估失去公平性"", ""D. 模型無法收斂需要重新訓練""]", CorrectAnswer="C", Explanation=@"測試資料若被用於調參,其評估結果不再獨立,會高估模型真正泛化能力,違反公平評估原則。" },
            new() { Id=5088, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"某資料科學家聲稱:「我使用非結構化資料所以完全不需要前處理。」下列哪一項是對此說法較好的回應？", OptionsJson=@"[""A. 正確非結構化資料天然就適合模型使用"", ""B. 部分正確只有在使用時間序列時才需要前處理"", ""C. 不正確非結構化資料通常更需要轉換與特徵抽取才能被模型有效利用"", ""D. 正確因為深度學習可以自動處理所有資料""]", CorrectAnswer="C", Explanation=@"非結構化資料如文字、圖片、音頻通常需要清理、轉換與特徵抽取,才能成為模型可用的輸入。" },
            new() { Id=5089, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"關於名目資料與有序資料的差異下列敘述何者最接近考試常見陷阱？", OptionsJson=@"[""A. 將血型視為有序資料因為有四種型別"", ""B. 將滿意度評分視為有序資料因為有明顯順序"", ""C. 將國籍視為名目資料因為沒有自然順序"", ""D. 將教育程度(國中高中大學研究所)視為有序資料""]", CorrectAnswer="B", Explanation=@"考題常把滿意度評分與血型對調,血型沒有順序屬名目,滿意度有順序屬有序,若背錯分類容易中陷阱。" },
            new() { Id=5090, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在故障預測專案中若只選取「是否故障」欄位作為輸入特徵與輸出標籤同時使用最可能發生什麼情況？", OptionsJson=@"[""A. 模型能學會故障前的早期徵兆"", ""B. 模型會因為資訊過多而無法訓練"", ""C. 模型會形成完美預測但在實務上毫無意義"", ""D. 模型能有效避免過擬合""]", CorrectAnswer="C", Explanation=@"以目標欄位同時當輸入與輸出,模型可以直接複制答案而非學習關鍵特徵,在實務上完全無法泛化。" },
            new() { Id=5091, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在規劃資料處理與分析流程時，為何常強調必須先明確定義商業問題？", OptionsJson=@"[""A. 確保資料與模型設計圍繞實際需求，避免做無關分析"", ""B. 可以完全避免後續發生資料缺失問題"", ""C. 能保證不需要驗證集就能調參"", ""D. 使得任何演算法都能達到最優解""]", CorrectAnswer="A", Explanation=@"若一開始未定義清楚商業問題，後續資料收集、清理與建模可能偏離真正需求，造成資源浪費。" },
            new() { Id=5092, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在進行資料收集時，哪一項考量最能直接影響後續資料整理與分析的品質？", OptionsJson=@"[""A. 資料來源是否方便取得"", ""B. 是否全部為結構化資料"", ""C. 資料的代表性與可靠性是否足夠"", ""D. 是否全部儲存在雲端""]", CorrectAnswer="C", Explanation=@"若資料本身缺乏代表性或品質不佳，後續再多清理與建模也難以得到可靠結論。" },
            new() { Id=5093, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最接近資料整理（Data Cleaning）的主要目標？", OptionsJson=@"[""A. 將所有資料轉換為同一種檔案格式"", ""B. 確保資料盡可能準確、一致且沒有明顯錯誤"", ""C. 讓資料量變得越大越好"", ""D. 將所有欄位都轉為文字型態""]", CorrectAnswer="B", Explanation=@"資料整理重點在修正錯誤、處理缺失與不一致，以提升資料品質，而非單純改變格式或放大資料量。" },
            new() { Id=5094, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在資料處理流程中加入「資料探索性分析（EDA）」主要可以帶來什麼好處？", OptionsJson=@"[""A. 完全取代後續的模型訓練"", ""B. 協助了解資料分布、異常值與關聯，幫助決定後續處理策略"", ""C. 避免需要再做任何資料清理"", ""D. 直接提供可部署的預測模型""]", CorrectAnswer="B", Explanation=@"EDA 讓分析者理解資料結構與問題特性，有助選擇合適的清理方式與建模方法。" },
            new() { Id=5095, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"為何在機器學習專案中，常說「資料預處理」會比選擇演算法更關鍵？", OptionsJson=@"[""A. 演算法都一樣，差別只在資料"", ""B. 良好的資料預處理能顯著提升多種模型的表現與穩定性"", ""C. 只要演算法足夠複雜就不需要預處理"", ""D. 預處理只會延長專案時間，沒有實際效益""]", CorrectAnswer="B", Explanation=@"多數演算法對資料品質相當敏感，適當預處理有助於提高泛化能力與可解釋性。" },
            new() { Id=5096, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最適合作為資料編碼（Encoding）的目的說明？", OptionsJson=@"[""A. 增加欄位數量以提升難度"", ""B. 將類別或文字型資料轉成模型可處理的數值形式"", ""C. 縮小資料檔案容量"", ""D. 將標籤改成更好看的名稱""]", CorrectAnswer="B", Explanation=@"多數機器學習演算法需要數值輸入，編碼是為了將非數值資訊轉為可運算格式。" },
            new() { Id=5097, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"對於「城市類別」欄位有 10 個不同城市，若使用獨熱編碼（One-Hot Encoding），最可能產生的影響是什麼？", OptionsJson=@"[""A. 欄位數量增加，但不會引入城市間的順序關係"", ""B. 欄位數量大幅減少"", ""C. 城市之間會形成大小關係"", ""D. 會自動修正城市名稱的錯字""]", CorrectAnswer="A", Explanation=@"獨熱編碼會為每個城市建立一個二元欄位，維度增加但避免了虛假的順序與距離。" },
            new() { Id=5098, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在資料縮放（Scaling）中使用 Min-Max 正規化時，典型的作法是什麼？", OptionsJson=@"[""A. 將資料轉為平均數為 0、標準差為 1"", ""B. 將資料壓縮到 0 與 1 之間的區間"", ""C. 把所有資料改成 0"", ""D. 將欄位轉為類別變數""]", CorrectAnswer="B", Explanation=@"Min-Max 正規化常將數值映射到 [0,1] 或其他固定範圍，以避免某些特徵因尺度過大而主導模型。" },
            new() { Id=5099, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"若某欄位的數值範圍遠大於其他欄位，未經任何縮放就直接訓練模型，最可能的結果為何？", OptionsJson=@"[""A. 模型會更快收斂"", ""B. 該欄位可能過度影響模型權重，掩蓋其他重要特徵"", ""C. 模型完全不受影響"", ""D. 模型會自動刪除該欄位""]", CorrectAnswer="B", Explanation=@"未縮放時，大範圍特徵可能在優化過程中占主導地位，使其他特徵影響被弱化。" },
            new() { Id=5100, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在資料分割時，常採用「訓練集＋測試集」的最基本切分方式，其主要目的為何？", OptionsJson=@"[""A. 節省儲存空間"", ""B. 預先模擬模型在未見資料上的表現，以評估泛化能力"", ""C. 避免需要交叉驗證"", ""D. 加快特徵工程的速度""]", CorrectAnswer="B", Explanation=@"訓練集用於學習，測試集保留作為獨立評估，檢驗模型泛化能力。" },
            new() { Id=5101, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"為什麼在使用驗證集調整超參數後，仍然需要保留測試集？", OptionsJson=@"[""A. 測試集可用來再調一次參數"", ""B. 測試集作為完全未參與調參的資料，用於最終性能評估"", ""C. 驗證集只用於儲存資料備份"", ""D. 測試集只用來檢查資料格式是否正確""]", CorrectAnswer="B", Explanation=@"若使用同一資料調參又評估，容易高估模型表現；測試集需保持獨立。" },
            new() { Id=5102, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在資料清理中處理缺失值時，下列哪種作法最容易導致偏差？", OptionsJson=@"[""A. 根據變數分布進行合理插補"", ""B. 直接刪除少量缺失值列且樣本數仍充足"", ""C. 對關鍵變數的大量缺失列全部刪除，未評估影響"", ""D. 視情況使用中位數填補連續變數""]", CorrectAnswer="C", Explanation=@"對關鍵變數大量刪除可能破壞樣本結構與代表性，造成分析結果偏差。" },
            new() { Id=5103, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"若資料集中存在明顯的極端異常值，通常最適切的第一步是什麼？", OptionsJson=@"[""A. 無條件將所有極端值刪除"", ""B. 先檢視異常值可能的成因與對分析目標的影響"", ""C. 將異常值全部設為 0"", ""D. 忽略異常值，直接建模""]", CorrectAnswer="B", Explanation=@"了解異常值是否為輸入錯誤、罕見但真實事件或重要風險指標，有助決定適當處理策略。" },
            new() { Id=5104, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"資料整合（Data Integration）的主要挑戰之一是什麼？", OptionsJson=@"[""A. 檔名不一致"", ""B. 必須將所有資料轉成影像才可整合"", ""C. 不同來源資料在欄位定義與格式上可能不一致"", ""D. 無法同時處理數值與文字資料""]", CorrectAnswer="C", Explanation=@"異質資料來源常有欄位名稱、類型與編碼方式差異，需要對齊與轉換。" },
            new() { Id=5105, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在資料處理流程中，為何要考慮資料的時間序列特性（例如按日記錄的銷售資料）？", OptionsJson=@"[""A. 時間序列資料不需要預處理"", ""B. 時間順序可能影響資料分割與特徵設計，例如不能隨機打散全部資料"", ""C. 可以任意打散、混合，不會影響模型"", ""D. 時間資訊在所有情境下都不重要""]", CorrectAnswer="B", Explanation=@"對時間序列常需依時間分割訓練與測試，以避免未來資料洩漏到模型訓練中。" },
            new() { Id=5106, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在特徵工程中，將「日期時間」拆成「日期」與「小時」欄位，主要屬於哪種作法？", OptionsJson=@"[""A. 資料縮放"", ""B. 特徵分解與重組，以擷取更有意義的資訊"", ""C. 資料標註"", ""D. 資料合併""]", CorrectAnswer="B", Explanation=@"透過分解欄位可專注於與問題最相關的時間粒度，例如某些問題只與「時段」有關。" },
            new() { Id=5107, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在資料預處理階段，為何常會同時使用「標準化」與「降維」技術？", OptionsJson=@"[""A. 標準化可以取代降維"", ""B. 兩者結合可在平衡特徵尺度的同時，壓縮維度並保留重要資訊"", ""C. 降維只適用於已標準化的文字資料"", ""D. 標準化會自動完成降維""]", CorrectAnswer="B", Explanation=@"先標準化可避免某些變數因尺度巨大主導降維過程，再透過降維提取關鍵結構。" },
            new() { Id=5108, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在完整的資料處理與分析流程中，下列哪一個步驟最常被用來檢查模型是否過擬合？", OptionsJson=@"[""A. 只看訓練集上的準確率"", ""B. 比較訓練集與驗證集（或測試集）上的表現差異"", ""C. 只看資料清理前的準確率"", ""D. 檢查欄位數是否足夠多""]", CorrectAnswer="B", Explanation=@"若訓練表現遠好於驗證或測試，通常代表模型過度擬合訓練資料。" },
            new() { Id=5109, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能代表資料處理與分析流程中「迭代」的重要性？", OptionsJson=@"[""A. 流程一定一次完成，不能回頭修正"", ""B. 隨著對資料與模型理解加深，需不斷調整清理策略與特徵工程"", ""C. 只要第一次模型表現不錯就不再調整"", ""D. 每次迭代必須更換演算法""]", CorrectAnswer="B", Explanation=@"資料科學專案通常透過多次迭代，逐步修正資料處理與模型設計，提升成效。" },
            new() { Id=5110, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"若在部署模型後，持續監測到預測表現下降，最合理的第一步處理方式是什麼？", OptionsJson=@"[""A. 立即更換成完全不同的演算法"", ""B. 回頭檢查資料分布是否隨時間改變，可能需要重新收集與處理資料"", ""C. 強制模型輸出固定值"", ""D. 完全停止使用資料驅動決策""]", CorrectAnswer="B", Explanation=@"資料漂移會使原模型不再適用，需要重新檢查與更新資料與模型。" },
            new() { Id=5111, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在高度類別不平衡的二元分類問題中，下列哪一種資料處理策略最能協助改善模型對少數類別的辨識？", OptionsJson=@"[""A. 對多數類別進行適度下採樣或對少數類別進行適度上採樣"", ""B. 刪除少數類別的所有樣本"", ""C. 只用準確率作為唯一評估指標"", ""D. 將所有樣本標記為多數類別""]", CorrectAnswer="A", Explanation=@"調整類別比例可讓模型有足夠機會學習少數類別特徵，搭配適當評估指標更有效。" },
            new() { Id=5112, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在處理高維度資料時，為何常需要搭配特徵選擇或降維技術？", OptionsJson=@"[""A. 高維度一定代表資訊更完整"", ""B. 過多特徵可能引入噪音並增加計算成本，反而降低模型泛化能力"", ""C. 特徵越多越不可能過擬合"", ""D. 高維度資料不需要任何預處理""]", CorrectAnswer="B", Explanation=@"高維資料易產生維度災難與過擬合，適度壓縮特徵空間可提升效率與表現。" },
            new() { Id=5113, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"若在資料清理過程中，將所有離群值都無條件刪除，可能造成什麼風險？", OptionsJson=@"[""A. 模型一定變得更穩定"", ""B. 可能連同關鍵的罕見但重要事件（如詐欺）也被刪除"", ""C. 不會產生任何影響"", ""D. 可以保證模型不再過擬合""]", CorrectAnswer="B", Explanation=@"有些離群點代表特殊但重要的情境，若盲目刪除會讓模型失去偵測能力。" },
            new() { Id=5114, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在資料標準化前，發現某數值特徵呈現高度右偏且有極端大值，下列何種處理順序較佳？", OptionsJson=@"[""A. 先標準化，再觀察是否需要對數轉換"", ""B. 先進行對數或根號轉換降低偏態，再做標準化"", ""C. 直接刪除所有大於平均數的值"", ""D. 只做標準化即可""]", CorrectAnswer="B", Explanation=@"先透過對數等轉換減少偏態和極端值影響，再標準化有助於穩定模型訓練。" },
            new() { Id=5115, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在資料分割時，若將時間序列資料隨機打散後再切出訓練與測試集，最可能造成哪種問題？", OptionsJson=@"[""A. 增加訓練速度"", ""B. 導致未來資訊洩漏到訓練過程，評估過度樂觀"", ""C. 完全無法訓練模型"", ""D. 使資料變成非結構化""]", CorrectAnswer="B", Explanation=@"時間序列應依時間先後分割，隨機打散會讓模型在訓練時看見未來資料，評估不實際。" },
            new() { Id=5116, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在資料整合過程中，若不同系統對「性別」欄位分別使用 'M/F' 與 '1/0' 表示，最佳的處理方式是什麼？", OptionsJson=@"[""A. 直接將兩者視為不同欄位"", ""B. 選一種統一轉換標準，將所有資料映射到共同編碼"", ""C. 刪除此欄位以簡化處理"", ""D. 保留原樣不做任何處理""]", CorrectAnswer="B", Explanation=@"需建立一致的編碼規則，將異質來源標準化，才能正確整合與分析。" },
            new() { Id=5117, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在進行 PCA 時，為何通常需要先對各特徵進行標準化？", OptionsJson=@"[""A. 避免 PCA 自動刪除部分特徵"", ""B. 確保所有特徵在相同尺度，以免尺度大的特徵主導主成分"", ""C. 讓 PCA 可以處理類別型變數"", ""D. 標準化可以直接產生主成分""]", CorrectAnswer="B", Explanation=@"若未標準化，數值範圍大的特徵會對協方差矩陣產生較大影響，扭曲主成分方向。" },
            new() { Id=5118, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在完整資料處理流程中，若只在訓練資料上進行缺失值填補與縮放，而沒有在測試資料上套用相同規則，會產生什麼後果？", OptionsJson=@"[""A. 不會有影響"", ""B. 測試資料的特徵分布與訓練資料不一致，導致評估結果失真"", ""C. 模型會自動對測試資料重新訓練"", ""D. 測試集準確率一定更高""]", CorrectAnswer="B", Explanation=@"資料轉換必須用訓練集學到的規則套用在測試集上，才能維持一致性。" },
            new() { Id=5119, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在建立資料處理流程時，使用自動化流程（如流水線 / Pipeline）的主要優點之一為何？", OptionsJson=@"[""A. 可以避免所有錯誤"", ""B. 讓資料永遠不需要清理"", ""C. 確保同樣的前處理步驟以固定順序一致地套用在訓練與測試資料上"", ""D. 只適用於深度學習模型""]", CorrectAnswer="C", Explanation=@"自動化流程能減少人為遺漏步驟或順序錯誤，保障實驗與部署的一致性。" },
            new() { Id=5120, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在評估整體資料處理與分析流程的品質時，下列哪一項指標最能反映流程是否真正支援決策？", OptionsJson=@"[""A. 模型在訓練集上的最高準確率"", ""B. 流程執行時間是否最短"", ""C. 模型在實務情境下對業務指標（如成本、風險、收益）的實際改善程度"", ""D. 使用的演算法是否最新""]", CorrectAnswer="C", Explanation=@"資料與模型的最終目的在於改善實際決策與績效，而不只是追求單一技術指標。" },
            new() { Id=5121, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"AI在資料隱私方面的主要風險最常與哪一項有關？", OptionsJson=@"[""A. 資料濫用與推理攻擊"", ""B. 硬體設備老化"", ""C. 網路頻寬不足"", ""D. 模型訓練時間過長""]", CorrectAnswer="A", Explanation=@"AI可能過度蒐集個人資料並透過推理演算法推斷敏感資訊，形成資料濫用與推理攻擊風險。" },
            new() { Id=5122, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"未經同意蒐集個人資料的AI作法，主要違反了哪一項原則？", OptionsJson=@"[""A. 演算法效率"", ""B. 隱私與資料保護"", ""C. 開放原始碼精神"", ""D. 單一責任原則""]", CorrectAnswer="B", Explanation=@"未經同意即蒐集個人資料，可能違反隱私法規並侵害個人資料保護原則。" },
            new() { Id=5123, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能代表AI對個人隱私的典型威脅情境？", OptionsJson=@"[""A. 模型推論速度過慢"", ""B. 訓練資料維度過多"", ""C. 大規模監控與行為追蹤"", ""D. 雲端儲存成本過高""]", CorrectAnswer="C", Explanation=@"政府或企業可利用AI實施大規模監控與行為追蹤，嚴重影響個人隱私與自由。" },
            new() { Id=5124, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"AI系統大量蒐集生物識別、瀏覽歷史與健康資料的主要隱私風險為何？", OptionsJson=@"[""A. 演算法無法收斂"", ""B. 系統無法進行線上學習"", ""C. 伺服器難以部署"", ""D. 個人隱私暴露風險增加""]", CorrectAnswer="D", Explanation=@"資料類型越廣、敏感度越高，被濫用或洩漏時對個人隱私的影響越大。" },
            new() { Id=5125, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"AI系統重新利用履歷或照片作為訓練資料時，最大隱憂為何？", OptionsJson=@"[""A. 資料標註成本過高"", ""B. 模型準確率下降"", ""C. 運算資源浪費"", ""D. 未經同意使用個人資料""]", CorrectAnswer="D", Explanation=@"在當事人不知情或未同意下重複利用個人資料，容易違反隱私權與資料保護規範。" },
            new() { Id=5126, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"差分隱私在AI訓練中的主要目的為何？", OptionsJson=@"[""A. 縮短模型推論時間"", ""B. 降低識別單一個體的可能性"", ""C. 提高硬體效能"", ""D. 簡化使用者介面""]", CorrectAnswer="B", Explanation=@"差分隱私透過加入隨機雜訊，使攻擊者難以從結果推斷出特定個人的資訊。" },
            new() { Id=5127, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"隱私影響評估(PIA)在AI系統中的主要功能是什麼？", OptionsJson=@"[""A. 提升模型運算速度"", ""B. 預先評估系統是否可能侵犯個人隱私"", ""C. 減少網路延遲"", ""D. 優化使用者體驗介面""]", CorrectAnswer="B", Explanation=@"PIA在系統部署前評估隱私風險，有助於及早發現與降低可能的侵害。" },
            new() { Id=5128, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"以下哪一項是維護AI資料隱私的常見實務？", OptionsJson=@"[""A. 只追求最高準確率"", ""B. 完全匿名化所有資料而不考慮效益"", ""C. 導入隱私保護技術並遵循監管標準"", ""D. 僅依公司內規自律""]", CorrectAnswer="C", Explanation=@"技術措施加上法規遵循，才能在使用AI優勢時同時降低隱私風險。" },
            new() { Id=5129, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"當AI使用含偏見的訓練資料時，下列何種結果最值得擔心？", OptionsJson=@"[""A. 系統運算速度變慢"", ""B. 儲存空間不足"", ""C. 前端介面不友善"", ""D. 產生不公平甚至歧視性的決策""]", CorrectAnswer="D", Explanation=@"偏見資料會被模型學習並在決策中放大，導致對特定群體的不公平對待。" },
            new() { Id=5130, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"AI技術的「黑箱決策」對資料隱私與權利的關鍵問題是什麼？", OptionsJson=@"[""A. 模型參數太少"", ""B. 決策過程不透明且難以解釋"", ""C. 使用者無法上傳資料"", ""D. 系統無法自動備份""]", CorrectAnswer="B", Explanation=@"黑箱決策讓使用者很難理解或質疑結果，增加隱私與權利被侵害的風險。" },
            new() { Id=5131, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"在AI情境中，資料隱私的首要目標是什麼？", OptionsJson=@"[""A. 保護個人資料權利與機密性"", ""B. 提升演算法複雜度"", ""C. 擴大量測試資料"", ""D. 降低硬體成本""]", CorrectAnswer="A", Explanation=@"資料隱私強調個人資料應被妥善保護，避免未授權使用與洩漏。" },
            new() { Id=5132, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"個人資料高度集中儲存在單一AI系統中的主要風險為何？", OptionsJson=@"[""A. 造成系統版本太多"", ""B. 增加前端框架轉換成本"", ""C. 導致使用者介面不一致"", ""D. 成為攻擊目標導致資料洩漏""]", CorrectAnswer="D", Explanation=@"集中化儲存使攻擊者只要突破單一點就可能取得大量敏感資料。" },
            new() { Id=5133, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"以下哪一敘述最能說明「AI同時威脅也能保護資料隱私」？", OptionsJson=@"[""A. AI可能造成洩漏，但也能透過威脅偵測與異常分析增強保護"", ""B. AI只能造成洩漏無法防禦"", ""C. AI只與隱私無關的技術相關"", ""D. AI僅在硬體安全上有幫助""]", CorrectAnswer="A", Explanation=@"AI可用於攻擊或不當使用，也可用於入侵偵測與異常行為分析，形成保護機制。" },
            new() { Id=5134, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"「隱私設計原則(Privacy by Design)」的核心精神是什麼？", OptionsJson=@"[""A. 在產品上市後再視需要補強隱私"", ""B. 只在法規要求時才考慮隱私"", ""C. 從設計與流程一開始就內建隱私保護"", ""D. 完全不留任何日誌紀錄""]", CorrectAnswer="C", Explanation=@"在產品與流程全生命週期都主動納入隱私考量，可從根本降低風險。" },
            new() { Id=5135, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"為何「透明度」在資料隱私治理中特別重要？", OptionsJson=@"[""A. 可完全消除所有資安風險"", ""B. 可讓模型自動變得更準確"", ""C. 有助建立信任並確保符合法規"", ""D. 可以取代所有加密機制""]", CorrectAnswer="C", Explanation=@"公開清楚的資料處理方式有助建立使用者信任，也便於監管機關檢視合規性。" },
            new() { Id=5136, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能說明「演算法透明性」的好處？", OptionsJson=@"[""A. 讓使用者直接修改模型參數"", ""B. 減少對任何監管的需求"", ""C. 完全避免模型過擬合"", ""D. 有助發現模型中的偏見與缺陷""]", CorrectAnswer="D", Explanation=@"能理解與檢查決策邏輯，才能及早發現對特定群體不公平的結果。" },
            new() { Id=5137, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"AI自動威脅檢測工具在隱私保護上的主要角色是什麼？", OptionsJson=@"[""A. 協助壓縮檔案大小"", ""B. 偵測潛在隱私侵犯行為並及早阻止"", ""C. 降低網路流量費用"", ""D. 自動產生使用者介面文字""]", CorrectAnswer="B", Explanation=@"此類工具透過異常與攻擊行為分析，保護資料不被惡意存取或濫用。" },
            new() { Id=5138, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"定期進行資料保護影響評估的主要目的為何？", OptionsJson=@"[""A. 提升系統前端美觀度"", ""B. 增加商業廣告點擊率"", ""C. 辨識並減輕AI系統的潛在隱私風險"", ""D. 縮短機器學習訓練週期""]", CorrectAnswer="C", Explanation=@"透過定期檢視，組織可以持續調整控制措施以符合隱私要求。" },
            new() { Id=5139, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"AI驅動的招聘系統若使用有偏見的歷史資料，最有可能造成哪種問題？", OptionsJson=@"[""A. 無法進行任何預測"", ""B. 使所有候選人得分一致"", ""C. 只影響模型訓練速度"", ""D. 對特定群體產生不公平或歧視性決策""]", CorrectAnswer="D", Explanation=@"偏見資料會延續甚至放大既有不平等，例如性別或種族歧視。" },
            new() { Id=5140, ChapterId=1302, Type="multiple", Difficulty=2, QuestionText=@"為減少AI偏見決策對個人權利的傷害，下列哪一項做法最適切？", OptionsJson=@"[""A. 檢測資料公平性並搭配可解釋AI與隱私評估"", ""B. 完全停止使用任何AI技術"", ""C. 只聘請單一族群的資料科學家"", ""D. 將所有輸入資料隨機打亂而不檢查""]", CorrectAnswer="A", Explanation=@"多面向措施包含資料公平性測試、解釋性與隱私影響評估，能較完整控管風險。" },
            new() { Id=5141, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"差分隱私技術在機器學習情境中的設計目標，下列何者最精確？", OptionsJson=@"[""A. 完全不需任何訓練資料"", ""B. 保證模型準確率永遠提升"", ""C. 消除所有類別不平衡問題"", ""D. 分析結果不因單一個人資料的有無而有明顯差異""]", CorrectAnswer="D", Explanation=@"差分隱私要求輸出對單一個體的敏感度很低，以保護個人不被識別。" },
            new() { Id=5142, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"同態加密的關鍵優勢是什麼？", OptionsJson=@"[""A. 可自動產生標註資料"", ""B. 可在不解密資料的情況下進行計算"", ""C. 確保模型一定不會過擬合"", ""D. 讓所有資料永久不需備份""]", CorrectAnswer="B", Explanation=@"同態加密允許對加密資料直接運算，解密權掌握在資料持有者手中。" },
            new() { Id=5143, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"以下哪一種作法最符合「差分隱私」在實務中的應用精神？", OptionsJson=@"[""A. 將所有欄位直接刪除"", ""B. 僅保留極少量樣本"", ""C. 只對資料做壓縮但不改變內容"", ""D. 在查詢或訓練過程中加入適當隨機雜訊""]", CorrectAnswer="D", Explanation=@"透過雜訊控制資訊洩漏，使攻擊者無法從輸出精確推回個別記錄。" },
            new() { Id=5144, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"差分隱私與同態加密這兩種技術的共同目標為何？", OptionsJson=@"[""A. 增加系統可視化效果"", ""B. 縮短需求訪談時間"", ""C. 強化前端框架效能"", ""D. 在分析與計算過程中保護資料隱私""]", CorrectAnswer="D", Explanation=@"兩者都聚焦在讓有用分析仍能進行，但不暴露個人敏感資訊。" },
            new() { Id=5145, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"聯合學習(Federated Learning)與傳統集中訓練相比，最大差異在於哪一點？", OptionsJson=@"[""A. 模型在本地資料上訓練，只回傳參數而不傳原始資料"", ""B. 所有資料都必須匯入中央伺服器"", ""C. 訓練完全不需任何網路連線"", ""D. 只能用於影像資料而非文字資料""]", CorrectAnswer="A", Explanation=@"聯合學習透過本地訓練與集中參數聚合，在不搬移原始資料的情況下完成學習。" },
            new() { Id=5146, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在醫療情境中採用聯合學習的主要隱私優勢是什麼？", OptionsJson=@"[""A. 所有病歷必須上傳雲端集中儲存"", ""B. 只提供匿名化後的統計報表給醫師"", ""C. 完全不再需要任何隱私法規"", ""D. 各機構可協作訓練模型而不暴露病患個人醫療紀錄""]", CorrectAnswer="D", Explanation=@"醫院在本地使用自身資料訓練，再共享模型更新即可，降低跨機構資料交換風險。" },
            new() { Id=5147, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"隱私保護機器學習(PPML)的核心目標為何？", OptionsJson=@"[""A. 在保護客戶資料機密性的前提下仍能訓練高效模型"", ""B. 只追求最小化訓練時間"", ""C. 將所有模型開源以交換隱私"", ""D. 完全改以合成資料取代真實資料""]", CorrectAnswer="A", Explanation=@"PPML強調在模型效能與資料隱私間取得平衡，避免敏感資訊在訓練與部署中洩漏。" },
            new() { Id=5148, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"PPML常用的技術組合包含哪幾類方法？", OptionsJson=@"[""A. 僅使用資料壓縮與快取"", ""B. 只依賴資料視覺化工具"", ""C. 只強化前端驗證機制"", ""D. 差分隱私、同態加密與安全多方計算""]", CorrectAnswer="D", Explanation=@"這些技術共同讓多方能在不暴露原始資料的前提下協同訓練模型。" },
            new() { Id=5149, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"在跨國資料共享情境中，歐盟公司與美國企業合作時，為符合法規通常需要依循哪一類機制？", OptionsJson=@"[""A. 依GDPR使用標準合約條款(SCCs)"", ""B. 完全不再共享任何資料"", ""C. 只口頭約定保護隱私即可"", ""D. 改以紙本方式傳輸資料""]", CorrectAnswer="A", Explanation=@"GDPR要求透過標準合約條款等法律工具，確保跨境傳輸仍符合保障水準。" },
            new() { Id=5150, ChapterId=1302, Type="multiple", Difficulty=3, QuestionText=@"GDPR與CCPA在AI與資料隱私領域中最關鍵的共同角色為何？", OptionsJson=@"[""A. 直接規定所有AI模型架構"", ""B. 保證企業不需再自訂內控"", ""C. 只關注硬體與網路設備安全"", ""D. 提供保護個人資料免於濫用的法律框架""]", CorrectAnswer="D", Explanation=@"兩者皆透過立法界定組織可如何蒐集、使用、共享個人資料，限制濫用行為。" },
            new() { Id=5151, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"機器學習的主要目標是什麼？", OptionsJson=@"[""A. 讓電腦能從資料中學習模式並做出預測或決策"", ""B. 讓電腦只執行固定程式碼"", ""C. 讓電腦只進行資料儲存"", ""D. 避免人類參與所有決策""]", CorrectAnswer="A", Explanation=@"機器學習的核心在於從資料中學習規律以進行預測或決策而非僅執行固定程式。" },
            new() { Id=5152, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"監督式學習中必備的資料特徵是什麼？", OptionsJson=@"[""A. 只有大量未標記資料"", ""B. 輸入資料及對應的標記輸出"", ""C. 只有類別名稱而無特徵"", ""D. 只有連續型數值但沒有標記""]", CorrectAnswer="B", Explanation=@"監督式學習依賴輸入特徵及其對應正確標記來學習輸入與輸出之間的映射關係。" },
            new() { Id=5153, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"下列何者最適合使用監督式學習中的分類模型？", OptionsJson=@"[""A. 預測明天氣溫的實際數值"", ""B. 估計房價的連續數值"", ""C. 將電子郵件判斷為垃圾郵件或正常郵件"", ""D. 計算資料集中平均值""]", CorrectAnswer="C", Explanation=@"垃圾郵件判斷屬於離散類別輸出因此適合使用分類模型。" },
            new() { Id=5154, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"在監督式學習中「標記資料」的主要作用是什麼？", OptionsJson=@"[""A. 增加資料量以節省運算資源"", ""B. 提供真實輸出讓模型學習輸入與輸出關係"", ""C. 減少特徵維度"", ""D. 將連續變數轉成類別""]", CorrectAnswer="B", Explanation=@"標記資料提供已知正確答案使模型能學習如何從輸入推得目標輸出。" },
            new() { Id=5155, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項是典型的迴歸問題？", OptionsJson=@"[""A. 預測一封信是否為垃圾郵件"", ""B. 預測使用者會點選哪一類型廣告"", ""C. 預測新產品下個月的銷售額"", ""D. 將圖片分為狗或貓""]", CorrectAnswer="C", Explanation=@"迴歸問題的輸出為連續數值例如銷售額、價格或需求量。" },
            new() { Id=5156, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"在迴歸分析中預測二手車價格時最重要的特徵組合是？", OptionsJson=@"[""A. 顏色與車門數"", ""B. 乘客人數與輪胎尺寸"", ""C. 車牌號碼與車主姓名"", ""D. 品牌年份與里程數""]", CorrectAnswer="D", Explanation=@"品牌年份與里程數與車輛價值高度相關常被用作價格預測的關鍵特徵。" },
            new() { Id=5157, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"下列何者屬於無監督式學習的典型應用？", OptionsJson=@"[""A. 根據歷史價格預測股價"", ""B. 將客戶依購買行為自動分成幾個族群"", ""C. 根據標記資料訓練垃圾郵件分類器"", ""D. 根據醫師標記診斷疾病""]", CorrectAnswer="B", Explanation=@"以 K 均值等方法依特徵自動形成群集屬於典型無監督式學習應用。" },
            new() { Id=5158, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"無監督學習與監督學習的主要差異是什麼？", OptionsJson=@"[""A. 無監督學習不用資料"", ""B. 監督學習不需要演算法"", ""C. 無監督學習使用未標記資料而監督學習使用標記資料"", ""D. 兩者皆只使用文字資料""]", CorrectAnswer="C", Explanation=@"無監督學習從未標記資料中尋找結構監督學習則需標記資料學習輸出。" },
            new() { Id=5159, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"K 均值聚類演算法在機器學習中主要用途為何？", OptionsJson=@"[""A. 將連續值轉換為類別標籤"", ""B. 減少模型的特徵數量"", ""C. 將資料劃分為 K 個相似的群集"", ""D. 評估分類器的準確率""]", CorrectAnswer="C", Explanation=@"K 均值會根據距離度量將資料分為 K 個群集使群內相似群間差異大。" },
            new() { Id=5160, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"半監督式學習最大的優點是什麼？", OptionsJson=@"[""A. 完全不需要標記資料"", ""B. 能同時利用少量標記與大量未標記資料提升模型效能"", ""C. 不需要演算法設計"", ""D. 只適用於影像資料""]", CorrectAnswer="B", Explanation=@"半監督式學習在標記成本高時以少量標記資料搭配大量未標記資料可提升模型表現。" },
            new() { Id=5161, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"下列何者最適合使用半監督式學習？", OptionsJson=@"[""A. 所有樣本都已完整標記"", ""B. 僅有少數標記樣本但有大量未標記樣本"", ""C. 完全沒有任何標記資料"", ""D. 只有少量數據且都已標記""]", CorrectAnswer="B", Explanation=@"在少量標記搭配大量未標記的情境下半監督式學習能有效利用兩種資訊。" },
            new() { Id=5162, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"強化學習中「回饋」通常以何種形式提供？", OptionsJson=@"[""A. 標記的靜態類別"", ""B. 固定權重矩陣"", ""C. 獎勵與懲罰訊號"", ""D. 隨機噪音加入輸入""]", CorrectAnswer="C", Explanation=@"強化學習透過環境提供的獎勵或懲罰訊號來調整策略以最大化長期回饋。" },
            new() { Id=5163, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"下列哪一個情境最適合使用強化學習？", OptionsJson=@"[""A. 靜態資料的房價預測"", ""B. 將圖片分為貓或狗"", ""C. 統計問卷平均分數"", ""D. 自駕車在道路上學習安全行駛策略""]", CorrectAnswer="D", Explanation=@"自駕車需持續與環境互動並根據回饋調整行為策略是強化學習的典型應用。" },
            new() { Id=5164, ChapterId=1303, Type="multiple", Difficulty=2, QuestionText=@"「訓練集」在機器學習流程中的主要用途是什麼？", OptionsJson=@"[""A. 評估模型最終表現"", ""B. 用來調整超參數"", ""C. 用來訓練模型學習輸入與輸出的關係"", ""D. 用來儲存預測結果""]", CorrectAnswer="C", Explanation=@"訓練集提供已知資料與標記讓模型在學習階段調整參數以擬合資料。" },
