            new() { Id=5202, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"在模型調整中，「超參數」較可能是以下哪一項？", OptionsJson=@"[""A. 每一筆訓練樣本的標籤值"", ""B. 學習率或正則化係數"", ""C. 模型的單次預測輸出"", ""D. 損失函數的單筆誤差""]", CorrectAnswer="B", Explanation=@"超參數如學習率與正則化係數會直接影響模型訓練行為與性能。" },
            new() { Id=5203, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"關於「正則化」在機器學習中的角色，下列敘述何者最恰當？", OptionsJson=@"[""A. 增加模型複雜度以提高訓練準確率"", ""B. 在損失函數中加入懲罰項以抑制模型複雜度"", ""C. 刪除所有特徵"", ""D. 只在測試階段使用""]", CorrectAnswer="B", Explanation=@"正則化透過懲罰項限制模型複雜度降低過擬合風險。" },
            new() { Id=5204, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"下列哪一個指標最適合用來評估「類別高度不平衡」的分類問題？", OptionsJson=@"[""A. 準確率(Accuracy)"", ""B. 均方誤差(MSE)"", ""C. F1 score"", ""D. 決定係數(R2)""]", CorrectAnswer="C", Explanation=@"F1 score 綜合 Precision 與 Recall在類別不平衡時較具代表性" },
            new() { Id=5205, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"F1 score 是由哪兩個指標組合而成？", OptionsJson=@"[""A. Accuracy 與 Recall"", ""B. Accuracy 與 Precision"", ""C. Precision 與 Recall"", ""D. MSE 與 MAE""]", CorrectAnswer="C", Explanation=@"F1 score 是 Precision 與 Recall 的調和平均。" },
            new() { Id=5206, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"若一個問題的目標是「將顧客區分為幾個行為相似的群組」", OptionsJson=@"[""A. 監督學習中的分類"", ""B. 監督學習中的迴歸"", ""C. 非監督學習中的分群"", ""D. 強化學習中的策略學習""]", CorrectAnswer="C", Explanation=@"該問題著重發現群組結構而非標記預測屬於非監督分群。" },
            new() { Id=5207, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"多層感知器(MLP)相較於單層感知器的主要優勢為何？", OptionsJson=@"[""A. 可以完全避免過擬合"", ""B. 可以處理非線性與複雜模式"", ""C. 不需要任何訓練資料"", ""D. 只需一個神經元即可完成所有任務""]", CorrectAnswer="B", Explanation=@"MLP 透過多層與非線性函數，能進行複雜的模式識別與分類。" },
            new() { Id=5208, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"在選擇機器學習模型時，下列哪一項考量「並非」常見的重要要素？", OptionsJson=@"[""A. 應用場景"", ""B. 資料特徵"", ""C. 計算資源"", ""D. 程式語言風格""]", CorrectAnswer="D", Explanation=@"會考慮應用場景、資料特徵與計算資源，程式語言風格通常不是主要模型考量。" },
            new() { Id=5209, ChapterId=1303, Type="multiple", Difficulty=3, QuestionText=@"若你希望在未標記的高維資料上進行「易於視覺化」的結構探索，以下哪一種方法最合適？", OptionsJson=@"[""A. 邏輯迴歸"", ""B. 決策樹"", ""C. 隨機森林"", ""D. t-SNE 或類似的降維方法""]", CorrectAnswer="D", Explanation=@"t-SNE 是常用的維度縮減方法，可將高維資料嵌入低維空間以利視覺化。" },
            new() { Id=5210, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在博物館的比喻中，下列哪一種描述最符合「鑑別式 AI」的角色？", OptionsJson=@"[""A. 創作全新畫作的畫家"", ""B. 辨識畫作風格的訪客"", ""C. 設計展場動線的策展人"", ""D. 管理門票系統的售票機""]", CorrectAnswer="B", Explanation=@"鑑別式 AI 重點在「辨識與分類」，就像能看出畫作屬於何種風格的訪客；生成式 AI 才是創作新畫作的角色。" },
            new() { Id=5211, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"關於鑑別式 AI 的敘述，哪一項最為正確？", OptionsJson=@"[""A. 專門學習資料分布以生成新樣本"", ""B. 適合用來產生新圖像與音樂"", ""C. 主要目標是進行資料的分類與辨識"", ""D. 只能處理未標記資料""]", CorrectAnswer="C", Explanation=@"鑑別式 AI 注重在類別之間畫出決策邊界，用於分類與辨識；生成資料分布的是生成式模型。" },
            new() { Id=5212, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在鑑別式 AI 的訓練資料中，通常以 X 和 y 表示什麼？", OptionsJson=@"[""A. X 是標籤，y 是特徵"", ""B. X 是輸入特徵，y 是對應標籤"", ""C. X 是隨機雜訊，y 是輸出樣本"", ""D. X 是潛在空間向量，y 是損失值""]", CorrectAnswer="B", Explanation=@"在監督式學習架構中，X 代表輸入特徵，y 代表標記/類別，鑑別式模型透過學習 X 與 y 的關係進行分類。" },
            new() { Id=5213, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"自然語言處理中的「情感分析」（判斷正面或負面）通常屬於哪一種任務？", OptionsJson=@"[""A. 回歸任務"", ""B. 二元分類任務"", ""C. 多標籤分類任務"", ""D. 群聚任務""]", CorrectAnswer="B", Explanation=@"情感分析常見的設定是將文本分為「正面」或「負面」兩類，因此屬於二元分類任務。" },
            new() { Id=5214, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能代表鑑別式模型的限制？", OptionsJson=@"[""A. 無法處理高維度資料"", ""B. 不適合用於生成新資料樣本"", ""C. 無法學習輸入與輸出之間的關係"", ""D. 只能處理影像資料""]", CorrectAnswer="B", Explanation=@"鑑別式模型主要用於分類與判別，並不擅長直接生成新資料樣本；生成式模型才負責建模分布並生成。" },
            new() { Id=5215, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"關於 Q-learning 的說明，下列何者正確？", OptionsJson=@"[""A. 必須先完全知道環境模型才能學習"", ""B. 透過學習狀態–行動價值來最大化獎勵"", ""C. 只適用於監督式學習任務"", ""D. 主要用於生成圖像內容""]", CorrectAnswer="B", Explanation=@"Q-learning 是強化學習演算法，透過估計不同狀態–行動組合的價值（Q 值）來選擇能最大化長期獎勵的行動。" },
            new() { Id=5216, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能描述「生成式 AI」？", OptionsJson=@"[""A. 只負責評估模型效能"", ""B. 專門將資料分群而不需標籤"", ""C. 學習資料分布並生成新內容"", ""D. 只能用於結構化數值資料""]", CorrectAnswer="C", Explanation=@"生成式 AI 的核心是學習訓練資料的機率分布，再據此生成新的文本、影像、音樂等內容。" },
            new() { Id=5217, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"當考題提到「學習資料的整體機率分布並生成新樣本」，最可能指的是哪一類模型？", OptionsJson=@"[""A. 鑑別式模型"", ""B. 生成式模型"", ""C. 強化學習模型"", ""D. 推薦系統模型""]", CorrectAnswer="B", Explanation=@"「學習分布」「生成新樣本」是生成式模型的關鍵描述，不是鑑別式模型的主要目標。" },
            new() { Id=5218, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項是生成式 AI 的典型應用範例？", OptionsJson=@"[""A. 判斷電子郵件是否為垃圾信"", ""B. 預測房價數值"", ""C. 根據文字描述產生圖片"", ""D. 計算模型準確率""]", CorrectAnswer="C", Explanation=@"依照文字提示產生圖像是典型的生成式 AI 任務，例如 DALL·E 2、Midjourney 等。" },
            new() { Id=5219, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"GAN（生成對抗網路）的架構主要由哪兩個子模型組成？", OptionsJson=@"[""A. 編碼器與解碼器"", ""B. 生成器與判別器"", ""C. 特徵提取器與分類器"", ""D. 強化器與回饋器""]", CorrectAnswer="B", Explanation=@"GAN 由生成器負責產生資料，判別器負責區分真實與生成樣本，兩者以對抗方式共同訓練。" },
            new() { Id=5220, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在 GAN 中，生成器的主要目標是什麼？", OptionsJson=@"[""A. 正確分類輸入樣本"", ""B. 計算損失函數的梯度"", ""C. 生成足以欺騙判別器的樣本"", ""D. 降低訓練資料的維度""]", CorrectAnswer="C", Explanation=@"生成器要產生看似真實的資料，使判別器無法區分真實或偽造，藉此提升生成品質。" },
            new() { Id=5221, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"許多圖像生成型 GAN 中，生成器與判別器常使用哪一種神經網路結構？", OptionsJson=@"[""A. 循環神經網路 (RNN)"", ""B. 卷積神經網路 (CNN)"", ""C. 圖神經網路 (GNN)"", ""D. 遞迴神經網路 (RecNN)""]", CorrectAnswer="B", Explanation=@"圖像資料具有空間結構特性，因此常以 CNN 作為 GAN 的生成器與判別器主體。" },
            new() { Id=5222, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在 GAN 的生成過程中，生成器常使用何種輸入來啟動生成？", OptionsJson=@"[""A. 帶標籤的訓練樣本"", ""B. 高斯分布的隨機向量"", ""C. 經過編碼器壓縮的特徵"", ""D. 模型的評估指標""]", CorrectAnswer="B", Explanation=@"GAN 典型做法是從高斯或均勻分布抽樣一個隨機向量作為潛在向量 z，經生成器轉換為樣本。" },
            new() { Id=5223, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"Midjourney 與 Stable Diffusion 等服務多採用哪一類生成式模型？", OptionsJson=@"[""A. GAN"", ""B. 自編碼器"", ""C. 擴散模型"", ""D. 貝氏網路""]", CorrectAnswer="C", Explanation=@"這些圖像生成服務以擴散模型為核心，透過加噪與逐步降噪的反向過程生成高品質圖像。" },
            new() { Id=5224, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"擴散模型在訓練過程中的「正向過程」通常是什麼？", OptionsJson=@"[""A. 從雜訊逐步產生清晰圖像"", ""B. 將資料聚類成多個群組"", ""C. 在資料上逐步加入雜訊"", ""D. 直接最大化分類準確率""]", CorrectAnswer="C", Explanation=@"正向擴散是將原始資料一步步加上雜訊，逆向過程才是學習如何從雜訊還原到資料。" },
            new() { Id=5225, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"與 GAN 相比，下列哪一項通常是擴散模型的優點？", OptionsJson=@"[""A. 完全不需要訓練資料"", ""B. 訓練損失函數較簡單且較穩定"", ""C. 只能生成低解析度圖像"", ""D. 無法用於多模態 AI""]", CorrectAnswer="B", Explanation=@"擴散模型以穩定、相對簡單的目標函數訓練，較不易出現 GAN 的不穩定與模式崩潰問題。" },
            new() { Id=5226, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"Sora 這類「文字到影片」的生成式 AI 模型，通常結合哪些技術？", OptionsJson=@"[""A. GAN 與貝氏網路"", ""B. 擴散模型與 Transformer"", ""C. K-means 與決策樹"", ""D. RNN 與自編碼器""]", CorrectAnswer="B", Explanation=@"Sora 結合擴散模型來生成影片細節，並利用類 GPT 的 Transformer 架構來組織影片整體結構。" },
            new() { Id=5227, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"Transformer 在處理語言資料時，哪一項機制讓它能有效捕捉長距離依賴？", OptionsJson=@"[""A. 池化層"", ""B. 自注意力機制 (Self-Attention)"", ""C. 捲積核"", ""D. 隨機丟棄 (Dropout)""]", CorrectAnswer="B", Explanation=@"自注意力機制能在序列中任意兩位置之間直接建立關聯，不受距離限制，是 Transformer 的核心。" },
            new() { Id=5228, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"相較傳統 RNN，Transformer 在序列處理上的一項重要優勢是什麼？", OptionsJson=@"[""A. 不需要任何參數"", ""B. 只能一次處理一個時間步"", ""C. 能對整個序列進行高度並行化運算"", ""D. 完全不需要訓練資料""]", CorrectAnswer="C", Explanation=@"Transformer 不必逐步傳遞狀態，可對整個序列同時計算注意力，提升訓練效率與效果。" },
            new() { Id=5229, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在模型評估階段，使用「測試資料」的主要目的為何？", OptionsJson=@"[""A. 增加訓練資料量"", ""B. 微調模型參數"", ""C. 評估模型在未見資料上的泛化能力"", ""D. 降低模型推論時間""]", CorrectAnswer="C", Explanation=@"測試資料必須與訓練資料分開，用來客觀衡量模型在新資料上的表現，評估泛化能力。" },
            new() { Id=5230, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"下列哪一項最能精確區分「鑑別式模型」與「生成式模型」的學習目標？", OptionsJson=@"[""A. 鑑別式模型學習資料分布；生成式模型只學習決策邊界"", ""B. 鑑別式模型同時學習分布與邊界；生成式模型只學習標籤"", ""C. 鑑別式模型學習類別決策邊界；生成式模型學習資料機率分布"", ""D. 兩者都只學習輸入到標籤的映射，沒有本質差異""]", CorrectAnswer="C", Explanation=@"鑑別式模型關注類別之間的決策邊界，用於分類；生成式模型則學習整體資料分布，以此生成新樣本。" },
            new() { Id=5231, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在高維度資料情境下，為何鑑別式 AI 常較適合作為分類器？", OptionsJson=@"[""A. 因為高維度資料無法建模機率分布"", ""B. 因為鑑別式模型直接學習類別邊界，可有效利用高維特徵"", ""C. 因為生成式模型不支援高維度輸入"", ""D. 因為鑑別式模型不需要標記資料""]", CorrectAnswer="B", Explanation=@"鑑別式模型可在高維特徵空間中直接尋找能分隔類別的決策邊界，對高維分類問題表現良好。" },
            new() { Id=5232, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"某模型使用標記資料 (X, y) 訓練，以最大化類別判別正確率；另一模型使用未標記 X 來學習資料分布並產生新樣本。下列配對何者較合理？", OptionsJson=@"[""A. 前者為生成式模型，後者為鑑別式模型"", ""B. 前者為鑑別式模型，後者為生成式模型"", ""C. 兩者皆為生成式模型"", ""D. 兩者皆為鑑別式模型""]", CorrectAnswer="B", Explanation=@"利用 (X, y) 最大化分類正確率是典型鑑別式；僅用 X 建模分布並生成新樣本則是生成式。" },
            new() { Id=5233, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"關於 GAN 中判別器的角色，下列敘述何者較完整？", OptionsJson=@"[""A. 只需分辨真實樣本，忽略生成樣本"", ""B. 是單純的回歸模型，預測連續數值"", ""C. 是一個二元分類器，學習區分真實與生成樣本"", ""D. 只負責產生潛在向量供生成器使用""]", CorrectAnswer="C", Explanation=@"GAN 的判別器本質上是二元分類模型，用來判斷輸入是來自真實資料還是生成器。" },
            new() { Id=5234, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"若在 GAN 的訓練過程中，判別器遠強於生成器且長期保持高準確率，最可能發生的現象為何？", OptionsJson=@"[""A. 生成器學得更快，生成品質大幅提昇"", ""B. 訓練會趨於穩定並快速收斂到最優解"", ""C. 生成器梯度變得非常微弱，難以學習"", ""D. GAN 會自動轉為監督式學習""]", CorrectAnswer="C", Explanation=@"當判別器過強時，生成器在大多數樣本上得到接近零的梯度訊號，導致學習困難。" },
            new() { Id=5235, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"擴散模型的「反向過程」(reverse process) 主要在學習什麼能力？", OptionsJson=@"[""A. 如何將乾淨資料轉為純雜訊"", ""B. 如何從隨機噪聲逐步還原為結構化資料"", ""C. 如何計算資料的真實標籤"", ""D. 如何將資料映射到潛在向量""]", CorrectAnswer="B", Explanation=@"正向過程加噪，反向過程則學習從噪聲逐步去噪，恢復出結構化、高品質的樣本。" },
            new() { Id=5236, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"擴散模型相較於傳統 GAN，在多樣性與訓練穩定性上常被視為較佳的原因之一為何？", OptionsJson=@"[""A. 擴散模型完全不需要損失函數"", ""B. 擴散模型不需要反向傳播"", ""C. 擴散模型以逐步降噪方式學習，目標函數相對穩定，較少出現模式崩潰"", ""D. 擴散模型只需極少訓練樣本即可泛化""]", CorrectAnswer="C", Explanation=@"擴散模型採用穩定的降噪目標，多數情況較少出現 GAN 常見的訓練不穩與模式崩潰。" },
            new() { Id=5237, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"關於 Sora 這類文本到影片的生成模型，下列哪一項敘述較貼近其設計精神？", OptionsJson=@"[""A. 以單一 CNN 模型負責影片所有畫面與時間結構"", ""B. 只使用 Transformer，完全不使用生成式結構"", ""C. 結合擴散模型處理畫面細節，並以 Transformer 處理長程時序與結構"", ""D. 完全仰賴強化學習來產生連續影格""]", CorrectAnswer="C", Explanation=@"Sora 類系統結合擴散模型的細節生成能力與 Transformer 的長程結構建模能力，實現文字到影片。" },
            new() { Id=5238, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"下列何者最能體現 Transformer 自注意力機制在圖像任務中的優點？", OptionsJson=@"[""A. 只能關注局部 3x3 區域特徵"", ""B. 必須按照固定掃描順序處理像素"", ""C. 能在圖像各區域之間建立全域關聯，捕捉物件與背景間的關係"", ""D. 無法處理高解析度圖像""]", CorrectAnswer="C", Explanation=@"自注意力可跨越圖像任意區塊建立關聯，有助於理解物件與背景之間的全域上下文。" },
            new() { Id=5239, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在模型評估時，若只關注準確率 (accuracy) 而忽略精準率 (precision) 與召回率 (recall)，在何種情境中最可能產生嚴重誤判？", OptionsJson=@"[""A. 類別分布完全平衡的任務"", ""B. 所有類別錯誤成本皆相同"", ""C. 高度不平衡資料且少數類別極為重要的任務"", ""D. 資料量非常龐且標籤完全正確的任務""]", CorrectAnswer="C", Explanation=@"在不平衡且關鍵少數類別的情境，單看準確率會被多數類別主導，需同時考量精準率與召回率。" },
            new() { Id=5240, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在整合鑑別式AI與生成式AI的系統中，鑑別式模型最主要扮演的角色是？", OptionsJson=@"[""A. 學習資料分布並生成新樣本"", ""B. 判斷輸入屬於哪一類或是否有效"", ""C. 減少模型參數以降低計算量"", ""D. 負責資料前處理與清洗""]", CorrectAnswer="B", Explanation=@"鑑別式AI專注於學習分類邊界，用來判斷輸入的類別或有效性，在整合系統中通常負責評估與選擇生成結果。" },
            new() { Id=5241, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在生成對抗網路（GAN）中，生成器（Generator）的主要任務是？", OptionsJson=@"[""A. 判斷樣本是真實還是偽造"", ""B. 產生接近真實資料分布的新樣本"", ""C. 標記訓練資料中的標籤"", ""D. 對輸入資料進行正規化處理""]", CorrectAnswer="B", Explanation=@"GAN中生成器負責根據噪聲或潛在變數產生新樣本，目標是讓鑑別器難以分辨真偽。" },
            new() { Id=5242, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"以下哪一個情境最適合使用「生成式＋鑑別式」整合方式？", OptionsJson=@"[""A. 僅需對圖片進行二元分類"", ""B. 只需計算數值迴歸預測"", ""C. 希望產生逼真的假資料並同時過濾品質不佳樣本"", ""D. 只做靜態規則比對，不涉及學習""]", CorrectAnswer="C", Explanation=@"當要大量產生新樣本且需要控制品質時，生成式模型負責產生資料，鑑別式模型負責篩選與評估，是典型整合應用。" },
            new() { Id=5243, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在自然語言處理任務中，常見的整合流程是：先用生成模型在大量未標註文本上預訓練，再搭配鑑別模型進行微調。這樣做的主要好處是？", OptionsJson=@"[""A. 完全不需要標註資料"", ""B. 可以同時降低模型大小與運算成本"", ""C. 善用未標註資料學習語言結構，並用少量標註資料提升特定任務表現"", ""D. 避免模型學到任何偏差""]", CorrectAnswer="C", Explanation=@"先用未標註資料預訓練生成模型，再用少量標註資料微調鑑別或任務頭，可兼顧資料效率與效能。" },
            new() { Id=5244, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"若要建立一個系統，自動產生客服回覆內容，再判斷回覆是否符合公司政策並過濾不當回答，較合適的架構是？", OptionsJson=@"[""A. 單一鑑別式模型"", ""B. 單一生成式模型"", ""C. 生成式模型產生回覆，再由鑑別式模型審核是否通過"", ""D. 先用鑑別式模型，通過後再交給人工撰寫""]", CorrectAnswer="C", Explanation=@"生成式模型負責提出候選回覆，鑑別式模型作為政策與安全審核層，是典型生成＋鑑別整合應用。" },
            new() { Id=5245, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"以下哪一種資料組合最有利於同時訓練生成式與鑑別式AI？", OptionsJson=@"[""A. 只有少量、高度結構化的數值資料"", ""B. 大量未標註資料搭配較小但品質高的標註資料集"", ""C. 僅有人工撰寫的規則集合"", ""D. 只保留測試資料，不保留訓練資料""]", CorrectAnswer="B", Explanation=@"生成式模型可利用大量未標註資料學習分布，鑑別式模型則使用較小但精準的標註資料學分類邊界。" },
            new() { Id=5246, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在醫療影像領域，將生成式AI與鑑別式AI結合的主要理由之一是？", OptionsJson=@"[""A. 完全取代醫師的臨床判斷"", ""B. 產生更多合成影像用於擴增資料集，並用鑑別式模型維持診斷準確度"", ""C. 只為了使影像看起來更有藝術感"", ""D. 避免使用任何標註資料""]", CorrectAnswer="B", Explanation=@"生成式模型可產生合成醫療影像擴充資料，鑑別式模型則維持診斷性能與品質控制。" },
            new() { Id=5247, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在整合應用中，若生成式模型品質不佳，最常見的現象是？", OptionsJson=@"[""A. 鑑別式模型訓練資料不足"", ""B. 生成樣本與真實資料分布差異過大，導致下游鑑別式模型表現不穩定"", ""C. 測試資料集無法使用"", ""D. 無法再使用任何未標註資料""]", CorrectAnswer="B", Explanation=@"若生成器產生的樣本與真實分布差異大，可能導致鑑別式模型學到偏差或效果不佳。" },
            new() { Id=5248, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能描述「使用鑑別式模型來輔助生成式模型微調」？", OptionsJson=@"[""A. 利用鑑別式模型產生新的訓練標註"", ""B. 用鑑別式模型的輸出作為回饋，調整生成式模型的產出方向"", ""C. 完全刪除生成式模型，只保留鑑別式模型"", ""D. 讓生成式模型負責標註所有資料""]", CorrectAnswer="B", Explanation=@"鑑別式模型可以評估生成結果好壞，其回饋可用來調整生成式模型，使輸出更符合目標。" },
            new() { Id=5249, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在聊天機器人應用中，下列哪一項屬於「生成＋鑑別」整合策略？", OptionsJson=@"[""A. 只用語言模型直接回覆使用者"", ""B. 使用鑑別式模型判斷使用者意圖後，直接由人工回覆"", ""C. 使用生成式模型產生多個候選回覆，再由鑑別式模型選出最適合的一個"", ""D. 只用關鍵字比對產生固定回應""]", CorrectAnswer="C", Explanation=@"生成模型提供多樣候選回答，鑑別式模型根據安全性、禮貌性或相關性選擇最佳輸出。" },
            new() { Id=5250, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"若希望利用生成式AI產生合成訓練資料，來改善鑑別式模型在少數類別（rare class）上的表現，設計上最需要注意的是？", OptionsJson=@"[""A. 確保所有類別都被刪除"", ""B. 生成樣本必須完全隨機，避免任何模式"", ""C. 合成樣本必須接近真實分布，並避免嚴重偏差"", ""D. 只生成多數類別樣本即可""]", CorrectAnswer="C", Explanation=@"若合成少數類別樣本與真實分布差異過大，反而會讓鑑別式模型學到錯誤模式。" },
            new() { Id=5251, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"以下哪一項是整合生成式與鑑別式AI時常見的評估方式？", OptionsJson=@"[""A. 只看生成式模型的損失函數"", ""B. 只比較訓練時間長短"", ""C. 同時評估生成樣本品質與鑑別式下游任務的準確率"", ""D. 只用人工主觀感受判斷好壞""]", CorrectAnswer="C", Explanation=@"整合系統須兼顧生成品質（逼真度、多樣性）與下游鑑別任務績效。" },
            new() { Id=5252, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在語音合成與辨識系統中，下列哪種架構屬於生成與鑑別的整合？", OptionsJson=@"[""A. 語音辨識模型單獨運作"", ""B. 語音合成模型單獨運作"", ""C. 先用生成式模型合成語音資料，再用鑑別式模型訓練或評估辨識系統"", ""D. 以傳統規則庫判斷語音內容""]", CorrectAnswer="C", Explanation=@"生成式模型可產生語音樣本，擴充數據給鑑別式辨識模型訓練與測試。" },
            new() { Id=5253, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在整合應用場景中，何時較適合優先引入生成式AI？", OptionsJson=@"[""A. 只想提升既有分類模型的推論速度"", ""B. 需要產生新內容或合成資料來擴充訓練集"", ""C. 只做簡單線性回歸即可解決問題"", ""D. 系統僅依靠固定規則即可運作""]", CorrectAnswer="B", Explanation=@"當需要新內容或額外資料時，生成式AI能提供創造與擴增能力，是整合的起點。" },
            new() { Id=5254, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在模型訓練流程中，常見實務作法為：先以生成模型在大規模未標註資料上預訓練，再加上一個小型鑑別式分類頭進行微調。這種做法屬於：", OptionsJson=@"[""A. 僅使用監督式學習"", ""B. 僅使用非監督式學習"", ""C. 結合自監督／非監督預訓練與監督式微調"", ""D. 完全不需要標註資料""]", CorrectAnswer="C", Explanation=@"先在未標註資料上自監督或非監督預訓練，再用標註資料進行監督式微調，是常見整合流程。" },
            new() { Id=5255, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在隱私敏感情境中，為何有時會用生成式模型合成資料，再訓練鑑別式模型？", OptionsJson=@"[""A. 合成資料永遠不包含任何風險"", ""B. 可在降低直接暴露真實資料的情況下，仍讓鑑別式模型學到有效模式"", ""C. 生成資料比真實資料更便宜但完全無風險"", ""D. 可以完全避免任何法律規範""]", CorrectAnswer="B", Explanation=@"合成資料可降低揭露真實個資的風險，同時維持訓練鑑別式模型的能力，但仍需謹慎評估。" },
            new() { Id=5256, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在評估整合系統時，若發現鑑別式模型在真實資料上表現良好，但在生成樣本上表現極差，較合理的推論是？", OptionsJson=@"[""A. 生成樣本品質與真實分布差異過大"", ""B. 鑑別式模型一定過擬合"", ""C. 測試資料被重複使用"", ""D. 說明整合系統表現完美""]", CorrectAnswer="A", Explanation=@"若鑑別式模型在真實資料表現好，卻在生成樣本上失準，通常代表生成樣本分布與真實資料不匹配。" },
            new() { Id=5257, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在推薦系統中，以下哪一種作法體現生成式與鑑別式AI的整合？", OptionsJson=@"[""A. 只用協同過濾做推薦"", ""B. 用生成式模型模擬使用者可能喜歡的新內容，再由鑑別式模型預測點擊或購買機率"", ""C. 只根據時間排序顯示最新內容"", ""D. 完全依賴人工編輯推薦清單""]", CorrectAnswer="B", Explanation=@"生成模型用來創造或模擬候選內容，鑑別式模型預測其被接受的可能性，是推薦系統中的整合應用。" },
            new() { Id=5258, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"在實務系統中，引入鑑別式模型作為生成式模型的「安全閥」主要是為了？", OptionsJson=@"[""A. 縮短訓練時間"", ""B. 增加模型參數量"", ""C. 攔截不當或不符合規範的生成輸出"", ""D. 讓生成模型完全停止工作""]", CorrectAnswer="C", Explanation=@"鑑別式模型可作為審核層，過濾有害、不當或不合規的生成內容，提高系統安全性。" },
            new() { Id=5259, ChapterId=1304, Type="multiple", Difficulty=2, QuestionText=@"總結而言，整合鑑別式AI與生成式AI的最大價值在於？", OptionsJson=@"[""A. 讓系統只依賴單一模型即可"", ""B. 完全避免收集任何資料"", ""C. 同時獲得內容生成能力與嚴謹的品質／安全控制"", ""D. 只用來裝飾系統介面""]", CorrectAnswer="C", Explanation=@"整合方式結合生成的創造力與鑑別的判斷力，兼顧多樣性與可靠性，是現代AI系統的重要方向。" },
            new() { Id=5260, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在半監督式學習情境中，如何善用生成式AI來提升鑑別式模型的效能？", OptionsJson=@"[""A. 只用生成式模型標註所有未標註資料而不再檢查"", ""B. 利用生成式模型建構潛在空間，再在該空間上訓練鑑別式分類器"", ""C. 強迫生成式模型輸出與真實資料完全相同的樣本"", ""D. 僅用生成式模型合成噪聲樣本加入訓練""]", CorrectAnswer="B", Explanation=@"生成模型學到的潛在表示可提供結構化特徵，鑑別模型在此空間中學習分類邊界通常更有效率。" },
            new() { Id=5261, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"下列哪一項最接近「能量型模型（Energy-based Model）」與生成／鑑別整合的觀念？", OptionsJson=@"[""A. 只在輸入空間上定義一個標準常態分布"", ""B. 為每個樣本定義一個能量函數，低能量對應合理樣本，再以鑑別式準則學習能量差異"", ""C. 只在標籤空間中建立隨機猜測分布"", ""D. 只透過手工規則定義分類邊界""]", CorrectAnswer="B", Explanation=@"能量型模型同時可以視為生成模型（建構分布）與鑑別模型（區分高低能量），天然具備整合特性。" },
            new() { Id=5262, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在GAN訓練過程中，若鑑別器遠強於生成器且收斂很快，下列何種情況最可能發生？", OptionsJson=@"[""A. 生成器學得更好，樣本多樣性變高"", ""B. 鑑別器無法分辨真偽，損失接近隨機"", ""C. 生成器梯度幾乎為零，導致訓練停滯或崩潰"", ""D. 兩者都同時快速提升且沒有問題""]", CorrectAnswer="C", Explanation=@"當鑑別器過強時，生成器得到的梯度訊號接近零，難以更新參數，訓練易陷入停滯。" },
            new() { Id=5263, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在文字生成任務中引入「強化學習自人類回饋（RLHF）」時，鑑別式成分多半扮演什麼角色？", OptionsJson=@"[""A. 作為隨機噪聲來源"", ""B. 作為回饋函數或獎勵模型，評估生成文字品質"", ""C. 負責取代語言模型本身"", ""D. 只用來產生更多訓練樣本""]", CorrectAnswer="B", Explanation=@"在RLHF中，獎勵或偏好模型通常可視為鑑別器，根據人類偏好評分生成結果，引導生成模型更新。" },
            new() { Id=5264, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"若希望降低生成式模型產生帶有敏感個資的內容，下列何種作法最符合「生成＋鑑別」的防護思維？", OptionsJson=@"[""A. 只在訓練前移除所有真實資料"", ""B. 在推論階段之前，使用專門偵測個資洩漏的鑑別模型過濾生成輸出"", ""C. 讓生成模型自行學會不輸出任何字串"", ""D. 完全停止使用生成模型""]", CorrectAnswer="B", Explanation=@"額外的鑑別模型可偵測與封鎖含個資或敏感資訊的輸出，是常見安全架構。" },
            new() { Id=5265, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在使用生成式模型進行資料擴增時，下列哪一項指標最能直接反映其對鑑別式模型泛化能力的幫助？", OptionsJson=@"[""A. 生成樣本的檔案大小"", ""B. 生成樣本與真實樣本的平均位元組長度差異"", ""C. 加入生成樣本後，鑑別式模型在獨立真實測試集上的表現變化"", ""D. 訓練過程所使用的GPU數量""]", CorrectAnswer="C", Explanation=@"最終關鍵在於下游鑑別式模型在真實資料上的泛化表現是否提升。" },
            new() { Id=5266, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"若一個結合生成與鑑別的系統在訓練時使用合成資料與真實資料比例嚴重失衡，下列何者最可能成為風險？", OptionsJson=@"[""A. 模型一定更穩定，因為資料量變大"", ""B. 模型只會記住真實資料，不受合成資料影響"", ""C. 鑑別式模型可能過度依賴合成分布，導致在真實世界資料上表現不佳"", ""D. 訓練時間必然縮短""]", CorrectAnswer="C", Explanation=@"若合成資料比例過高且分布有偏，鑑別式模型可能學到偏離真實世界的模式。" },
            new() { Id=5267, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在多模態系統中，若以生成式模型同時生成圖像與說明文字，再用鑑別式模型評估兩者的一致性，此鑑別式模型的主要學習目標是？", OptionsJson=@"[""A. 僅判斷圖像是否清晰"", ""B. 判斷文字是否符合語法規則"", ""C. 判斷圖文是否語意對齊與相互一致"", ""D. 只計算圖像檔案大小是否合格""]", CorrectAnswer="C", Explanation=@"多模態鑑別器關注的是圖像內容與描述文字的語意對齊程度。" },
            new() { Id=5268, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在模型監控階段，若發現生成式模型輸出分布隨時間漂移（distribution shift），下列哪一種結合鑑別式模型的策略較為合理？", OptionsJson=@"[""A. 忽略漂移，只要系統仍能運作即可"", ""B. 使用鑑別式模型偵測輸出是否偏離歷史分布，觸發再訓練或人工審查流程"", ""C. 完全停止紀錄任何輸出"", ""D. 只增加生成模型的溫度參數""]", CorrectAnswer="B", Explanation=@"鑑別式偵測器可視為監控器，當發現輸出分布異常時啟動警示與調整流程。" },
            new() { Id=5269, ChapterId=1304, Type="multiple", Difficulty=3, QuestionText=@"在設計考試題目以評量「鑑別式AI與生成式AI的整合應用」時，下列哪一種題型最能同時考到概念理解與情境判斷？", OptionsJson=@"[""A. 單純背誦定義的是非題"", ""B. 只問數學公式推導"", ""C. 給定實務案例，要求選出最適合的生成＋鑑別架構或流程"", ""D. 只問模型參數精確數值""]", CorrectAnswer="C", Explanation=@"情境題可同時檢驗考生對整合架構、適用情境與風險考量的理解。" },
            new() { Id=5270, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"關於 Low-code 平台的描述，下列何者最正確？", OptionsJson=@"[""A. 完全禁止撰寫任何程式碼，只能使用範本"", ""B. 在視覺化工具基礎上，仍可加入自訂程式碼"", ""C. 必須以純文字程式碼編輯器進行開發"", ""D. 僅能用於原始系統維護，無法開發新功能""]", CorrectAnswer="B", Explanation=@"Low-code 在視覺化工具上仍可加入程式碼，兼具速度與彈性。" },
            new() { Id=5271, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"關於 No-code 平台的主要特徵，下列何者正確？", OptionsJson=@"[""A. 完全仰賴手寫程式碼"", ""B. 允許非技術使用者在不寫程式碼的情況下建立應用"", ""C. 僅能由資深工程師操作"", ""D. 必須自行設計與維護所有基礎架構""]", CorrectAnswer="B", Explanation=@"No-code 讓非技術使用者不寫程式碼也能建立應用。" },
            new() { Id=5272, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能描述 Low-code 與 No-code 之間的主要差異？", OptionsJson=@"[""A. Low-code 比 No-code 更難維護但更便宜"", ""B. Low-code 允許一定程度編碼與客製，No-code 幾乎不需寫程式"", ""C. No-code 僅支援行動裝置，Low-code 僅支援網頁"", ""D. Low-code 與 No-code 在技術能力需求上完全相同""]", CorrectAnswer="B", Explanation=@"關鍵差異在於可客製化與是否需撰寫程式碼。" },
            new() { Id=5273, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"企業採用 Low-code 平台的主要直接效益通常是什麼？", OptionsJson=@"[""A. 延長開發時程，以換取更高品質"", ""B. 縮短開發時間並降低開發成本"", ""C. 完全消除對任何技術人員的需求"", ""D. 僅改善硬體效能，與開發效率無關""]", CorrectAnswer="B", Explanation=@"Low-code 透過視覺化與預建組件加速開發並降低成本。" },
            new() { Id=5274, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台常見的開發介面與操作方式為何？", OptionsJson=@"[""A. 命令列文字指令與批次檔"", ""B. 拖放式元件與圖形化流程設計"", ""C. 純終端機介面與組合語言"", ""D. 僅能透過 API 腳本進行設定""]", CorrectAnswer="B", Explanation=@"LCNC 核心是視覺化拖放與流程設計介面。" },
            new() { Id=5275, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"No-code 平台最主要是解決什麼問題？", OptionsJson=@"[""A. 提升演算法精準度"", ""B. 讓沒有程式背景的人也能建立簡單應用"", ""C. 強化底層網路協定安全性"", ""D. 自動產生大型資料湖架構""]", CorrectAnswer="B", Explanation=@"No-code 降低開發門檻，讓非技術使用者也能開發。" },
            new() { Id=5276, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列何者不是 LCNC 平台常見的優點？", OptionsJson=@"[""A. 縮短開發時間"", ""B. 降低技術門檻"", ""C. 完全消除所有資安風險"", ""D. 降低對專業工程師的依賴""]", CorrectAnswer="C", Explanation=@"LCNC 並不會自動消除資安風險，安全仍需管理。" },
            new() { Id=5277, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"公民開發者（Citizen Developer）最可能使用哪一類平台？", OptionsJson=@"[""A. 僅限資深系統工程師"", ""B. 財務審計人員"", ""C. 業務或流程專家等非技術人員"", ""D. 資料中心機房維運工程師""]", CorrectAnswer="C", Explanation=@"公民開發者多為業務與流程專家，使用 LCNC 平台開發。" },
            new() { Id=5278, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台對 IT 團隊最大的幫助通常是什麼？", OptionsJson=@"[""A. 讓 IT 團隊必須手動撰寫更多基礎程式碼"", ""B. 釋放部分例行開發工作，專注於高價值專案"", ""C. 完全取代 IT 團隊的所有職能"", ""D. 迫使 IT 團隊轉為只做硬體維護""]", CorrectAnswer="B", Explanation=@"例行開發由 LCNC 分擔，IT 能專注在較複雜與高價值工作。" },
            new() { Id=5279, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最可能是導入 No-code 平台時需要事先評估的議題？", OptionsJson=@"[""A. 伺服器機房的溫度與耗電"", ""B. 使用者介面配色是否符合品牌識別"", ""C. 未來若轉移到其他平台的難度與成本"", ""D. 開發團隊是否精通三種以上程式語言""]", CorrectAnswer="C", Explanation=@"需評估未來平台轉移的困難度與可能成本（Vendor lock-in）。" },
            new() { Id=5280, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"關於 LCNC 平台與數位轉型的關係，下列何者較為合理？", OptionsJson=@"[""A. LCNC 與數位轉型無直接關聯"", ""B. LCNC 僅適用於完成轉型後的維護階段"", ""C. LCNC 可加速原型開發與創新，有助數位轉型落地"", ""D. LCNC 只會增加轉型複雜度，應盡量避免使用""]", CorrectAnswer="C", Explanation=@"LCNC 可加速原型與創新，是落實數位轉型的工具之一。" },
            new() { Id=5281, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列何者最符合 Low-code 平台的典型使用情境？", OptionsJson=@"[""A. 需要長期、大量底層演算法最佳化"", ""B. 需要快速實作內部表單與流程自動化"", ""C. 需要開發作業系統核心功能"", ""D. 需要設計高效能即時通訊協定""]", CorrectAnswer="B", Explanation=@"Low-code 適合快速建立內部流程與表單類應用。" },
            new() { Id=5282, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"關於 No-code 平台的客製化能力，下列敘述何者較為恰當？", OptionsJson=@"[""A. 完全等同於傳統全客製化系統"", ""B. 在高度客製需求下可能受平台預設結構限制"", ""C. 一定可以自由修改所有底層程式碼"", ""D. 無法因應任何業務需求變更""]", CorrectAnswer="B", Explanation=@"No-code 在高度客製情境較易受平台預設結構限制。" },
            new() { Id=5283, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台常被認為能「民主化軟體開發」，其意涵為何？", OptionsJson=@"[""A. 只有工程師能開發應用程式"", ""B. 任何開發都必須透過外包完成"", ""C. 讓更多非技術人員也能參與應用開發"", ""D. 禁止業務人員接觸系統設定""]", CorrectAnswer="C", Explanation=@"民主化意指擴大參與者，讓非技術人員也能開發應用。" },
            new() { Id=5284, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能代表 LCNC 平台的技術門檻特徵？", OptionsJson=@"[""A. 需要非常深厚的系統程式設計知識"", ""B. 完全不需要理解任何業務流程"", ""C. 技術門檻較傳統開發低，支援非技術人員參與"", ""D. 必須精通多種程式語言才能上手""]", CorrectAnswer="C", Explanation=@"LCNC 降低技術門檻，讓更多人能參與系統開發。" },
            new() { Id=5285, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列何者最可能是使用 No-code 平台開發應用的使用者角色？", OptionsJson=@"[""A. 專職資料中心網路工程師"", ""B. 具備深度演算法能力的 AI 研究員"", ""C. 需要自助建立流程工具的業務主管"", ""D. 僅限資深資料庫管理員""]", CorrectAnswer="C", Explanation=@"No-code 目標族群是需要自助開發的業務與流程負責人。" },
            new() { Id=5286, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"在考量 LCNC 平台導入時，下列何者屬於風險面向的問題？", OptionsJson=@"[""A. 平台供應商是否可能停止維護與支援"", ""B. 螢幕大小是否符合行動裝置標準"", ""C. 鍵盤排列是否符合國家標準"", ""D. 是否強制改用開源作業系統""]", CorrectAnswer="A", Explanation=@"需評估供應商穩定度與是否可能停止支援（Vendor lock-in 相關）。" },
            new() { Id=5287, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"關於 LCNC 平台的程式碼產生方式，下列何者正確？", OptionsJson=@"[""A. 多以拖放與視覺化操作來產生程式碼"", ""B. 完全不會產生任何程式碼"", ""C. 僅能由人工逐行輸入指令碼"", ""D. 必須由編譯器手動轉成機器碼""]", CorrectAnswer="A", Explanation=@"LCNC 透過視覺化操作自動產生程式碼。" },
            new() { Id=5288, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台最適合用於哪一種專案管理與開發模式？", OptionsJson=@"[""A. 完全瀑布式開發，禁止變更需求"", ""B. 強調一次性設計，避免迭代"", ""C. 支援敏捷與快速迭代的開發方式"", ""D. 僅適用於多年期的大型建置案""]", CorrectAnswer="C", Explanation=@"LCNC 適合搭配敏捷、短週期迭代與快速原型。" },
            new() { Id=5289, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"當考題提到「拖放元件、視覺化流程、幾乎不寫程式」，最有可能指的是？", OptionsJson=@"[""A. 傳統嵌入式系統開發"", ""B. Low-code / No-code 類型平台的應用開發"", ""C. 僅限大型主機 COBOL 系統維護"", ""D. 高階晶片設計流程""]", CorrectAnswer="B", Explanation=@"關鍵字明顯對應 LCNC 平台的典型特徵。" },
            new() { Id=5290, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"關於 Low-code 平台在客製化與維護性之間的平衡，下列敘述何者最恰當？", OptionsJson=@"[""A. 完全依賴視覺化配置，長期維護必然最輕鬆"", ""B. 允許部分自訂程式碼，但可能增加平台升級與維護複雜度"", ""C. 禁止任何自訂程式碼，因此維護成本趨近於零"", ""D. 所有邏輯皆交由外包，內部維護負擔一定較低""]", CorrectAnswer="B", Explanation=@"自訂程式碼帶來彈性，也會增加升級與維護的複雜度。" },
            new() { Id=5291, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"企業大量採用單一 LCNC 平台時，最需要關注的長期風險為何？", OptionsJson=@"[""A. 無法再使用任何傳統開發工具"", ""B. 平台供應商中止服務時，系統移轉困難與資安風險"", ""C. 程式碼過於透明，導致商業機密外洩"", ""D. 員工須全部改為遠端工作""]", CorrectAnswer="B", Explanation=@"高度依賴單一平台會產生 Vendor lock-in 與安全維護風險。" },
            new() { Id=5292, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"下列何者最能說明 LCNC 平台對「開發流程角色分工」的影響？", OptionsJson=@"[""A. 強化傳統開發人員對架構決策的獨占權"", ""B. 讓更多業務與領域專家能直接參與設計與實作"", ""C. 完全取消測試與上線流程，加快交付速度"", ""D. 只允許外包團隊接觸開發環境""]", CorrectAnswer="B", Explanation=@"LCNC 讓業務與領域專家在開發流程中扮演更積極的角色。" },
            new() { Id=5293, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"在安全性管理面向，下列哪一個特徵最容易成為 LCNC 平台的弱點？", OptionsJson=@"[""A. 運行方式過度透明，導致駭客容易逆向工程"", ""B. 平台運行機制相對不透明，難以進行弱點掃描與稽核"", ""C. 所有程式碼都以開源方式釋出"", ""D. 只能部署在本機，無法使用雲端防護""]", CorrectAnswer="B", Explanation=@"黑盒特性使弱點掃描與稽核較為困難。" },
            new() { Id=5294, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"若考題提到「避免硬編碼業務邏輯」作為設計原則，最可能的原因是什麼？", OptionsJson=@"[""A. 確保所有流程無法被修改，維持最高穩定性"", ""B. 保留彈性以因應未來業務需求變化與平台升級"", ""C. 讓平台供應商可以完全控制客戶流程"", ""D. 避免任何形式的自動化設定""]", CorrectAnswer="B", Explanation=@"避免硬編碼可以保留彈性，利於未來調整與升級。" },
            new() { Id=5295, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"下列哪一種情境最容易凸顯 No-code 平台在彈性上的限制？", OptionsJson=@"[""A. 需要持續調整複雜核價演算法的金融交易系統"", ""B. 快速建立固定格式的內部申請單並偶爾調整欄位"", ""C. 建立一次性活動報名表單，不需與其他系統串接"", ""D. 建立靜態公司簡介網頁，幾乎不更動內容""]", CorrectAnswer="A", Explanation=@"高度複雜且常變更的演算法需求較不適合 No-code。" },
            new() { Id=5296, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"關於 LCNC 與敏捷開發實務整合，下列何者較合理？", OptionsJson=@"[""A. LCNC 與敏捷開發衝突，不宜同時採用"", ""B. LCNC 可輔助快速建立可運作原型，支持短週期迭代"", ""C. 敏捷開發要求所有程式碼必須手寫，故無法搭配 LCNC"", ""D. 只要使用 LCNC，就不需要任何敏捷實務""]", CorrectAnswer="B", Explanation=@"LCNC 能加速原型製作，與敏捷短週期迭代相輔相成。" },
            new() { Id=5297, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"導入 LCNC 平台時，對架構師能力的要求為何？", OptionsJson=@"[""A. 只需熟悉單一程式語言即可，不必理解業務"", ""B. 需能抽象化與泛化業務需求，設計可配置的通用模型"", ""C. 只要會操作拖放介面即可，無須任何架構思維"", ""D. 主要負責硬體採購與網路布建""]", CorrectAnswer="B", Explanation=@"架構師需將多元需求抽象成可重用、可配置的模型。" },
            new() { Id=5298, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"在治理（Governance）觀點，下列何者是大規模導入公民開發時需要特別建立的機制？", OptionsJson=@"[""A. 取消所有存取權限控管以提高開發速度"", ""B. 建立權限、審核與版控流程，管理公民開發成果"", ""C. 禁止記錄任何變更紀錄，以保護隱私"", ""D. 完全放任各部門各自為政，以促進創新""]", CorrectAnswer="B", Explanation=@"須有清楚的權限、審核與版控機制來管理公民開發。" },
            new() { Id=5299, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"有關 LCNC 平台生成程式碼的「可見度」與「可控性」，下列敘述何者最適切？", OptionsJson=@"[""A. 所有自動產生的程式碼都完全不可檢視"", ""B. 程式碼結構通常較抽象，需透過平台工具輔助理解與控制"", ""C. 所有程式碼必須由開發者手動撰寫與維護"", ""D. LCNC 平台不會產生任何執行程式碼，只產生文件""]", CorrectAnswer="B", Explanation=@"程式碼可見度有限，通常需透過平台工具來檢視與調整。" },
            new() { Id=5300, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台在降低開發成本上的主要作法為何？", OptionsJson=@"[""A. 使用視覺化介面與預配置模板，減少手寫程式碼"", ""B. 強制所有開發人員加班以縮短開發時間"", ""C. 完全外包開發給第三方廠商"", ""D. 只允許高階工程師撰寫程式碼""]", CorrectAnswer="A", Explanation=@"LCNC 透過視覺化介面與預配置模板來降低編碼需求並節省成本。" },
            new() { Id=5301, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台特別適合用來達成下列哪一項目標？", OptionsJson=@"[""A. 完全取代專業軟體工程師"", ""B. 讓非技術人員也能建置應用程式"", ""C. 避免任何系統整合需求"", ""D. 禁止業務單位參與系統設計""]", CorrectAnswer="B", Explanation=@"LCNC 的核心價值之一是降低技術門檻，讓非技術人員可參與開發。" },
            new() { Id=5302, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"關於 LCNC 對流程自動化的描述，下列何者正確？", OptionsJson=@"[""A. 僅能在單一資料庫上建立手動流程"", ""B. 無法與現有系統整合"", ""C. 可設計自動化工作流程並與多種系統、資料來源整合"", ""D. 僅能用於前端畫面設計，不支援流程""]", CorrectAnswer="C", Explanation=@"LCNC 能設計自動化流程並與多種系統與資料來源無縫整合。" },
            new() { Id=5303, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台有助於企業快速回應不斷變化的業務需求，主要原因是什麼？", OptionsJson=@"[""A. 所有程式碼皆寫死，不可修改"", ""B. 每次需求變更都必須重建新系統"", ""C. 只允許年度一次的版本更新"", ""D. 可在少量程式變更下修改與擴展應用程式""]", CorrectAnswer="D", Explanation=@"LCNC 提供靈活性，可在不大量編碼情況下調整與擴展應用。" },
            new() { Id=5304, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台如何降低技術門檻？", OptionsJson=@"[""A. 提供簡單的視覺化使用者介面與拖放方式"", ""B. 要求所有使用者學習多門程式語言"", ""C. 只提供命令列編輯介面"", ""D. 完全不提供任何圖形功能""]", CorrectAnswer="A", Explanation=@"簡單視覺化 UI 讓非技術人員也能參與開發。" },
            new() { Id=5305, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台對原型設計的主要貢獻是什麼？", OptionsJson=@"[""A. 只適合在專案結束時建立原型"", ""B. 允許快速建立原型以收集使用者回饋"", ""C. 不支援原型設計"", ""D. 原型建立一定比傳統開發更慢""]", CorrectAnswer="B", Explanation=@"LCNC 能快速建原型，幫助收集回饋並加快開發週期。" },
            new() { Id=5306, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"LCNC 平台對企業創新週期的影響為何？", OptionsJson=@"[""A. 因流程僵化而延長創新時間"", ""B. 必須等待 IT 部門排程，反而減慢創新"", ""C. 透過直覺拖放介面，加速新應用原型設計與測試"", ""D. 僅限於維護既有系統，無法創新""]", CorrectAnswer="C", Explanation=@"LCNC 簡化開發流程，讓非技術使用者更快進行原型與測試，加速創新。" },
            new() { Id=5307, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"下列何者為 LCNC 平台在安全性上的一項風險？", OptionsJson=@"[""A. 過度開放導致所有人都能修改程式碼"", ""B. 無法與任何資料來源連線"", ""C. 一定無法通過任何稽核"", ""D. 封閉開發方式使程式碼審查與安全測試困難""]", CorrectAnswer="D", Explanation=@"封閉開發方式會使程式碼審查與安全測試更困難，帶來潛在漏洞。" },
            new() { Id=5308, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"企業同時使用多個 LCNC 工具時，最可能出現哪種問題？", OptionsJson=@"[""A. 難以統一權限管理與安全政策"", ""B. 各工具自動整合，毫無風險"", ""C. 無法建立任何自動化流程"", ""D. 所有系統都必須使用相同帳號密碼""]", CorrectAnswer="A", Explanation=@"多個 LCNC 工具併用時，統一權限管理與安全政策會變得困難。" },
            new() { Id=5309, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"「供應商鎖定」在 LCNC 情境下最可能是哪種情況？", OptionsJson=@"[""A. 平台允許隨時零成本轉換到任何其他平台"", ""B. 一旦大量採用某 LCNC 平台，轉換到其他平台非常困難"", ""C. 企業可同時使用所有平台而沒有任何限制"", ""D. 使用者無法在平台上開發任何應用""]", CorrectAnswer="B", Explanation=@"LCNC 可能導致供應商鎖定，使平台轉換變得困難且成本高。" },
            new() { Id=5310, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"由於 LCNC 平台的封閉特性，哪一項是可能產生的後果？", OptionsJson=@"[""A. 所有程式碼都開放，任何人都可修改"", ""B. 完全不需要維護"", ""C. 程式碼審查與安全測試受限，維護難度增加"", ""D. 可避免一切安全風險""]", CorrectAnswer="C", Explanation=@"封閉開發方式會限制程式碼審查與安全測試，導致維護困難。" },
            new() { Id=5311, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"生成式 AI 能協助開發者專注於複雜問題的原因是什麼？", OptionsJson=@"[""A. 禁止開發者進行任何手動編碼"", ""B. 只能用來寫文件，無法寫程式碼"", ""C. 強迫開發者撰寫更多低階程式碼"", ""D. 可自動化常規開發工作，釋放開發者時間""]", CorrectAnswer="D", Explanation=@"生成式 AI 可自動化常規開發工作，使開發者專注高階問題與創新。" },
            new() { Id=5312, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"生成式 AI 對編碼門檻的影響為何？", OptionsJson=@"[""A. 自動生成大部分程式碼，讓非技術人員也能參與開發"", ""B. 使程式語言學習變得更困難"", ""C. 要求使用者手動撰寫所有程式碼"", ""D. 只支援專業工程師使用""]", CorrectAnswer="A", Explanation=@"生成式 AI 自動生成大部分程式碼，降低開發門檻。" },
            new() { Id=5313, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"若企業不想從頭構建 AI 模型，較適合的選擇為何？", OptionsJson=@"[""A. 自行建立深度學習模型"", ""B. 採用嵌入生成式 AI 的 LCNC 平台"", ""C. 僅使用試算表與手動規則"", ""D. 完全不使用任何 AI""]", CorrectAnswer="B", Explanation=@"此情境建議選擇 LCNC 嵌入生成式 AI 平台，以節省時間與資源。" },
            new() { Id=5314, ChapterId=1305, Type="multiple", Difficulty=2, QuestionText=@"當企業需要針對特定任務開發自訂 AI 模型時，最適合使用哪種工具？", OptionsJson=@"[""A. 只用內建範本，不做任何調整"", ""B. 僅依賴人工決策，不使用任何工具"", ""C. 使用 LCNC AI 工具建構、訓練與部署模型"", ""D. 只能改用傳統手寫程式方式開發""]", CorrectAnswer="C", Explanation=@"LCNC AI 工具提供建構、訓練與部署自訂 AI 模型的低程式碼／無程式碼環境。" },
            new() { Id=5315, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"為何許多生成式 AI 模型常被視為「黑盒」？", OptionsJson=@"[""A. 因為模型完全不需要任何資料"", ""B. 因為所有計算都由人類手動完成"", ""C. 因為模型只能執行簡單線性運算"", ""D. 其決策過程難以解釋且不透明""]", CorrectAnswer="D", Explanation=@"多數基於深度學習的生成式模型，其內部權重與決策邏輯不易被人理解，因此被稱為黑盒。" },
            new() { Id=5316, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"為何必須檢查生成式 AI 所產生程式碼的準確性與偏見？", OptionsJson=@"[""A. 因其推理過程不透明，輸出可能帶有錯誤或偏見"", ""B. 因為 AI 產生的程式碼一定完全正確"", ""C. 法律全面禁止使用 AI 程式碼"", ""D. 因為 AI 完全無法處理任何資料""]", CorrectAnswer="A", Explanation=@"決策與資料來源難以完全追踪，若不檢查，可能引入錯誤、偏見或不合規的內容。" },
            new() { Id=5317, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"在測試與故障排除中，對 AI 的角色何者為適當看法？", OptionsJson=@"[""A. AI 可以完全取代所有測試工程師"", ""B. AI 可協助快速找出問題，但仍需人類檢查與驗證"", ""C. AI 完全無法協助任何測試工作"", ""D. 只要 AI 判定測試通過就可略過一切人工檢查""]", CorrectAnswer="B", Explanation=@"AI 能加速錯誤偵測與分析，但生成或建議的修正仍可能有誤，需要人工確認。" },
            new() { Id=5318, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"關於提示（Prompt）品質與 AI 生成程式碼品質的關係，下列何者正確？", OptionsJson=@"[""A. 提示品質與程式碼品質毫無關係"", ""B. 提示愈清楚、具體，產生的程式碼愈可能符合需求"", ""C. 輸入任何隨機文字結果都一樣好"", ""D. AI 可自行推斷所有需求，不需要提示""]", CorrectAnswer="C", Explanation=@"生成式 AI 對輸入提示高度敏感，需具體說明需求才能得到較符合預期的輸出。" },
            new() { Id=5319, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"LCNC 平台與生成式 AI 的關係，下列敘述何者最為適當？", OptionsJson=@"[""A. 兩者互斥，無法同時使用"", ""B. 生成式 AI 將完全取代 LCNC 平台"", ""C. LCNC 將完全取代所有 AI 模型"", ""D. 兩者互補：LCNC 降低開發門檻，AI 強化自動化與生成能力""]", CorrectAnswer="D", Explanation=@"教材強調兩者在技術定位不同但互補，可共同提升開發效率與易用性。" },
            new() { Id=5320, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"技術或產品領袖在導入「生成式 AI＋LCNC 解決方案」時，首要考量為何？", OptionsJson=@"[""A. 如何整合以提升產品功能與使用效率"", ""B. 如何全面禁止團隊使用任何 AI"", ""C. 只關注單一工具授權費用，忽略流程"", ""D. 假設不需要任何治理與監控""]", CorrectAnswer="A", Explanation=@"關鍵在於策略性整合，讓產品更好用、更高效，同時納入治理與風險控管。" },
            new() { Id=5321, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"關於 Create ML 在 AI 平台中的定位，下列何者正確？", OptionsJson=@"[""A. 只適用於 Windows 伺服器端開發"", ""B. 完全不支援任何機器學習功能"", ""C. 是為 Apple/macOS 開發者設計的機器學習平台"", ""D. 僅為單純的資料庫管理工具""]", CorrectAnswer="C", Explanation=@"Create ML 針對 Apple 生態系設計，協助開發者較容易建構與訓練 ML 模型。" },
            new() { Id=5322, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"AI 在應用程式開發中如何縮短產品上市時間（Time-to-market）？", OptionsJson=@"[""A. 要求增加更多人工測試步驟"", ""B. 刻意限制功能以延長開發時間"", ""C. 自動化程式碼生成、錯誤檢查與測試等例行任務"", ""D. 只產生文件而不產生程式碼""]", CorrectAnswer="C", Explanation=@"自動化重複性工作可減少人工投入與迭代時間，使產品更快上市。" },
            new() { Id=5323, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"AI 如何提升低程式碼平台所建應用的可擴展性？", OptionsJson=@"[""A. 禁止任何系統調整以維持穩定"", ""B. 只允許固定流程，不支援擴充"", ""C. 分析使用者行為，使應用能動態調整邏輯並提供個人化"", ""D. 強迫所有使用者使用完全相同設定""]", CorrectAnswer="C", Explanation=@"透過行為分析與動態調整，系統能隨需求變化擴展並個人化。" },
            new() { Id=5324, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"哪一項指標最適合用來評估 AI 開發工具在團隊中的採用程度？", OptionsJson=@"[""A. 開發者對 AI 工具的使用頻率與依賴程度"", ""B. 辦公室座位數量"", ""C. 公司 Logo 的顏色"", ""D. 員工午餐選項""]", CorrectAnswer="A", Explanation=@"使用頻率與依賴度直接反映工具在實際開發流程中的重要性。" },
            new() { Id=5325, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"在將生成式 AI 與 LCNC 結合時，下列何者是關鍵治理考量？", OptionsJson=@"[""A. 如何整合以提升產品功能與使用效率"", ""B. 最大化模型不透明度並隱藏所有紀錄"", ""C. 完全移除所有人工監督"", ""D. 忽略所有相關法規要求""]", CorrectAnswer="B", Explanation=@"必須建立治理機制控管權限、稽核與風險，以落實 Responsible AI。" },
            new() { Id=5326, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"為何 LCNC 平台可能增加長期維護風險與技術債？", OptionsJson=@"[""A. 因封閉實作使程式碼審查與系統轉移更為困難"", ""B. 因為平台永遠開放原始碼給所有人"", ""C. 因為系統永不變更所以不需維護"", ""D. 因為可完全避免所有安全問題""]", CorrectAnswer="A", Explanation=@"黑盒與專屬實作使得維護、除錯與移轉到其他環境的成本與風險提高。" },
            new() { Id=5327, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"下列何者最能說明「LCNC 供應商鎖定」的情境？", OptionsJson=@"[""A. 團隊可零成本隨時更換工具"", ""B. 所有平台天生完全可互換"", ""C. 開發人員被禁止在平台上建任何應用"", ""D. 高度依賴單一 LCNC 廠商，導致轉換到其他平台成本極高""]", CorrectAnswer="D", Explanation=@"大量採用某平台後，切換將面臨高額重建與整合成本，即為供應商鎖定。" },
            new() { Id=5328, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"為何將生成式 AI 直接嵌入既有 LCNC 工作流程有助於導入？", OptionsJson=@"[""A. 使用者可在熟悉流程中使用 AI，降低學習門檻與變革阻力"", ""B. 使用者必須完全放棄原有工具與流程"", ""C. 所有既有工作流程都必須廢棄重建"", ""D. AI 只能在獨立且無人使用的環境中執行""]", CorrectAnswer="A", Explanation=@"在既有流程中添加能力，而非強迫大幅改變流程，可加速實際採用。" },
            new() { Id=5329, ChapterId=1305, Type="multiple", Difficulty=3, QuestionText=@"為何說 LCNC 有助於「民主化軟體開發」？", OptionsJson=@"[""A. 只允許資深工程師開發系統"", ""B. 要求所有使用者具備資工相關學位"", ""C. 禁止非技術人員接觸系統"", ""D. 讓沒有正式程式訓練的使用者也能建構可用應用程式""]", CorrectAnswer="D", Explanation=@"LCNC 讓更多非工程背景的角色也能參與開發，擴大創新來源。" },
            new() { Id=5330, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"生成式AI與一般機器學習方法相比，最關鍵的差異是什麼？", OptionsJson=@"[""A. 能建立原創且類似人類創作的新內容"", ""B. 能處理結構化資料"", ""C. 主要用於分類與回歸任務"", ""D. 完全不需要任何訓練資料""]", CorrectAnswer="A", Explanation=@"一般機器學習多著重於分類與預測，而生成式AI可以根據學到的資料模式主動創造新內容，例如文字、圖像或音訊。" },
            new() { Id=5331, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在互動體驗中，生成式AI被特別看重的主要能力是什麼？", OptionsJson=@"[""A. 只提供靜態文字說明文件"", ""B. 產生即時對話與自適應故事情節，讓內容更豐富、動態"", ""C. 只能產生預先寫好的固定回應"", ""D. 僅用於加密遊戲帳號資料""]", CorrectAnswer="B", Explanation=@"生成式AI可以依玩家或使用者的輸入即時產生對話與故事分支，讓體驗更具沉浸感與變化性。" },
            new() { Id=5332, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在媒體與娛樂產業中，生成式AI幫助業者維持競爭力的關鍵原因是什麼？", OptionsJson=@"[""A. 能完全消除娛樂產業的成本"", ""B. 僅用於管理員工出勤"", ""C. 加速內容建立、提供個人化體驗並協助內容貨幣化"", ""D. 只能產生靜態文字廣告""]", CorrectAnswer="C", Explanation=@"生成式AI可以快速生成多版本內容並分析觀眾偏好，支援個人化推薦與收益模式設計。" },
            new() { Id=5333, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能代表生成式AI在內容建立活動中的應用？", OptionsJson=@"[""A. 自動設定防火牆規則"", ""B. 管理公司財務帳目"", ""C. 僅進行資料備份與還原"", ""D. 撰寫文章、產生社群貼文與撰寫電子郵件內容""]", CorrectAnswer="D", Explanation=@"生成式AI常用於自動產生各類文本內容，如文章草稿、貼文與郵件，有效提升內容產出效率。" },
            new() { Id=5334, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在醫療決策支援中，生成式AI扮演的角色為何？", OptionsJson=@"[""A. 分析病患資料並提供診斷建議草案，協助醫師決策"", ""B. 自動批准所有醫療處置申請"", ""C. 只管理醫療器材盤點"", ""D. 直接取代專科醫師培訓""]", CorrectAnswer="A", Explanation=@"系統可彙整檢驗與影像結果產出建議，但最終診斷仍需由醫師負責。" },
            new() { Id=5335, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在電信產業中，引入生成式AI的典型目標為何？", OptionsJson=@"[""A. 提高電話費率以增加收入"", ""B. 預測網路故障並進行預防性維護，改善客戶體驗"", ""C. 只管理員工班表"", ""D. 強制縮短用戶上網時間""]", CorrectAnswer="B", Explanation=@"透過分析網路流量與設備紀錄，AI可提前偵測異常、安排維護，降低中斷風險。" },
            new() { Id=5336, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"語言模型的核心功能可如何描述？", OptionsJson=@"[""A. 將影像轉成聲音訊號"", ""B. 壓縮影音檔案"", ""C. 根據上下文預測下一個單詞或標記的機率分布"", ""D. 只負責排序資料庫索引""]", CorrectAnswer="C", Explanation=@"大多數語言模型透過預測下一個詞元來學習語言結構與用法。" },
            new() { Id=5337, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在設計領域，生成式AI可以如何協助簡報設計？", OptionsJson=@"[""A. 僅負責壓縮簡報檔案大小"", ""B. 只能為投影片設定檔案密碼"", ""C. 僅能產生隨機色彩主題"", ""D. 根據提供的文本自動生成視覺投影片版面""]", CorrectAnswer="D", Explanation=@"設計類生成式AI可依使用者輸入的結構或文字，自動排版並產生具視覺吸引力的投影片。" },
            new() { Id=5338, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在金融產業中，導入生成式AI的主要目標之一為何？", OptionsJson=@"[""A. 改善個人化客戶服務，並協助風險降低與文件自動化"", ""B. 只處理現金存放安全"", ""C. 取代所有法規遵循人員"", ""D. 僅用於計算匯率""]", CorrectAnswer="A", Explanation=@"生成式AI可以分析客戶行為提供客製化建議，同時自動產出合約與報告，支援風險與合規流程。" },
            new() { Id=5339, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在零售與電商領域，生成式AI常被用來做什麼？", OptionsJson=@"[""A. 計算營業稅與成本"", ""B. 生成產品文本、圖像、影片與3D資產，並建立個人化購物體驗"", ""C. 僅記錄倉庫溫濕度"", ""D. 限制顧客瀏覽時間""]", CorrectAnswer="B", Explanation=@"零售業者利用生成式AI產生產品說明與視覺素材，並根據顧客行為設計個人化推薦與頁面。" },
            new() { Id=5340, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"生成式AI在醫療影像中的一項關鍵應用是什麼？", OptionsJson=@"[""A. 任意公開病患原始影像以增加資料量"", ""B. 只提供醫院財務預算建議"", ""C. 生成合成醫療影像做訓練與研究，同時兼顧隱私保護"", ""D. 取代所有放射科醫師職務""]", CorrectAnswer="C", Explanation=@"合成影像可增加訓練資料多樣性，又能避免直接暴露真實病患資料，有助隱私保護。" },
            new() { Id=5341, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在軟體開發中，使用生成式AI工具（如程式碼助理）的主要好處是什麼？", OptionsJson=@"[""A. 讓程式完全不必測試"", ""B. 只用來加密原始碼"", ""C. 取代版本控制系統"", ""D. 自動生成與重構程式碼，減少重複勞務並提高效率""]", CorrectAnswer="D", Explanation=@"程式碼生成工具可根據上下文給出程式碼片段，協助開發者更快完成常見模式與樣板。" },
            new() { Id=5342, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"自注意力機制在語言模型中的主要功用為何？", OptionsJson=@"[""A. 動態衡量序列中各詞元之間的重要性與關聯性"", ""B. 自動安裝硬體驅動程式"", ""C. 將所有輸入權重設定為零"", ""D. 只處理數值欄位而非文字""]", CorrectAnswer="A", Explanation=@"自注意力讓模型能針對不同位置的詞分配不同權重，以掌握重要的上下文關係。" },
            new() { Id=5343, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"大型語言模型（LLM）最主要設計目的是什麼？", OptionsJson=@"[""A. 管理公司財務報表"", ""B. 理解並生成自然語言文字內容"", ""C. 控制工廠機械手臂動作"", ""D. 只負責資料庫備份""]", CorrectAnswer="B", Explanation=@"LLM 是為理解語意與產生自然語言而設計，可應用於對話、摘要與內容生成。" },
            new() { Id=5344, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在LLM中，「參數」一詞指的是什麼？", OptionsJson=@"[""A. 硬體設備的序號"", ""B. 使用者輸入的關鍵字"", ""C. 模型中可訓練的權重或變數"", ""D. 網路頻寬設定值""]", CorrectAnswer="C", Explanation=@"參數是模型在訓練過程中調整的權重，數量影響模型的容量與表現上限。" },
            new() { Id=5345, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"Transformer架構被廣泛用於生成式AI的原因是什麼？", OptionsJson=@"[""A. 能完全不使用注意力機制"", ""B. 專門用於壓縮影像"", ""C. 僅支援單一字元輸入"", ""D. 適合處理序列資料並透過注意力機制擷取長距依賴""]", CorrectAnswer="D", Explanation=@"Transformer透過多頭自注意力有效掌握長距上下文，適合語言與其他序列任務。" },
            new() { Id=5346, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"ChatGPT所使用的訓練方法中，RLHF（人類回饋強化學習）的核心目的為何？", OptionsJson=@"[""A. 根據人類偏好調整模型輸出，使回應更貼近人類期待"", ""B. 讓模型完全不再學習新資料"", ""C. 只用來減少參數數量"", ""D. 改成只輸出隨機答案""]", CorrectAnswer="A", Explanation=@"RLHF結合人類對回答品質的評分或排序，透過強化學習讓模型產生更合適的回應。" },
            new() { Id=5347, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"GitHub Copilot 這類工具的主要功能為何？", OptionsJson=@"[""A. 自動整理員工排班表"", ""B. 整合於程式碼編輯器中，提供即時程式碼補全與建議"", ""C. 只用來壓縮程式檔案"", ""D. 負責部署伺服器硬體""]", CorrectAnswer="B", Explanation=@"GitHub Copilot 會根據目前檔案與專案上下文，預測開發者可能想寫的程式碼片段。" },
            new() { Id=5348, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"Microsoft 365 Copilot 與一般聊天機器人相比，最大的特點是什麼？", OptionsJson=@"[""A. 只能在命令列介面使用"", ""B. 僅能回答天氣資訊"", ""C. 不支援文件內容讀取"", ""D. 深度整合 Word、Excel、PowerPoint 等Office工具與Graph資料""]", CorrectAnswer="D", Explanation=@"Microsoft 365 Copilot 利用LLM 結合使用者文件與組織資料，支援寫作、分析與簡報製作。" },
            new() { Id=5349, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"在醫療情境中使用合成醫療影像訓練模型，其主要倫理優勢為何？", OptionsJson=@"[""A. 在增加資料多樣性的同時降低直接暴露敏感個資的風險"", ""B. 可以隨意分享病患真實資料"", ""C. 保證模型不再需要任何真實影像"", ""D. 可完全取代倫理審查機制""]", CorrectAnswer="A", Explanation=@"合成影像降低了對真實敏感資料的依賴，有助隱私保護，但仍需適當的倫理與實證檢驗。" },
            new() { Id=5350, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某零售平台使用生成式AI動態調整首頁商品顯示，長期下來卻讓小品牌曝光大幅下降。這最貼近下列哪一種風險？", OptionsJson=@"[""A. 單純的硬體故障"", ""B. 演算法偏見造成分配不公平"", ""C. 網路頻寬不足"", ""D. 資料庫語法錯誤""]", CorrectAnswer="B", Explanation=@"系統若依歷史點擊與轉換偏好優待大品牌，可能在無意間加劇既有市場集中與不公平。" },
            new() { Id=5351, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"關於LLM的「幻覺」現象，下列哪一項作法最能直接降低其在重要決策中的負面影響？", OptionsJson=@"[""A. 改用更大的模型並取消所有審核流程"", ""B. 完全禁止模型回答使用者問題"", ""C. 在關鍵領域導入人工複核與多來源事實查核流程"", ""D. 只要求模型回覆更長的答案""]", CorrectAnswer="C", Explanation=@"幻覺無法完全避免，因此在醫療、金融等高風險情境中必須透過人工與來源驗證降低風險。" },
            new() { Id=5352, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某遊戲公司使用生成式AI為NPC產生對話，卻被發現NPC偶爾輸出帶有歧視言論的台詞，最可能的根本原因是什麼？", OptionsJson=@"[""A. GPU運算速度太快"", ""B. 遊戲地圖太小"", ""C. 玩家登入人數不足"", ""D. 訓練資料中包含偏見與不當語言，模型在生成時重現了這些模式""]", CorrectAnswer="D", Explanation=@"若訓練語料本身含有歧視與偏見用語，模型就可能在新情境中產生類似輸出。" },
            new() { Id=5353, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"當企業將生成式AI導入客服聊天機器人時，下列哪一種策略最能兼顧效率與風險控管？", OptionsJson=@"[""A. 限制AI僅在低風險情境提供建議答覆，高風險案件轉交人工處理"", ""B. 允許AI對所有投訴案件直接做出最終賠償決策"", ""C. 讓AI自行蒐集並儲存所有客戶敏感資料"", ""D. 只讓AI回覆固定的FAQ而不記錄任何對話""]", CorrectAnswer="A", Explanation=@"分級管理能讓AI在常規問題上發揮效率，同時避免在複雜或敏感案件上越權決策。" },
            new() { Id=5354, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"Midjourney這類文本轉圖像工具與LLM及穩定擴散模型的關係，下列哪一項描述較為恰當？", OptionsJson=@"[""A. 完全不依賴任何語言模型"", ""B. 結合語言模型理解文字提示，再由擴散模型負責影像生成"", ""C. 先由擴散模型產生文字，再由LLM轉成圖像"", ""D. 只使用傳統規則式程式產生圖像""]", CorrectAnswer="B", Explanation=@"系統通常先以語言模組解析提示，再將語意轉為適合擴散模型生成圖像的表示。" },
            new() { Id=5355, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"在LLM應用中加入「領域專家微調模型」的主要好處為何？", OptionsJson=@"[""A. 讓模型不再需要基礎語言能力"", ""B. 降低所有推論延遲到零"", ""C. 提高模型在特定領域（如醫療、金融）中的上下文理解與專業準確度"", ""D. 讓模型只能回答單選題""]", CorrectAnswer="C", Explanation=@"在通用模型上再以特定領域資料微調，可使輸出更符合該領域術語與情境。" },
            new() { Id=5356, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"在多種生成式AI應用中，同時使用真實與合成資料的關鍵設計考量是什麼？", OptionsJson=@"[""A. 確保兩者比例完全相同"", ""B. 盡量只保留合成資料"", ""C. 排除所有來源標示以簡化流程"", ""D. 在提升模型泛化能力的同時，避免因合成資料分布失真而造成偏差""]", CorrectAnswer="D", Explanation=@"合成資料應輔助而非完全取代真實資料，並需檢查其與真實世界分布的一致性。" },
            new() { Id=5357, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某組織想評估生成式AI在醫療決策支援中的實際成效，下列哪一項評估方法最具代表性？", OptionsJson=@"[""A. 僅比較部署前後的硬體採購成本"", ""B. 比較導入前後誤診率、早期檢出率與醫師工作負荷等臨床指標"", ""C. 統計使用者對介面顏色的喜好"", ""D. 只調查IT部門滿意度""]", CorrectAnswer="B", Explanation=@"對臨床相關指標與工作流程負荷的量化分析，才能真正反映AI導入的醫療成效。" },
            new() { Id=5358, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"在設計生成式AI應用的合規策略時，下列哪一項做法最能體現「資料最小化」原則？", OptionsJson=@"[""A. 將所有可取得資料一律蒐集並上傳雲端訓練"", ""B. 無限制地與第三方共享訓練資料"", ""C. 永久保留所有原始輸入以備未來使用"", ""D. 只蒐集完成任務所必需的欄位，並對敏感資料做匿名化或去識別化處理""]", CorrectAnswer="D", Explanation=@"資料最小化強調僅蒐集與保留完成特定目的所需的最少資訊，並搭配適當保護措施。" },
            new() { Id=5359, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"關於「提示詞（Prompt）」的敘述，下列何者最為正確？", OptionsJson=@"[""A. 提示詞是用來引導 AI 產生特定輸出的輸入文字或指令"", ""B. 提示詞是模型訓練過程中的權重參數設定"", ""C. 提示詞只在圖像生成模型中使用，與文字任務無關"", ""D. 提示詞主要用來調整硬體資源配置""]", CorrectAnswer="A", Explanation=@"提示詞是使用者給模型的輸入文字或指令，用來引導特定輸出。" },
            new() { Id=5360, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"「簡單提示詞」最適合描述下列哪一種情境？", OptionsJson=@"[""A. 需要明確規定回應格式與欄位的報表產出"", ""B. 只用一句話請模型將英文句子翻譯成中文"", ""C. 要求模型依照多步驟流程進行推理與說明"", ""D. 在提示中加入角色、任務與格式三部分""]", CorrectAnswer="B", Explanation=@"簡單提示詞只需直接描述基本任務，不含複雜結構與背景。" },
            new() { Id=5361, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"關於「結構化提示詞」，下列何者最貼切？", OptionsJson=@"[""A. 以明確的指示與組織化格式，讓模型依固定欄位或步驟回答"", ""B. 完全依賴模型自行決定回答形式"", ""C. 只接受是非題形式的輸入"", ""D. 主要用於訓練模型，而非日常使用""]", CorrectAnswer="A", Explanation=@"結構化提示詞強調明確指示與固定格式，提升輸出一致性。" },
            new() { Id=5362, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能說明「高品質提示詞」的價值？", OptionsJson=@"[""A. 讓模型忽略訓練資料，只靠運氣回答"", ""B. 可以更好對齊模型內部結構與資料，提升回應精確與相關性"", ""C. 只用更長的句子堆疊關鍵字即可"", ""D. 完全消除模型的所有錯誤""]", CorrectAnswer="B", Explanation=@"高品質提示詞能更好匹配模型能力，產生精確且相關的回應。" },
            new() { Id=5363, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"「提示工程」最核心的目的是哪一項？", OptionsJson=@"[""A. 透過設計與優化提示詞，讓 AI 產生更準確、有用或高效率的輸出"", ""B. 降低硬體設備採購成本"", ""C. 縮短模型訓練時間"", ""D. 完全取代標註資料的需求""]", CorrectAnswer="A", Explanation=@"提示工程重點在於設計與優化提示，提升模型輸出品質與效率。" },
            new() { Id=5364, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能代表提示工程對使用者體驗的影響？", OptionsJson=@"[""A. 使互動更直觀流暢，回應更貼近使用者期待"", ""B. 讓使用者無法修改輸入內容"", ""C. 使模型只能回答固定主題"", ""D. 要求使用者使用程式語言輸入指令""]", CorrectAnswer="A", Explanation=@"精心設計的提示能讓互動更自然，回應更符合期待。" },
            new() { Id=5365, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在應用提示工程時，若希望控制 AI 回應的風格與態度，下列做法何者最適切？", OptionsJson=@"[""A. 只調整輸出字數長度"", ""B. 在提示中明確說明要採用的語氣、風格與寫作方向"", ""C. 隨機更換模型參數"", ""D. 完全關閉模型的系統訊息""]", CorrectAnswer="B", Explanation=@"可透過提示中的語氣與風格指示，引導模型輸出一致風格。" },
            new() { Id=5366, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列哪一種作法最有助於降低大型語言模型的「幻覺」問題？", OptionsJson=@"[""A. 結合外部經過審核的知識來源，並在提示中提供相關上下文"", ""B. 讓模型在資訊不足時強制輸出答案"", ""C. 完全關閉模型存取外部資料的能力"", ""D. 將所有回答限制在是非題""]", CorrectAnswer="A", Explanation=@"結合外部可靠資料與適當提示能減少幻覺並提升準確度。" },
            new() { Id=5367, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在決策支援系統中，精心設計的提示詞可以帶來哪項主要好處？", OptionsJson=@"[""A. 生成更細緻、相關的分析結果，協助提升決策效率與品質"", ""B. 使系統只能處理單一問題"", ""C. 完全排除人類參與"", ""D. 只能回傳原始數據不做解讀""]", CorrectAnswer="A", Explanation=@"良好提示可引導模型產生有助決策的深度分析。" },
            new() { Id=5368, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"關於「思維鏈提示（Chain-of-Thought）」的使用情境，下列何者最適合？", OptionsJson=@"[""A. 希望模型逐步展示中間推理過程來解數學或邏輯題"", ""B. 需要模型同時評估多個互斥分支方案"", ""C. 只要求模型給出最終答案即可"", ""D. 只處理單字翻譯任務""]", CorrectAnswer="A", Explanation=@"思維鏈提示強調逐步推理並顯示中間步驟。" },
            new() { Id=5369, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在提示工程中加入「角色設定」的主要目的為何？", OptionsJson=@"[""A. 讓模型更清楚自身在任務中的定位，產生更符合期待的回應"", ""B. 限制模型只能回答固定長度內容"", ""C. 讓模型無法引用外部知識"", ""D. 縮短模型輸出時間但犧牲品質""]", CorrectAnswer="A", Explanation=@"角色設定可明確模型身份與視角，提高回應相關性與專業度。" },
            new() { Id=5370, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能表現「提示工程是一個反覆迭代過程」的概念？", OptionsJson=@"[""A. 持續觀察模型回應，調整提示 wording 與結構以改善結果"", ""B. 一次設計完成後禁止修改提示"", ""C. 只依賴隨機試誤不紀錄任何經驗"", ""D. 只在模型訓練階段使用提示，部署後不再調整""]", CorrectAnswer="A", Explanation=@"提示工程需要不斷測試、評估與調整才能優化回答品質。" },
            new() { Id=5371, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"CTF 結構中，「C」所代表的概念最適切的說明為何？", OptionsJson=@"[""A. Context，背景與情境"", ""B. Command，命令"", ""C. Concept，概念說明"", ""D. Category，分類""]", CorrectAnswer="A", Explanation=@"CTF 中 C 是 Context，指提供必要的背景與情境資訊。" },
            new() { Id=5372, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"RTF 結構中，「R」與 CTF 結構中的「C」分別強調哪一項？", OptionsJson=@"[""A. R 強調角色，C 強調情境背景"", ""B. R 強調報酬，C 強調成本"", ""C. R 強調資源，C 強調控制條件"", ""D. R 強調風險，C 強調信心""]", CorrectAnswer="A", Explanation=@"RTF 的 R 是 Role，CTF 的 C 是 Context，兩者常被考其差異。" },
            new() { Id=5373, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"在 RAG 系統中加入「檢索器」的主要目的為何？", OptionsJson=@"[""A. 從外部資料庫中找到與查詢相關的內容供模型參考"", ""B. 產生新的訓練資料"", ""C. 壓縮模型權重以節省空間"", ""D. 負責部署模型到伺服器""]", CorrectAnswer="A", Explanation=@"檢索器負責依查詢從外部資料源找出相關上下文。" },
            new() { Id=5374, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"關於 RAG 技術，下列哪一項描述最恰當？", OptionsJson=@"[""A. 透過從外部來源擷取資料，豐富提示內容，讓模型在不重訓下產生更完整回答"", ""B. 必須重新訓練模型才能使用 RAG"", ""C. 只能用於影像生成任務"", ""D. 會降低回答與外部資料的一致性""]", CorrectAnswer="A", Explanation=@"RAG 以外部資料增強提示，無需重訓即可提升回答完整性。" },
            new() { Id=5375, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列何種應用場景最適合導入 RAG？", OptionsJson=@"[""A. 需要頻繁取得最新政策與法規變更資訊"", ""B. 需要處理靜態且多年不變的知識"", ""C. 只進行簡單四則運算"", ""D. 僅需隨機產生故事情節""]", CorrectAnswer="A", Explanation=@"RAG 能提供即時更新資料，特別適合最新政策與法規查詢。" },
            new() { Id=5376, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"一般「微調（Fine-tuning）」相較於僅使用基礎模型，其最大優點是什麼？", OptionsJson=@"[""A. 在特定任務或領域表現更佳"", ""B. 使模型通用性完全消失"", ""C. 大幅降低所有運算成本但犧牲準確度"", ""D. 使模型不能再使用外部工具""]", CorrectAnswer="A", Explanation=@"微調能針對特定任務或領域優化模型表現。" },
            new() { Id=5377, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"LoRA 在微調大型語言模型時的關鍵特性為何？", OptionsJson=@"[""A. 透過引入低秩矩陣，只需調整少量參數即可完成微調"", ""B. 完全凍結所有參數，不允許任何更新"", ""C. 只適用於影像模型，不能用於文字模型"", ""D. 需要比一般微調更多的 GPU 記憶體""]", CorrectAnswer="A", Explanation=@"LoRA 利用低秩矩陣，減少需更新參數數量，節省資源。" },
            new() { Id=5378, ChapterId=1306, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能說明 LoRA 對遷移學習的幫助？", OptionsJson=@"[""A. 可在較少訓練資料下進行有效微調，提升在新任務上的表現"", ""B. 需要大量標註資料才能遷移"", ""C. 限制模型只能在單一任務中運作"", ""D. 需要頻繁重訓整個模型""]", CorrectAnswer="A", Explanation=@"LoRA 以較少資料完成微調，提升多任務遷移效率。" },
            new() { Id=5379, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某團隊在專案中區分三個層次：A. 調整與使用者對話的提示設計；B. 建立外部知識庫供查詢；C. 針對自家資料微調模型。若依互動層、資料層、模型層的順序排列，下列何者正確？", OptionsJson=@"[""A. A=互動層，B=資料層，C=模型層"", ""B. A=資料層，B=互動層，C=模型層"", ""C. A=模型層，B=資料層，C=互動層"", ""D. A=互動層，B=模型層，C=資料層""]", CorrectAnswer="A", Explanation=@"A 為提示工程層（互動）、B 為 RAG 資料層、C 為微調/LoRA 模型層。" },
            new() { Id=5380, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某數學解題系統要求模型：先重述題意、列出已知與未知，再逐步展開推理，最後給出答案。整個過程以線性步驟呈現。此系統最可能採用了哪種提示方式？", OptionsJson=@"[""A. 思維樹提示（Tree-of-Thought）"", ""B. 思維鏈提示（Chain-of-Thought）"", ""C. 方向性刺激提示"", ""D. RTF 結構提示""]", CorrectAnswer="B", Explanation=@"題幹描述線性多步驟推理，符合思維鏈提示特徵。" },
            new() { Id=5381, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"另一個系統在設計提示時，先定義「專案是否可行」為主幹，再將其拆成「技術風險、財務風險、市場風險」等分支，下層再細分為更具體檢查項目。此種層級化提示最適合歸類為：", OptionsJson=@"[""A. 思維鏈提示"", ""B. 思維樹提示"", ""C. 方向性刺激提示"", ""D. CTF 結構提示""]", CorrectAnswer="B", Explanation=@"主幹、分支、葉子與層級結構是思維樹提示典型特徵。" },
            new() { Id=5382, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某法律諮詢機器人被要求「僅依據台灣現行法律條文回答，避免引用其他國家案例」，此設計主要是透過哪種提示特性來提升回答精準度？", OptionsJson=@"[""A. 思維鏈提示：強調中間推理"", ""B. 思維樹提示：強調多分支結構"", ""C. 方向性刺激提示：減少歧義並聚焦意圖"", ""D. CTF 結構：強調格式設計""]", CorrectAnswer="C", Explanation=@"限制範圍與聚焦意圖是方向性刺激提示的核心作用。" },
            new() { Id=5383, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"下列哪一組最正確對應 RTF 與 CTF 結構中的關鍵要素？", OptionsJson=@"[""A. RTF：Role、Task、Format；CTF：Context、Task、Format"", ""B. RTF：Role、Topic、Format；CTF：Context、Target、Format"", ""C. RTF：Risk、Task、Form；CTF：Condition、Task、Form"", ""D. RTF：Role、Task、Field；CTF：Content、Task、Format""]", CorrectAnswer="A", Explanation=@"RTF 與 CTF 的差異主要在 R=Role 與 C=Context。" },
            new() { Id=5384, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某 AI 系統回答使用者提問前，會先：①根據問題從知識庫檢索相關文段；②將文段切分清理並向量化；③把整理後內容附加在提示中；④最後檢查輸出品質。此流程最接近下列何者？", OptionsJson=@"[""A. RAG 系統的擷取、處理、格式化、評估流程"", ""B. 一般模型訓練流程"", ""C. LoRA 的低秩矩陣分解流程"", ""D. 思維樹的主幹與分支建立流程""]", CorrectAnswer="A", Explanation=@"此流程四步驟正是 RAG 運作的典型階段。" },
            new() { Id=5385, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某財經聊天機器人能即時回答「今天台股大盤表現」與「最新利率決策」等問題，而開發團隊並未頻繁重訓模型，只是讓系統連結即時更新的資料庫。此作法主要運用了哪種技術的特性？", OptionsJson=@"[""A. 微調（Fine-tuning）"", ""B. RAG（檢索增強生成）"", ""C. LoRA（低秩自適應）"", ""D. 思維鏈提示""]", CorrectAnswer="B", Explanation=@"利用外部即時資料庫回答問題，是 RAG 的代表性優勢。" },
            new() { Id=5386, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"某公司僅有少量客訴處理對話紀錄與有限 GPU 記憶體，希望在不更新全部模型參數的情況下，將通用模型調整為專門客服模型。最合適的技術選擇為何？", OptionsJson=@"[""A. 從頭訓練全新大型模型"", ""B. 使用 LoRA 微調，只調整少量附加參數"", ""C. 完全改用 RAG，不做任何模型調整"", ""D. 僅依賴提示工程，不使用任何訓練資料""]", CorrectAnswer="B", Explanation=@"LoRA 可在少量資料與有限資源下，以小幅參數調整完成微調。" },
            new() { Id=5387, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"下列哪一種題目描述最有可能是在考「RAG 的資料更新優勢」？", OptionsJson=@"[""A. 強調模型在單一任務上的推理深度"", ""B. 強調系統透過外部資料庫提供最新與即時資訊"", ""C. 強調模型權重壓縮比率"", ""D. 強調僅靠提示即可避免所有錯誤""]", CorrectAnswer="B", Explanation=@"提到「最新、即時」與外部資料庫時，多在考 RAG 的優勢。" },
            new() { Id=5388, ChapterId=1306, Type="multiple", Difficulty=3, QuestionText=@"若題目強調「在少量資料與有限 GPU 記憶體下，仍能有效微調大型模型」，最有可能對應到下列哪一項技術特性？", OptionsJson=@"[""A. 一般微調的一般特性"", ""B. RAG 的檢索能力"", ""C. LoRA 減少可訓練參數與資源需求的能力"", ""D. 思維鏈提示提升推理能力的特性""]", CorrectAnswer="C", Explanation=@"少量資料＋有限資源仍能微調，是 LoRA 的代表性優勢。" },
            new() { Id=5389, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在規劃生成式AI導入時，下列哪一項作法最能確保專案真正對企業產生實質商業價值，而不是流於技術展示？", OptionsJson=@"[""A. 先明確對齊企業商業目標與關鍵指標，再從中辨識可用生成式AI解決的使用情境"", ""B. 優先挑選開發成本最低、導入最省時的應用案例"", ""C. 先選擇目前市場上最熱門、參數量最大的模型"", ""D. 由技術團隊決定模型與架構，再請業務單位配合現有方案""]", CorrectAnswer="A", Explanation=@"生成式AI導入需與企業商業目標緊密結合，應先定義清楚的商業目標與價值假設，再反推適合的使用情境與技術方案，以避免技術為主導、價值不明的專案。" },
            new() { Id=5390, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"為了制定一個以價值為導向的生成式AI戰略，組織在專案初期最應該先做的是哪一項工作？", OptionsJson=@"[""A. 直接建立大型資料湖，之後再思考要做哪些應用"", ""B. 先評估組織需求並確認生成式AI能真正帶來利益的領域"", ""C. 先全面盤點現有的所有AI工具與平台"", ""D. 優先導入可節省最多人力的RPA流程自動化""]", CorrectAnswer="B", Explanation=@"以價值為導向的生成式AI戰略，需要先了解組織的痛點與目標，辨識生成式AI在哪些領域能產生實質影響，再規劃後續技術與資料需求。" },
            new() { Id=5391, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在生成式AI專案開始時進行技術可行性分析的主要目的為何？", OptionsJson=@"[""A. 確認市場上是否有足夠多的競爭對手以驗證技術成熟度"", ""B. 確定專案能在一年內完成以滿足管理層預期"", ""C. 讓供應商承諾未來三年的維護合約"", ""D. 確保所選技術與基礎設施能支援專案需求與目標，並預先識別技術風險""]", CorrectAnswer="D", Explanation=@"技術可行性分析重點在檢查基礎設施負載能力、模型與架構是否符合業務需求，及早發現潛在技術瓶頸，調整計畫以降低風險。" },
            new() { Id=5392, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"生成式AI輸出品質高度依賴輸入資料品質。下列何者最能反映這個關係？", OptionsJson=@"[""A. 資料品質只影響訓練時間，與最終輸出無關"", ""B. 資料量愈大一定比資料品質重要"", ""C. 資料品質良好可以提升模型的準確性與可靠性，使生成的結果更有實際價值"", ""D. 只要模型足夠大，就可以彌補資料品質不佳的問題""]", CorrectAnswer="C", Explanation=@"生成式AI的表現與訓練與推論所用資料的品質高度相關，良好的資料管理與準備能提升結果的準確性與可用性，是成功實施的關鍵。" },
            new() { Id=5393, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在評估生成式AI專案的資料環境時，第一步應優先進行哪一項？", OptionsJson=@"[""A. 先決定要採用哪一種大型語言模型"", ""B. 先設計前端使用者介面，之後再回頭確認資料來源"", ""C. 將現有資料全部存入資料湖後再判斷用途"", ""D. 識別所有潛在資料來源，包含結構化、半結構化與非結構化資料""]", CorrectAnswer="D", Explanation=@"只有先全面辨識所有相關資料來源，才能進一步評估資料品質、適用性，並設計合適的資料治理與隱私保護措施。" },
            new() { Id=5394, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"為了兼顧資料品質與未來可擴展性，下列哪一種資料處理方式最適合生成式AI專案？", OptionsJson=@"[""A. 只針對目前的單一專案客製化撰寫一次性資料清洗腳本"", ""B. 完全仰賴模型在訓練過程自動學會忽略雜訊與缺失值"", ""C. 將所有原始資料直接輸入模型以避免前處理偏差"", ""D. 建立一致且可重複使用的資料處理結構，確保不同情境下都能用相同邏輯處理資料""]", CorrectAnswer="D", Explanation=@"一致的資料處理架構可支援可擴展性與可重複性，讓組織在不同專案重用相同流程，同時維持資料品質與效率。" },
            new() { Id=5395, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"關於缺失值與資料空隙，下列哪一個描述最恰當？", OptionsJson=@"[""A. 缺失值只會稍微影響模型訓練速度，對預測結果影響有限"", ""B. 只要刪除所有有缺失值的紀錄即可確保資料品質"", ""C. 可以交由模型在訓練過程自動推測缺失值，不需額外處理"", ""D. 應透過檢查並適當填補缺失值，必要時從其他資料來源補充資訊""]", CorrectAnswer="D", Explanation=@"缺失值與資料空隙若未妥善處理，容易導致偏差與錯誤判斷，透過補值與引入其他來源資訊可提升整體資料集品質與決策可靠度。" },
            new() { Id=5396, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"醫療健康相關產業在建置生成式AI資料解決方案時，特別需要注意哪一項？", OptionsJson=@"[""A. 是否能使用最新版本的開源框架"", ""B. 是否能完全移除人工審核流程以節省成本"", ""C. 是否能將所有資料集中到海外雲端以便管理"", ""D. 是否符合相關資料隱私與醫療法規的要求""]", CorrectAnswer="D", Explanation=@"醫療領域常處理高度敏感的個人健康資料，必須遵循相關隱私法規，確保資料處理與AI應用符合法律與行業標準。" },
            new() { Id=5397, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"公司在準備好輸入資料後進行AI模型訓練，其主要目的是什麼？", OptionsJson=@"[""A. 讓模型學會如何壓縮資料以節省儲存成本"", ""B. 檢查資料是否存在非法內容並自動刪除"", ""C. 使模型在資料中學習模式與關聯，以便在特定任務上產生準確結果"", ""D. 讓系統能夠自動產生更多原始訓練資料""]", CorrectAnswer="C", Explanation=@"透過訓練過程，模型從資料中學習模式與關聯，使其在實際應用情境中能產生與任務目標相符的準確輸出。" },
            new() { Id=5398, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"當模型面對高度專業化的資料集時，為什麼通常需要額外的微調？", OptionsJson=@"[""A. 微調只是為了減少運算成本，與任務表現無關"", ""B. 微調可以讓模型更貼近特定領域資料特性與需求，提升在專業任務上的表現"", ""C. 因為所有預訓練模型在通用資料上表現都不好"", ""D. 微調可以避免任何資料前處理的需求""]", CorrectAnswer="B", Explanation=@"透過在少量領域專屬資料上進行微調，模型能更好地理解專業語彙與情境，產生更符合實務的結果。" },
            new() { Id=5399, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"選擇小而可控的使用案例作為生成式AI導入起點，主要好處是什麼？", OptionsJson=@"[""A. 能在有限範圍內快速測試與優化，取得回饋後再逐步擴大應用範圍"", ""B. 可以完全避免風險，不需要任何風險管理"", ""C. 能一次涵蓋所有業務流程，避免切割"", ""D. 可讓供應商提供最大折扣""]", CorrectAnswer="A", Explanation=@"小型使用案例範圍明確、風險較低，便於快速開發與迭代，在取得初步成效與學習後再擴大，有助降低導入風險。" },
            new() { Id=5400, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"使用案例排序時，以下哪一項考量最能幫助企業在早期就看到實質進展？", OptionsJson=@"[""A. 優先選擇最具技術挑戰性的案例"", ""B. 以商業影響與戰略重要性為核心評估指標"", ""C. 以是否能使用最新模型API作為主要標準"", ""D. 以是否可完全自動化、移除人工為唯一標準""]", CorrectAnswer="B", Explanation=@"將商業影響（效率、成本、客戶體驗等）與戰略重要性作為優先排序依據，可以確保資源投入在最能創造價值的案例上。" },
            new() { Id=5401, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在建立使用案例評分矩陣時，下列哪一組因素較符合實務需求？", OptionsJson=@"[""A. 員工興趣、社群聲量、媒體曝光度"", ""B. 潛在收入影響、成本減少機會、技術複雜度與實施時間等"", ""C. 供應商知名度、行銷預算、企業形象"", ""D. 開發人員人數、程式碼行數、專案簡報頁數""]", CorrectAnswer="B", Explanation=@"評分矩陣通常會同時考量商業價值（收入與成本）、技術難度、資源需求與時程，以量化各使用案例的可行性與潛在回報。" },
            new() { Id=5402, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在設計生成式AI概念驗證（PoC）時，為何需要明確定義資料預處理需求？", OptionsJson=@"[""A. 預處理只是為了讓資料看起來比較整齊，與模型表現無關"", ""B. 只要使用預訓練模型，就不需要做任何資料預處理"", ""C. 預處理主要是為了減少儲存空間"", ""D. 清楚的預處理規格可以確保輸入資料品質，提升模型準確性與可靠性""]", CorrectAnswer="D", Explanation=@"資料預處理包含清理與轉換步驟，可確保輸入資料適合建模，直接影響模型效能與PoC評估結果的可信度。" },
            new() { Id=5403, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在PoC設計中考慮系統整合點的主要原因是？", OptionsJson=@"[""A. 確認供應商是否願意提供技術支援"", ""B. 避免讓IT部門過早參與專案"", ""C. 確保新模型或應用能與既有系統順利交換資料與協作，維持資料完整性與流程順暢"", ""D. 確保所有程式碼都可以開源釋出""]", CorrectAnswer="C", Explanation=@"系統整合點牽涉資料流與功能協作，若未妥善設計，可能導致資料遺失、錯誤或流程中斷，影響整體解決方案可行性。" },
            new() { Id=5404, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在設計PoC時事先定義性能指標與評估標準的主要好處為何？", OptionsJson=@"[""A. 可以減少與利害關係人的溝通次數"", ""B. 可以避免蒐集過多評估資料"", ""C. 讓團隊可以自由詮釋結果，不受限制"", ""D. 有助於客觀評估模型是否達成預期業務與技術目標，並指引後續調整""]", CorrectAnswer="D", Explanation=@"明確的性能指標（如準確率、反應時間）與評估標準，可在測試階段清楚判斷PoC是否成功，並作為後續優化與投產決策依據。" },
            new() { Id=5405, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在選擇生成式AI模型架構時，下列哪一項是第一個關鍵決策點？", OptionsJson=@"[""A. 決定採用預訓練模型還是開發自建模型"", ""B. 決定要使用哪一種程式語言撰寫前端介面"", ""C. 決定是否將系統部署在行動裝置上"", ""D. 決定專案簡報應該有多少頁""]", CorrectAnswer="A", Explanation=@"選擇預訓練模型或自建模型會大幅影響開發成本、時程與可控性，也是後續技術與資料策略的重要前提。" },
            new() { Id=5406, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"關於生成式AI專案中的快速原型設計，下列何者正確？", OptionsJson=@"[""A. 快速原型的目的主要是產出可立即上線的正式產品"", ""B. 快速原型只適用於前端介面，不適用於AI模型"", ""C. 為避免干擾既有流程，應盡量避免在使用者身上測試原型"", ""D. 快速原型設計有助於在早期透過反覆測試與回饋，驗證想法並支援未來可擴展性""]", CorrectAnswer="D", Explanation=@"透過快速建立與測試原型，團隊能在專案早期發現問題並調整方向，確保後續擴展與落地更穩健。" },
            new() { Id=5407, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"生成式AI快速原型設計通常包含哪三個關鍵步驟？", OptionsJson=@"[""A. 蒐集需求、撰寫程式碼、上線部署"", ""B. 準備資料、處理資料、質性評估結果"", ""C. 選擇供應商、議價、簽約"", ""D. 設計UI、設計Logo、設計行銷素材""]", CorrectAnswer="B", Explanation=@"快速原型設計中，需先準備與處理資料，再對模型產出的結果進行質性評估，以確保原型具備實務價值並找出優化方向。" },
            new() { Id=5408, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在設計生成式AI MVP（最小可行產品）時，下列哪一項考量最關鍵？", OptionsJson=@"[""A. 必須同時考慮可擴展性、資料依賴性與持續模型訓練的安排"", ""B. 確保MVP一開始就覆蓋所有潛在使用情境"", ""C. 重點放在視覺設計而非功能完整性"", ""D. 只要功能能跑就好，不需考慮未來維運""]", CorrectAnswer="A", Explanation=@"MVP若忽視可擴展性、資料依賴與持續訓練，後續在規模放大時會面臨瓶頸，因此需一開始就納入長期運行與成長的考量。" },
            new() { Id=5409, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在生成式AI專案進行過程中，為何需要持續進行模型品質評估？", OptionsJson=@"[""A. 主要是為了滿足審計單位對文件數量的要求"", ""B. 只要一開始訓練完成後模型表現良好，就不需要再評估"", ""C. 品質評估只與使用者介面相關，與模型本身無關"", ""D. 品質評估有助於確認模型輸出是否符合業務需求並在不同情境下保持一致，及早發現問題與改進空間""]", CorrectAnswer="D", Explanation=@"持續檢查輸出是否符合業務目標、是否穩健與合乎倫理，可以在環境或資料變化時及時調整模型，維持效能與可信度。" },
            new() { Id=5410, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在改進生成式AI模型時，下列哪一種做法最不應被忽視？", OptionsJson=@"[""A. 只關注目前測試集的準確率提升"", ""B. 將所有資源集中在視覺優化與前端互動效果"", ""C. 完全依賴雲端供應商的自動更新，不做任何內部評估"", ""D. 同時評估模型未來在需求成長與環境變化下的可擴展性""]", CorrectAnswer="D", Explanation=@"若忽視可擴展性，模型在使用量增加或情境改變時可能出現效能瓶頸，無法支撐業務成長，因此改進時必須一併考慮長期可用性。" },
            new() { Id=5411, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"當預訓練模型無法滿足特定需求時，下列哪一項是企業選擇自建模型的主要理由？", OptionsJson=@"[""A. 自建模型一定比預訓練模型便宜"", ""B. 自建模型不需要任何專業人力就能完成"", ""C. 自建模型可以完全避免資料治理與隱私問題"", ""D. 自建模型可以針對高度專業領域或敏感資料進行客製化，滿足特別要求""]", CorrectAnswer="D", Explanation=@"在高度專業或敏感情境下，自建模型可依據特定需求與限制進行設計與訓練，雖然成本較高，但能提供更高的精準度與掌控度。" },
            new() { Id=5412, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"以下哪一項不屬於文本中提到的AI風險四大類？", OptionsJson=@"[""A. 資料風險"", ""B. 模型風險"", ""C. 操作風險"", ""D. 財務風險""]", CorrectAnswer="D", Explanation=@"說明中將AI風險分為資料、模型、操作以及倫理與法律四類，財務風險雖可能由這些風險引發，但並未被列為主要分類之一。" },
            new() { Id=5413, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"若組織希望藉由保護資料的完整性、安全性與可用性來降低AI系統風險，主要是在管理哪一類風險？", OptionsJson=@"[""A. 模型風險"", ""B. 操作風險"", ""C. 法律風險"", ""D. 資料風險""]", CorrectAnswer="D", Explanation=@"確保資料在AI生命週期中不被篡改、不遭未授權存取且保持可用，是降低資料風險的核心策略，也間接影響模型與操作風險。" },
            new() { Id=5414, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"若在開發與部署AI系統時忽視安全與倫理，下列哪一種情況最可能發生？", OptionsJson=@"[""A. 系統運算速度變慢"", ""B. 模型無法在雲端環境運行"", ""C. 使用者介面風格不一致"", ""D. 出現嚴重的隱私違規與偏見結果，損害組織聲譽與合規性""]", CorrectAnswer="D", Explanation=@"使用有偏見的訓練資料或忽視隱私要求，可能導致歧視性決策與違法處理個資，對組織的法遵與品牌產生重大衝擊。" },
            new() { Id=5415, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在選擇生成式AI模型時，下列哪一項描述最符合「沒有通用解法」的概念？", OptionsJson=@"[""A. 每個使用案例的資料型態、任務性質與業務目標不同，因此需依個別需求選擇最合適的模型"", ""B. 只要參數量越大，模型就越適合所有用例"", ""C. 使用開源模型總是比商業模型更好"", ""D. 只要選擇雲端服務，模型差異可以忽略不計""]", CorrectAnswer="A", Explanation=@"不同應用的要求差異極大，開發者必須根據資料特性、任務與目標等條件選擇模型，無法依賴單一通用方案因地制宜。" },
            new() { Id=5416, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"關於快速原型設計策略與專案失敗之間的關係，下列說明何者較為合理？", OptionsJson=@"[""A. 只要一開始就制定詳細長期計畫，就不需要快速原型"", ""B. 快速原型只會增加風險，應避免在AI專案中使用"", ""C. 只要採用市面上成熟的雲端服務，就一定不需要原型設計"", ""D. 許多公司在生成式AI專案卡關，是因缺乏明確計畫與快速原型設計，導致無法有效驗證與調整應用""]", CorrectAnswer="D", Explanation=@"缺乏計畫與原型驗證，專案往往難以及時發現問題並調整方向；快速原型有助於透過小步快跑降低整體失敗風險。" },
            new() { Id=5417, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在生成式AI專案中進行質性評估結果的主要目的為何？", OptionsJson=@"[""A. 確認模型輸出是否美觀"", ""B. 減少需要儲存的測試資料量"", ""C. 讓行銷部門可以挑選範例放入簡報"", ""D. 透過人工檢視生成內容的相關性、正確性與實用性，以補足純量化指標的不足""]", CorrectAnswer="D", Explanation=@"質性評估可從使用者與領域專家的角度，檢查生成結果是否真實、有用且符合情境，補強單一數值指標無法捕捉的細節。" },
            new() { Id=5418, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在AI風險管理中，同時兼顧資料、模型、操作以及倫理與法律風險的整體目的為何？", OptionsJson=@"[""A. 確保AI系統在整個生命週期都能安全、可靠且合規運行，並避免對組織與利害關係人造成不當傷害"", ""B. 確保專案文件數量達到稽核標準"", ""C. 讓系統在短期內達到最高可能的運算速度"", ""D. 確保可以完全取代所有人工決策""]", CorrectAnswer="A", Explanation=@"整合性風險管理的目標，是在AI從資料收集到部署與使用的各階段，兼顧安全性、穩定性與法遵，降低對組織與社會的不利影響。" },
            new() { Id=5419, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"下列哪一項最能說明生成式AI對企業具有「重大變革潛力」的原因？", OptionsJson=@"[""A. 能增強創造力並提升營運效率與客戶體驗"", ""B. 能取代所有既有IT系統"", ""C. 主要用於降低硬體成本"", ""D. 只在研究單位有價值""]", CorrectAnswer="A", Explanation=@"生成式AI可以同時強化創造力、營運效率與客戶體驗，並在多個業務領域創造競爭優勢而被視為具有重大變革潛力。" },
            new() { Id=5420, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"一家企業想制定生成式AI策略，下列哪一項做法最恰當？", OptionsJson=@"[""A. 先購買多個最新AI工具試用再說"", ""B. 先從公司願景與整體戰略目標出發規劃AI應用方向"", ""C. 把所有IT專案都改名為AI策略以爭取預算"", ""D. 完全交由供應商設計策略""]", CorrectAnswer="B", Explanation=@"生成式AI策略應由組織願景與戰略目標向下展開，確保AI計畫能直接支持整體業務目標。" },
            new() { Id=5421, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在生成式AI策略規劃中，為何「技術架構」比一味追逐最新工具更重要？", OptionsJson=@"[""A. 新工具通常功能較少"", ""B. 技術架構一旦建立就不需維護"", ""C. 穩健的技術架構能支援多種工具並提供可擴展且穩定的環境"", ""D. 工具比架構更容易標準化""]", CorrectAnswer="C", Explanation=@"正確觀點是先建立可擴展且穩定的技術架構，才能長期支援不同生成式AI工具。" },
            new() { Id=5422, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"專案啟動會議中，專案經理詢問「為何要先建立明確的專案目標？」最適合的回答是：", OptionsJson=@"[""A. 方便快速購買軟體"", ""B. 避免日後需要與管理階層溝通"", ""C. 作為評估進度與調整策略的基準並確保專案朝正確方向前進"", ""D. 讓團隊可以自由詮釋專案方向""]", CorrectAnswer="C", Explanation=@"清晰目標可提供方向與衡量基準，在遇到挑戰時也能依此調整策略，是長期成功的關鍵。" },
            new() { Id=5423, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"設定生成式AI專案目標時，下列哪一項最符合建議做法？", OptionsJson=@"[""A. 由技術團隊依興趣決定目標"", ""B. 以「導入最新模型」作為唯一目標"", ""C. 從組織的整體戰略目標出發，對齊業務價值與客戶需求"", ""D. 只以縮減IT人力為主要目標""]", CorrectAnswer="C", Explanation=@"正確作法是由上而下對齊組織戰略，讓AI專案直接支持業務目標並聚焦高價值應用情境。" },
            new() { Id=5424, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"企業在導入生成式AI前評估「資料分析能力」時，下列哪一項不屬於主要考量？", OptionsJson=@"[""A. 員工生日與興趣清單"", ""B. 現有工具與技術能力"", ""C. 資料分析相關流程與資料基礎設施"", ""D. 團隊成員的資料分析技能""]", CorrectAnswer="A", Explanation=@"資料分析能力評估聚焦在工具、技術、技能、流程與資料基礎設施等面向，與個人興趣無關。" },
            new() { Id=5425, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"企業希望確保生成式AI的道德使用，下列哪一項做法最合適？", OptionsJson=@"[""A. 完全禁止所有員工使用AI"", ""B. 只依賴外部供應商自律"", ""C. 建立公司AI使用政策並提供倫理與工具使用相關培訓"", ""D. 只要求IT部門遵守政策即可""]", CorrectAnswer="C", Explanation=@"應透過明確政策與員工培訓來落實倫理準則，降低濫用與風險，而非只依賴外部或單一部門。" },
            new() { Id=5426, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"某公司急於跟上潮流，決定在沒有詳細規劃的情況下，三個月內全面導入生成式AI到所有部門。從風險管理角度，較恰當的建議是：", OptionsJson=@"[""A. 維持原計畫以免錯失時機"", ""B. 改為先訂定清晰計畫與里程碑，分階段導入並定期檢視風險與成效"", ""C. 取消所有AI相關計畫"", ""D. 只在單一員工個人電腦上試用即可""]", CorrectAnswer="B", Explanation=@"過於快速導入會增加風險且實施不成熟，應以清晰計畫與里程碑分階段推進以平衡進度與風險。" },
            new() { Id=5427, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"關於訓練生成式AI模型所需的資料，下列哪一項敘述較為正確？", OptionsJson=@"[""A. 只要資料量足夠大就能忽略品質問題"", ""B. 資料應能代表預期輸出類型且需經適當清理"", ""C. 盡量蒐集任何來源的資料以增加多樣性即可"", ""D. 為節省成本可大量使用過期資料""]", CorrectAnswer="B", Explanation=@"高品質資料必須能代表模型需生成的輸出，並經過清理以提升模型性能與可靠性。" },
            new() { Id=5428, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在談到資料品質時，下列何者最符合「能用於決策的高品質資料」的描述？", OptionsJson=@"[""A. 允許少量錯誤但快速取得的資料"", ""B. 內容多元但格式與定義各自不同的資料"", ""C. 無錯誤、無不一致性且盡量降低偏見的資料"", ""D. 只來自單一系統的資料即視為高品質""]", CorrectAnswer="C", Explanation=@"成功的生成式AI與決策依賴高品質資料，應盡量避免錯誤、不一致與偏見。" },
            new() { Id=5429, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"關於設計生成式AI解決方案架構，下列哪一項最需要優先考量？", OptionsJson=@"[""A. 是否能完全取代所有既有系統"", ""B. 是否與現有系統與工作流程具有良好整合能力"", ""C. 是否能使用最昂貴的雲端服務"", ""D. 是否能讓使用者完全感受不到AI的存在""]", CorrectAnswer="B", Explanation=@"解決方案架構設計時必須考量與既有系統與流程的整合，以確保部署順利並能實際落地。" },
            new() { Id=5430, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"評估生成式AI模型性能時，下列哪一種做法最合理？", OptionsJson=@"[""A. 只以「模型參數量是否足夠大」作為唯一指標"", ""B. 根據具體任務選擇多種適當的評估指標並定期檢視"", ""C. 只看初次上線時的表現即可"", ""D. 完全以主觀感覺判斷輸出好壞""]", CorrectAnswer="B", Explanation=@"性能評估應依任務特性選擇多元指標並定期檢視，以確保模型持續符合業務需求。" },
            new() { Id=5431, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"技術評估在生成式AI導入過程中的主要目的為何？", OptionsJson=@"[""A. 比較不同供應商報價"", ""B. 識別組織目前的技術能力與差距並作為未來提升的基準"", ""C. 確認員工對AI的好感度"", ""D. 決定要裁減哪些IT人力""]", CorrectAnswer="B", Explanation=@"技術評估主要在找出現有能力與差距，並形成整合下一代AI技術與衡量進展的基準。" },
            new() { Id=5432, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"某公司主張「我們只要一次訓練好模型，之後就不必再調整。」依生成式AI最佳實務，下列說明何者較佳？", OptionsJson=@"[""A. 此作法合理，可避免不必要的維護成本"", ""B. 模型應持續根據新資料與需求進行迭代與改進"", ""C. 只要一開始資料夠多，確實不需要再調整"", ""D. 只需每十年更新一次模型即可""]", CorrectAnswer="B", Explanation=@"生成式AI模型需持續改進以因應需求變化與新資料，單次訓練後不再調整並不符合實務。" },
            new() { Id=5433, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在高風險場景使用生成式AI時，下列哪一項設計較為適當？", OptionsJson=@"[""A. 讓AI完全自動做決策以提高效率"", ""B. 只要模型準確率高於95%即可完全信任"", ""C. 明確界定AI僅提供建議並要求人工進行關鍵決策與複核"", ""D. 避免蒐集任何使用記錄以保護隱私""]", CorrectAnswer="C", Explanation=@"高風險場景應限制AI角色，多數情況下AI應提供建議而非單獨做決策，並搭配人工複核與治理。" },
            new() { Id=5434, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在生成式AI模型訓練過程中，進行參數優化的主要目的為何？", OptionsJson=@"[""A. 讓訓練過程更花時間以顯示專業度"", ""B. 縮小模型輸出與預期結果之間的差距以提升性能"", ""C. 降低模型對訓練資料的學習程度"", ""D. 讓模型輸出更隨機以避免重複""]", CorrectAnswer="B", Explanation=@"參數優化透過調整學習率等設定，以減少輸出與預期之間的差距，提升模型準確性與可靠性。" },
            new() { Id=5435, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"關於監控生成式AI模型的性能，下列哪一項最接近正確做法？", OptionsJson=@"[""A. 模型一旦上線後表現穩定即可停止監控"", ""B. 只在使用者抱怨時才檢查模型表現"", ""C. 持續追蹤模型在訓練與驗證資料上的表現並依結果調整參數"", ""D. 只監看系統CPU使用率即可""]", CorrectAnswer="C", Explanation=@"持續監控模型在不同資料集上的表現可及早發現過擬合或效能下降，再透過調整參數加以改善。" },
            new() { Id=5436, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"關於微調（fine-tuning）預訓練生成式AI模型，下列敘述何者正確？", OptionsJson=@"[""A. 微調是從零開始重新訓練一個模型"", ""B. 微調只會降低模型在特定任務的表現"", ""C. 微調是使用較小且專門的資料集進一步訓練模型以適應特定任務或領域"", ""D. 微調只能用在影像模型上""]", CorrectAnswer="C", Explanation=@"微調是在預訓練模型基礎上利用專門資料集再訓練，使模型更符合特定任務或領域需求。" },
            new() { Id=5437, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在評估多個生成式AI用例的優先級時，下列哪一個評估組合最完整？", OptionsJson=@"[""A. 只看是否能使用最新技術"", ""B. 只考慮能否在最短時間完成"", ""C. 同時考慮業務影響力、技術與資料可行性以及實施所需努力與時間"", ""D. 完全以專案負責人的個人興趣為主""]", CorrectAnswer="C", Explanation=@"用例排序應綜合影響、可行性與努力程度等指標，將資源集中在最有價值且可行的用例。" },
            new() { Id=5438, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"某企業想選擇合適的基礎模型做為生成式AI專案的起點，下列哪一項考量最為重要？", OptionsJson=@"[""A. 模型名稱是否夠知名"", ""B. 是否與組織現有資料類型與技術需求相符"", ""C. 是否可以完全取代所有人類工作"", ""D. 是否是市場上最昂貴的選項""]", CorrectAnswer="B", Explanation=@"選擇基礎模型時需考量技術需求與資料來源，確保模型能有效處理可用資料並符合專案要求。" },
            new() { Id=5439, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某公司行銷部提出多個生成式AI應用構想，下列哪一個情境最適合被評為「優先導入」？", OptionsJson=@"[""A. 技術成熟度中等、預期影響大、需要中量資源且法規風險低"", ""B. 技術極度困難、預期影響未知、需要大量資源且高度合規風險"", ""C. 技術簡單、預期影響極小、僅改善內部非核心流程"", ""D. 技術尚未發展成熟、必須自行研發演算法""]", CorrectAnswer="A", Explanation=@"優先用例通常是高影響、可行性合理且法規風險可控的方案，兼顧價值與落地機率。" },
            new() { Id=5440, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"一家金融機構想用生成式AI協助撰寫投資建議書。為降低偏見與錯誤資訊風險，下列哪一種資料策略最為合適？", OptionsJson=@"[""A. 大量爬取未經驗證的網路討論文章作為主要訓練資料"", ""B. 優先使用經審核的內部研究報告與權威公開資料並定期更新"", ""C. 只使用歷史報酬率資料而不包含任何文字說明"", ""D. 主要依賴外部供應商的黑箱資料集而不做檢查""]", CorrectAnswer="B", Explanation=@"在高風險金融情境下應使用經審核的高品質資料來源並持續更新，以降低偏見與錯誤輸出的風險。" },
            new() { Id=5441, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某企業在導入生成式AI客服機器人時，發現模型在冷門問題上表現很差。若已確認資料品質與技術架構皆無明顯問題，下列哪一項措施最能有效改善？", OptionsJson=@"[""A. 降低模型訓練次數以避免過擬合"", ""B. 針對冷門問題建立專門的補充資料並進行有目標的微調"", ""C. 完全停止使用生成式AI並改回人工客服"", ""D. 只調整推論溫度而不改變訓練流程""]", CorrectAnswer="B", Explanation=@"對特定弱項建立專門資料集並進行微調，可以讓模型在該領域取得顯著提升。" },
            new() { Id=5442, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"一位專案負責人主張：「只要我們把生成式AI直接接到既有的資料庫，就算完成導入。」根據導入評估與規劃的觀點，下列哪一項是對此說法最關鍵的反駁？", OptionsJson=@"[""A. 資料庫連線會降低系統效能"", ""B. 缺乏與既有業務流程與治理機制整合，無法保證輸出被正確使用"", ""C. 資料庫無法支援大量查詢"", ""D. 員工不習慣新介面""]", CorrectAnswer="B", Explanation=@"單純技術串接並不等同成功導入，仍需考慮流程與治理，確保輸出在業務情境中被正確使用。" },
            new() { Id=5443, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某組織已建立多個生成式AI應用，但長期下來發現各系統表現差異很大。若要從架構角度改善此問題，下列哪一項做法最具結構性？", OptionsJson=@"[""A. 允許各團隊各自採用不同最佳實務以鼓勵創新"", ""B. 建立統一的MLOps與模型治理平台及部署流程"", ""C. 完全禁止新模型上線"", ""D. 只關注表現最好的單一應用並忽略其他""]", CorrectAnswer="B", Explanation=@"透過統一的MLOps與治理平台整合部署流程與監控，可提升整體一致性與可維護性。" },
            new() { Id=5444, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"關於在高風險決策流程中導入生成式AI，下列哪一項治理機制最能反映適當的責任分工？", OptionsJson=@"[""A. 將模型預測視為最終決策來源，人類僅負責執行結果"", ""B. 要求人類決策者對所有使用AI輔助做出的決策負最終責任，並保留覆核與否決權"", ""C. 將所有決策責任轉移給模型供應商"", ""D. 讓模型自行紀錄決策理由以減少人類參與""]", CorrectAnswer="B", Explanation=@"在人命或法規風險高的情境，人類決策者應保留最終決策權與責任，AI僅扮演輔助角色。" },
            new() { Id=5445, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某公司想同時評估兩個生成式AI模型A與B。若目標是用於客服多輪對話，下列哪一種評估組合最具代表性？", OptionsJson=@"[""A. 只比較兩者的訓練時間"", ""B. 同時評估回答正確性、對話連貫性、禮貌程度與使用者滿意度"", ""C. 只看模型在標準語料上的困惑度"", ""D. 只比較兩者的參數數量和雲端費用""]", CorrectAnswer="B", Explanation=@"多輪對話情境需要兼顧正確性、連貫性與互動體驗，因此應採用多維度指標而非單一技術指標。" },
            new() { Id=5446, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某企業希望導入生成式AI支援多國語系客服，並計畫使用單一英文預訓練模型再微調。下列哪一項風險最值得在規劃階段優先評估？", OptionsJson=@"[""A. 模型無法處理任何文字輸入"", ""B. 對非英文語料的表現可能嚴重落後且產生文化語境錯誤"", ""C. 雲端供應商會自動翻譯所有語言"", ""D. 資料庫無法儲存多國語文字""]", CorrectAnswer="B", Explanation=@"若基礎模型主要以英文訓練，對其他語言的能力可能不足，易產生語意與文化錯誤，需預先評估並設計對策。" },
            new() { Id=5447, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某公司為了加速生成式AI專案進度，決定縮短前期資料盤點與風險評估時間。依照導入最佳實務，下列哪一項是最可能的負面後果？", OptionsJson=@"[""A. 模型參數量會顯著下降"", ""B. 專案成本一定會立刻增加"", ""C. 後期可能因資料品質與合規問題導致返工與上線延遲"", ""D. 使用者滿意度必然維持不變""]", CorrectAnswer="C", Explanation=@"忽略前期盤點與風險評估可能導致後期才暴露資料與法規問題，需要大幅返工與延後上線。" },
            new() { Id=5448, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某企業計畫讓各部門自行決定是否以及如何使用生成式AI，但沒有任何中央層級的策略或標準。根據生成式AI導入評估與規劃的概念，下列哪一項最可能發生？", OptionsJson=@"[""A. 各部門自發創新，自然會收斂成一致標準"", ""B. 能自動形成完整且一致的治理制度"", ""C. 出現工具與資料使用碎片化、重複投資與風險難以整體掌握的情況"", ""D. 所有部門都會自然放棄使用AI以避免風險""]", CorrectAnswer="C", Explanation=@"缺乏中央策略與標準會造成工具與資料使用高度碎片化，難以統一治理與優化資源配置。" },
            new() { Id=5449, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"生成式AI系統最大的固有風險之一是什麼？", OptionsJson=@"[""A. 可能生成看似合理但實際錯誤或有害的內容"", ""B. 只能在離線環境中運作"", ""C. 完全不會受到訓練資料品質影響"", ""D. 無法產生任何創新內容""]", CorrectAnswer="A", Explanation=@"生成式AI依賴既有資料模式，可能在不了解脈絡下生成誤導性或有害內容，這是其固有風險之一。" },
            new() { Id=5450, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"企業為何必須主動管理生成式AI輸出的風險？", OptionsJson=@"[""A. 避免系統當機"", ""B. 確保生成內容的準確性與安全性"", ""C. 降低硬體成本"", ""D. 提高員工滿意度""]", CorrectAnswer="B", Explanation=@"若不管理輸出風險，可能導致錯誤決策、法律責任與聲譽受損，因此需確保內容準確與安全。" },
            new() { Id=5451, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"下列何者不是題示中提到的AI風險四大類別？", OptionsJson=@"[""A. 資料風險"", ""B. 模型風險"", ""C. 市場風險"", ""D. 營運風險""]", CorrectAnswer="C", Explanation=@"題示將AI風險分為資料、模型、營運及倫理與法律四類，市場風險並未列為其中一類。" },
            new() { Id=5452, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"倫理及法律風險最可能對企業造成何種結果？", OptionsJson=@"[""A. 品牌與信任受損並可能面臨法律懲罰"", ""B. 程式效能下降"", ""C. 員工請假率下降"", ""D. 伺服器用電量增加""]", CorrectAnswer="A", Explanation=@"若AI違反隱私或歧視，將導致公眾信任流失與法律處分，是倫理及法律風險的典型結果。" },
            new() { Id=5453, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"AI影響評估的主要目的之一是什麼？", OptionsJson=@"[""A. 識別AI系統的目的、用例與潛在影響"", ""B. 提升硬體運算效能"", ""C. 確保程式碼符合內部風格指南"", ""D. 增加行銷預算""]", CorrectAnswer="A", Explanation=@"影響評估協助組織釐清AI用途與影響，作為制訂風險管理策略與建立信任的基礎。" },
            new() { Id=5454, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在影響評估中，為何要特別考量隱私保護？", OptionsJson=@"[""A. 隱私與AI效能毫無關聯"", ""B. 隱私法規通常較鬆散"", ""C. 確保AI應用符合法規並避免個資濫用"", ""D. 只為了提升廣告點擊率""]", CorrectAnswer="C", Explanation=@"影響評估必須檢視AI對隱私的狀況，以確保符合法規並避免資料濫用。" },
            new() { Id=5455, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"減少AI系統偏見的較佳做法是什麼？", OptionsJson=@"[""A. 完全避免使用任何歷史資料"", ""B. 定期測試模型公平性並去偏資料"", ""C. 只依賴自動化工具監測偏見"", ""D. 只在發生爭議時再人工修正""]", CorrectAnswer="B", Explanation=@"主動且定期的公平性測試與資料去偏，才能有效降低偏見風險。" },
            new() { Id=5456, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"AI偏見在下列哪個領域可能造成特別嚴重的後果？", OptionsJson=@"[""A. 娛樂節目推薦"", ""B. 招聘與人力資源決策"", ""C. 天氣預報"", ""D. 線上遊戲配對""]", CorrectAnswer="B", Explanation=@"在招聘等關鍵領域，不公平決策會直接影響個人職涯與權益，因此偏見風險特別敏感。" },
            new() { Id=5457, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"為何在採用生成式AI前要先進行風險評估？", OptionsJson=@"[""A. 避免與其他系統整合"", ""B. 全面了解技術、合規、倫理與操作層面的風險"", ""C. 縮短專案時程"", ""D. 減少模型參數數量""]", CorrectAnswer="B", Explanation=@"事前風險評估可識別多面向風險，協助組織先設計控制措施，確保負責任與可持續的應用。" },
            new() { Id=5458, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"常規與全面風險評估的主要價值是什麼？", OptionsJson=@"[""A. 讓模型永遠不需要更新"", ""B. 確保AI功能被安全使用並符合全球法規"", ""C. 避免員工接觸AI系統"", ""D. 使公司完全免於任何風險""]", CorrectAnswer="B", Explanation=@"隨AI能力擴展，持續評估能安全使用AI並維持對全球法規的符合。" },
            new() { Id=5459, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"SWOT分析在AI風險管理中的角色為何？", OptionsJson=@"[""A. 量化計算每項風險的精確金額"", ""B. 評估組織的優勢、劣勢、機會與威脅"", ""C. 只用來設計UI介面"", ""D. 專門用來測試模型效能""]", CorrectAnswer="B", Explanation=@"SWOT是質性分析工具，用於評估內外部優勢、劣勢、機會與威脅，支援風險策略制定。" },
            new() { Id=5460, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在風險評估中，使用「高、中、低」分級的主要目的是什麼？", OptionsJson=@"[""A. 美化報告格式"", ""B. 方便對外行銷"", ""C. 區分風險對業務目標影響的程度"", ""D. 減少風險項目數量""]", CorrectAnswer="C", Explanation=@"高、中、低分級可區分影響大小，幫助決定哪些風險需優先處理。" },
            new() { Id=5461, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"管理AI系統中的訊息洩漏風險，下列何者最符合建議？", OptionsJson=@"[""A. 僅加強資料加密即可"", ""B. 完全關閉所有外部介面"", ""C. 利用監控系統持續追蹤模型性能與異常行為"", ""D. 只在出現重大事故後再調查""]", CorrectAnswer="C", Explanation=@"持續監控模型性能可及早發現潛在安全問題，而非只依賴加密或事後補救。" },
            new() { Id=5462, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"AI風險管理框架的核心目標是什麼？", OptionsJson=@"[""A. 在創新與穩定性之間取得平衡並創造長期價值"", ""B. 消除所有形式的風險"", ""C. 只追求技術投資最大化"", ""D. 避免任何AI技術導入""]", CorrectAnswer="A", Explanation=@"框架旨在平衡創新與穩定，使AI創造長期價值且符合公司價值與法律標準。" },
            new() { Id=5463, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"NIST AI風險管理框架的特性，下列何者正確？", OptionsJson=@"[""A. 為強制性且只適用單一產業"", ""B. 為自願性且適用於各種公司與產業"", ""C. 僅適用於政府機關"", ""D. 只涵蓋資料風險一種""]", CorrectAnswer="B", Explanation=@"NIST框架是自願性、通用的結構化流程，適用於不同產業與地區。" },
            new() { Id=5464, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"AI風險管理框架中的四大核心功能不包含哪一項？", OptionsJson=@"[""A. 治理（Govern）"", ""B. 映射（Map）"", ""C. 測量（Measure）"", ""D. 營運（Operate）""]", CorrectAnswer="D", Explanation=@"核心功能為治理、映射、測量、管理，營運並非其中之一。" },
            new() { Id=5465, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"企業開始應用NIST AI風險管理框架的合理起點是什麼？", OptionsJson=@"[""A. 停止所有AI專案"", ""B. 收集AI系統元資料並開發標準風險緩解措施"", ""C. 只委外給顧問處理"", ""D. 僅針對單一專案零星評估""]", CorrectAnswer="B", Explanation=@"框架建議從盤點與收集元資料、建立標準化緩解措施開始，並逐步自動化審查。" },
            new() { Id=5466, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"NIST AI RMP的主要目標為何？", OptionsJson=@"[""A. 協助組織管理AI風險並促進可信任、負責任的AI實踐"", ""B. 提升廣告投放精準度"", ""C. 取代所有既有資訊安全框架"", ""D. 避免使用任何外部標準""]", CorrectAnswer="A", Explanation=@"其目標是協助在設計至使用全流程中有效管理風險，並促進可信任與負責任的AI。" },
            new() { Id=5467, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"AI治理與風險管理之間的關係為何？", OptionsJson=@"[""A. 彼此互相排斥"", ""B. 治理是行銷的一部分"", ""C. 與風險無關"", ""D. AI治理可視為風險管理的一部分，兩者共同確保安全與合規""]", CorrectAnswer="D", Explanation=@"AI治理聚焦設計與部署是否符合法律與倫理，風險管理聚焦具體風險減輕，兩者高度互補。" },
            new() { Id=5468, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在AI風險管理中強調透明性與可追溯性的原因是什麼？", OptionsJson=@"[""A. 增加模型運算時間"", ""B. 強化使用者與審計者對AI決策過程的理解與信任"", ""C. 減少程式碼行數"", ""D. 使系統完全不需稽核""]", CorrectAnswer="B", Explanation=@"透明性與可追溯性讓決策過程可理解且可追蹤，有助於審計、偏見檢測與問責。" },
            new() { Id=5469, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"下列哪一項最能說明「倫理及法律風險」與影響評估之間的關係？", OptionsJson=@"[""A. 倫理風險與影響評估無關"", ""B. 影響評估有助於在導入前辨識倫理與法律風險並設計緩解策略"", ""C. 只要完成技術測試就無須影響評估"", ""D. 影響評估僅考慮硬體成本""]", CorrectAnswer="B", Explanation=@"影響評估會將倫理與法律風險納入分析，協助在導入前規畫對應控制與緩解措施。" },
            new() { Id=5470, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某公司為了避免AI偏見，決定完全不使用歷史資料訓練模型。此作法最大的問題是什麼？", OptionsJson=@"[""A. 會導致模型運算速度過快"", ""B. 違反資料保護法規"", ""C. 無法有效學習真實世界模式且仍未解決偏見評估問題"", ""D. 只能在雲端環境使用""]", CorrectAnswer="C", Explanation=@"完全不用歷史資料既不實際，也無法取代公平性測試與去偏程序。" },
            new() { Id=5471, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在AI風險管理中提到的「轉移」策略，最適合下列哪種情境？", OptionsJson=@"[""A. 公司希望消除所有AI相關風險"", ""B. 公司停止所有AI開發"", ""C. 公司購買資安保險以分攤可能的資安事故損失"", ""D. 公司將AI系統完全對外公開原始碼""]", CorrectAnswer="C", Explanation=@"轉移透過保險或外包將部分風險後果交由第三方承擔，但風險本身並未消失。" },
            new() { Id=5472, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"風險矩陣在管理決策中的關鍵貢獻為何？", OptionsJson=@"[""A. 確保所有風險一律視為高風險"", ""B. 提供視覺化方式呈現風險發生機率與影響程度，協助決定優先順序"", ""C. 消除所有低風險項目"", ""D. 只用來計算投資報酬率""]", CorrectAnswer="B", Explanation=@"風險矩陣將可能性與影響度交叉呈現，讓管理階層能清楚決定資源配置優先順序。" },
            new() { Id=5473, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在企業導入生成式AI的情境下，何者最符合「資料治理」的核心精神", OptionsJson=@"[""A. 只要將所有資料集中儲存即可視為良好治理"", ""B. 主要關注資料壓縮與備份效率即可"", ""C. 由IT部門單獨負責資料，其他單位不需介入"", ""D. 確保資料來源、處理與使用全流程的透明性與安全性""]", CorrectAnswer="D", Explanation=@"資料治理不僅是集中儲存或備份技術問題，其核心在於資料從來源、處理到使用的透明與安全，並需跨部門共同承擔責任。" },
            new() { Id=5474, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在供應鏈攻擊情境下，企業僅依賴供應商的安全聲明可能產生什麼風險？", OptionsJson=@"[""A. 提升內部審計效率"", ""B. 完全消除所有外部風險"", ""C. 增加模型可解釋性"", ""D. 無法偵測第三方組件中實際存在的安全弱點""]", CorrectAnswer="D", Explanation=@"若只依賴供應商聲明，而未自行審查第三方組件，可能忽略實際存在的漏洞，導致供應鏈攻擊。" },
            new() { Id=5475, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"下列何者最能體現「AI治理原則」與「風險管理工具」之間的關係？", OptionsJson=@"[""A. 治理原則主要用於對外宣傳，工具則僅供內部使用"", ""B. 兩者完全獨立運作，彼此沒有必然關聯"", ""C. 有了風險管理工具後即可取代治理原則，不再需要政策"", ""D. 治理原則提供方向，風險矩陣等工具將其具體化於實務決策中""]", CorrectAnswer="D", Explanation=@"公平、透明、問責等治理原則提供方向，而風險矩陣等工具協助在實務上落實與操作這些原則。" },
            new() { Id=5476, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"關於NIST AI RMP，下列哪一項最能突顯其對不同組織的適用性？", OptionsJson=@"[""A. 僅適用具高度成熟治理架構的大型跨國企業"", ""B. 只適用特定產業，無法跨產業使用"", ""C. 各項要求必須逐條完全遵循，無法依情境調整"", ""D. 屬自願性且具高度彈性的框架，可依不同組織與情境調整導入方式""]", CorrectAnswer="D", Explanation=@"NIST AI RMP設計為自願性且彈性，讓不同規模與產業的組織可依自身風險承受度與治理成熟度，選擇適合的導入深度與範圍。" },
            new() { Id=5477, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"透明性與可追溯性不足時，下列哪種後果最可能發生？", OptionsJson=@"[""A. 系統電力成本下降"", ""B. 模型參數自動減少"", ""C. 使用者更容易理解系統行為無法調整"", ""D. 偏見難以被檢測且問責機制難以落實""]", CorrectAnswer="D", Explanation=@"若缺乏透明與可追溯性，偏見與錯誤來源難以辨識，問責與修正也會變得困難。" },
            new() { Id=5478, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"某高風險AI應用在風險評估後被判定超出組織可接受範圍，但管理層仍堅持導入，只願意購買保險。此決策最可能忽略了哪一點？", OptionsJson=@"[""A. 轉移策略無法降低營運成本"", ""B. 保險公司不會接受AI相關風險"", ""C. 避免策略會降低技術創新"", ""D. 轉移策略無法改變風險本身與對利害關係人的潛在傷害""]", CorrectAnswer="D", Explanation=@"僅透過保險轉移財務後果，並未降低對客戶或社會的實際傷害，對高風險情境應考慮避免策略。" },
            new() { Id=5479, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"下列何者最能說明「認知工廠」相較於「智慧工廠」的關鍵差異？", OptionsJson=@"[""A. 僅提升感測器精度與可視化"", ""B. 強調 AI Agent 具推理、決策與自主執行能力"", ""C. 完全不需要人類參與決策"", ""D. 只聚焦在單一機台自動化""]", CorrectAnswer="B", Explanation=@"認知工廠的質變在於導入可推理、協調並在授權下自主執行任務的 AI Agent，而非只是顯示儀表板。" },
            new() { Id=5480, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"依本單元內容，一線員工在認知工廠中的角色轉變最貼近哪一描述？", OptionsJson=@"[""A. 從執行者轉為指揮官，專注目標設定與例外處理"", ""B. 從決策者退為純資料輸入人員"", ""C. 完全被 AI Agent 取代，不再介入現場"", ""D. 只負責設備保養，不參與任何決策""]", CorrectAnswer="A", Explanation=@"投影片指出，員工從數據搬運與手動調參的執行者，轉型為定義目標、審核 AI 建議與處理例外的指揮官。" },
            new() { Id=5481, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"Human-In-The-Loop 設計在本單元中的核心目的為何？", OptionsJson=@"[""A. 讓 AI 完全取代人類判斷"", ""B. 確保所有決策都由 AI 自主完成"", ""C. 在效率與安全間平衡，保留人類最終控制與價值判斷權"", ""D. 降低人員對系統介面的操作頻率""]", CorrectAnswer="C", Explanation=@"本單元強調負責任的 AI 需維持人在迴路中，保有人類最終控制權、價值判斷與異常應變權。" },
            new() { Id=5482, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在人機協作角色矩陣中，縱軸與橫軸分別代表什麼？", OptionsJson=@"[""A. 縱軸為自動化程度，橫軸為員工素質"", ""B. 縱軸為決策風險，橫軸為決策複雜度"", ""C. 縱軸為設備數量，橫軸為產線長度"", ""D. 縱軸為人力成本，橫軸為導入費用""]", CorrectAnswer="B", Explanation=@"文章以決策風險為縱軸、決策複雜度為橫軸，來規劃人與 AI 在不同情境下的角色。" },
            new() { Id=5483, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在「AI 作為顧問 (Advisor)」模式下，人類的主要角色為何？", OptionsJson=@"[""A. 完全不介入決策流程"", ""B. 僅負責維護 AI 模型參數"", ""C. 監看設備運轉但不做決策"", ""D. 保有最終決策權，評估是否採用 AI 建議""]", CorrectAnswer="D", Explanation=@"顧問模式中，AI 只提供洞察與建議，最後是否執行仍由人類拍板。" },
            new() { Id=5484, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"哪一種模式最適合用在高風險、但決策複雜度較低的情境，例如關鍵機台參數調整？", OptionsJson=@"[""A. AI 作為協作者 (Collaborator)"", ""B. AI 作為助手 (Assistant)"", ""C. AI 作為操作員 (Operator)"", ""D. AI 作為執行者 (Executor)""]", CorrectAnswer="A", Explanation=@"文中說明 Collaborator 模式適用高風險、低複雜度，由 AI 建議參數、人員驗證後才下指令。" },
            new() { Id=5485, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在「AI 輔助參數設定 (Configurator)」模式中，人類被定位為：", OptionsJson=@"[""A. 完全旁觀者"", ""B. 干預者與安全防線，可隨時覆蓋 AI 設定"", ""C. 純資料標註者，無法干預參數"", ""D. 僅負責回報錯誤給 IT 單位""]", CorrectAnswer="B", Explanation=@"Configurator 模式強調人類作為安全防線，保留隨時修正或覆蓋 AI 設定的權力。" },
            new() { Id=5486, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"「有條件自主 (Conditional Autonomy)」模式的關鍵機制為何？", OptionsJson=@"[""A. AI 永遠需要人按下確認才能執行"", ""B. AI 在任何情況下皆可完全自主決策"", ""C. AI 在預設條件內可自主執行，超出條件時將控制權交還給人"", ""D. AI 只提供報表，不參與任務執行""]", CorrectAnswer="C", Explanation=@"此模式允許 AI 在設定邊界內自主執行，一旦超出條件或信心不足就交回人類處理。" },
            new() { Id=5487, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"下列何者最符合「AI 作為助手 (Assistant)」模式的典型應用？", OptionsJson=@"[""A. 自動生成焊接路徑程式並直接下發機台"", ""B. 自動監控 80 台設備並獨立決定停線"", ""C. 提供報表整理、會議紀錄與數據收集支援"", ""D. 自主決定是否啟動備援產線""]", CorrectAnswer="C", Explanation=@"Assistant 模式聚焦行政與資訊支援，如整理會議紀錄、收集數據與產出報告。" },
            new() { Id=5488, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在「AI 作為操作員 (Operator)」模式中，哪一項敘述最正確？", OptionsJson=@"[""A. AI 只能顯示儀表板，無法進行操作"", ""B. AI 可獨立執行低風險但高複雜任務，人類負責監督與驗收"", ""C. 所有操作必須由人類下達，AI 僅記錄結果"", ""D. AI 不需任何人類監督即可執行高風險任務""]", CorrectAnswer="B", Explanation=@"文中以焊接路徑優化為例，AI 自我組織路徑，人只需定義標準並做最後驗收，屬低風險高複雜。" },
            new() { Id=5489, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"「AI 作為執行者 (Executor)」模式最典型的案例為何？", OptionsJson=@"[""A. AI 只提供靜態報表匯出"", ""B. AI 自動監控多台設備並在密切監視下做出決策與發送分析數據"", ""C. AI 僅扮演流程紀錄者，不下任何指令"", ""D. AI 僅在人工請求時才提供建議""]", CorrectAnswer="B", Explanation=@"文章提到 AI 自動監控 80 台設備、發送分析數據，人類緊密監視並可隨時介入，正是 Executor 模式。" },
            new() { Id=5490, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"導入 7 種人機協作模式的第一步，依本單元建議應著重於：", OptionsJson=@"[""A. 優先挑選最新 AI 模型"", ""B. 直接將所有高風險任務改由 AI 執行"", ""C. 依決策風險與複雜度設計人機分工"", ""D. 先全面裁減一線人力再引進系統""]", CorrectAnswer="C", Explanation=@"「導入關鍵」部分強調，應先依風險與複雜度規劃人機分工，再來選工具與技術。" },
            new() { Id=5491, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"為何同一座工廠內，會同時需要多種人機協作模式？", OptionsJson=@"[""A. 因為 AI 系統供應商要求如此"", ""B. 不同場景的決策風險與複雜度不同"", ""C. 法規規定至少要用三種模式"", ""D. 只為了增加系統導入複雜度""]", CorrectAnswer="B", Explanation=@"品質放行、能耗管理、路徑優化等場景風險與複雜度差異大，需採用不同協作模式。" },
            new() { Id=5492, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在認知工廠中，員工從「執行者」轉為「指揮官」後，釋放出的時間應優先投入哪一類工作？", OptionsJson=@"[""A. 重複性資料輸入"", ""B. 手動抄寫儀表板數據"", ""C. 高價值工藝改進與流程優化"", ""D. 純粹行政核銷作業""]", CorrectAnswer="C", Explanation=@"本單元指出，人應投入工藝改進與人員輔導等高價值活動，而非低價值重複工作。" },
            new() { Id=5493, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在本單元的架構中，下列何者最能體現「從自動化到自主化」的意涵？", OptionsJson=@"[""A. AI 只能在固定時間執行排程任務"", ""B. AI 僅依規則被動執行，不會主動提出建議"", ""C. AI Agent 能在獲授權後主動提出建議並執行任務"", ""D. 僅將紙本表單改為電子化輸入""]", CorrectAnswer="C", Explanation=@"從自動化到自主化的差異在於 AI 能主動分析、規劃並在授權下行動，而非被動執行。" },
            new() { Id=5494, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在中等風險、低複雜度的情境，例如週報整理與異常彙整，最適合採用哪一種協作模式？", OptionsJson=@"[""A. 顧問 (Advisor)"", ""B. 助手 (Assistant)"", ""C. 操作員 (Operator)"", ""D. 執行者 (Executor)""]", CorrectAnswer="B", Explanation=@"這類任務結構清楚且風險有限，適合交給 Assistant 模式由 AI 處理資訊整合。" },
            new() { Id=5495, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"下列何者最符合高風險決策區的人機分工原則？", OptionsJson=@"[""A. 讓 AI 完全自主決定是否停線"", ""B. 由 AI 決定品質放行，人類只負責記錄"", ""C. 人握有最終決策或驗證權，AI 提供分析與建議"", ""D. 全部改由機器人執行，不再需要人員值班""]", CorrectAnswer="C", Explanation=@"文章明言高風險決策須由人類掌握最終決策或驗證權，AI 僅扮演顧問或協作者。" },
            new() { Id=5496, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在規劃導入路徑時，本單元建議企業應從何種場景開始試點？", OptionsJson=@"[""A. 立即在高風險關鍵製程全面自動化"", ""B. 先在人力充足處嘗試減少班次"", ""C. 從低風險場景如報表、能耗分析等應用開始試點"", ""D. 直接將所有決策交由 AI 進行""]", CorrectAnswer="C", Explanation=@"實務建議指出，應先從低風險場景試點，降低導入風險並累積治理經驗。" },
            new() { Id=5497, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"AI Agent 在「跨系統協調」能力上，最接近下列哪一描述？", OptionsJson=@"[""A. 僅能從單一感測器取得數據"", ""B. 只能在 MES 內運作，無法觸及 ERP"", ""C. 整合 IT/OT 數據，協調採購、生產與物流等系統運作"", ""D. 僅用於產線外的辦公室自動化""]", CorrectAnswer="C", Explanation=@"本單元說明 AI Agent 能跨 ERP、MES、SCADA 等系統協調任務，而非孤島式運作。" },
            new() { Id=5498, ChapterId=1307, Type="multiple", Difficulty=2, QuestionText=@"在規劃人機協作時，下列哪一項最符合本單元強調的「人機權責治理」精神？", OptionsJson=@"[""A. 先確定 AI 能做什麼，再考慮人類角色"", ""B. 僅依照工具商建議配置模式"", ""C. 明確定義 AI 的授權邊界與例外處理機制"", ""D. 將所有決策流程視為相同風險處理""]", CorrectAnswer="C", Explanation=@"文章強調須定義不同場景下 AI 可做的範圍與必須交回人的條件，形成清楚治理機制。" },
            new() { Id=5499, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"身為 AI 應用規劃師，若要為「品質放行決策」設計協作模式，何者最符合本單元的風險觀點？", OptionsJson=@"[""A. 採用 Operator 模式，讓 AI 直接控制放行"", ""B. 採用 Assistant 模式，只做報表整理"", ""C. 採用 Advisor/Collaborator 模式，由 AI 提供分析與建議，但保留人類最終決策權"", ""D. 採用 Executor 模式，讓 AI 自主放行""]", CorrectAnswer="C", Explanation=@"品質放行屬高風險，應讓 AI 提供分析，由人類做最後放行判斷。" },
