            new() { Id=5501, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"若一任務屬於「低風險、高複雜度且高度重複」，依本單元原則，最適合採用哪一種協作模式？", OptionsJson=@"[""A. AI 作為操作員 (Operator)"", ""B. AI 作為顧問 (Advisor)"", ""C. AI 作為助手 (Assistant)"", ""D. AI 作為協作者 (Collaborator)""]", CorrectAnswer="A", Explanation=@"例如焊接路徑優化即屬此類，由 Operator 模式讓 AI 獨立執行、人類監督與驗收。" },
            new() { Id=5502, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在設計「有條件自主 (Conditional Autonomy)」模式時，若忽略哪一項會造成最大的治理風險？", OptionsJson=@"[""A. 未記錄 AI 模型版本資訊"", ""B. 未明確定義例外條件與回交給人的機制"", ""C. 未安裝最新感測器硬體"", ""D. 未將結果同步到所有螢幕""]", CorrectAnswer="B", Explanation=@"Conditional 模式關鍵在於清楚定義 AI 何時需停下並交還控制權，否則容易失控。" },
            new() { Id=5503, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"若管理層只將 AI Agent 視為「報表工具」，根據本單元觀點，下列哪一評估最為貼切？", OptionsJson=@"[""A. 已完全進入認知工廠階段"", ""B. 已充分發揮跨系統協調價值"", ""C. 僅停留在 Assistant/Advisor 的部分功能，未發揮自主執行與協調潛力"", ""D. 完全不需再調整任何人機分工""]", CorrectAnswer="C", Explanation=@"文章指出 AI Agent 真正價值在推理、協調與執行，只做報表仍停留在有限的助手角色。" },
