            new() { Id=5505, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"若規劃讓 AI 直接發送採購訂單，但錯誤採購可能造成重大成本損失，依本單元原則較佳的做法為何？", OptionsJson=@"[""A. 一律採用自動執行，不需人類介入"", ""B. 採用 Operator 模式交由 AI 獨立決策"", ""C. 採用 Advisor/Collaborator 模式，AI 提出訂單建議，由人類確認後再發送"", ""D. 改成 Assistant 模式，只讓 AI 輸出 PDF 報表""]", CorrectAnswer="C", Explanation=@"採購錯誤屬高風險財務決策，應由 AI 提案、人類審核後才正式下單。" },
            new() { Id=5506, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在建立人機協作矩陣時，若 AI 應用規劃師只考慮技術可行性而忽略決策風險，最可能導致何種後果？", OptionsJson=@"[""A. 模式數量過多，使用者困惑"", ""B. 在高風險決策上過度自動化，缺乏人類攔截機制"", ""C. AI 無法處理任何例外狀況"", ""D. 無法滿足 IT 資安要求""]", CorrectAnswer="B", Explanation=@"本單元不斷提醒需審視決策風險，以避免高風險場景被 AI 過度自動化處理。" },
            new() { Id=5507, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"若希望一線員工較能接受 AI Agent，依本單元的訊息設計，下列哪一溝通方式最有助於降低排斥感？", OptionsJson=@"[""A. 強調 AI 將全面取代現場人力"", ""B. 強調 AI 只是另一個監控系統，不會帶來改變"", ""C. 強調 AI 接手低價值重複性工作，員工升級為指揮官與工藝優化角色"", ""D. 不對員工說明任何 AI 導入內容""]", CorrectAnswer="C", Explanation=@"投影片以「指揮官」比喻新角色，說明 AI 是接手低價值工作，有助降低被取代焦慮。" },
            new() { Id=5508, ChapterId=1307, Type="multiple", Difficulty=3, QuestionText=@"在評估某決策是否適合交由 AI 自主執行時，依本單元建議，哪一個問題最貼近應優先思考的核心？", OptionsJson=@"[""A. 目前市場上是否已有相同解決方案"", ""B. IT 團隊是否有足夠人力導入"", ""C. 系統供應商是否提供折扣"", ""D. 此決策的風險與複雜度落在矩陣的哪個區域""]", CorrectAnswer="D", Explanation=@"本單元強調，AI 自主程度應取決於該決策在「風險 × 複雜度」矩陣中的位置。" },
